1	#!/usr/bin/env node
2	'use strict';
3	/**
4	 * HEALTH-GATE: the CodeScene-class complexity smells caught before a reviewer ever sees them.
5	 *
6	 * Builder agents ship functions that pass every test yet are the exact shape CodeScene later flags:
7	 * Complex Method (too long), Bumpy Road (too many independent branches), Deep Nested Complexity (too
8	 * many levels of if/for/while inside one another). This gate exists so those findings die in the
9	 * builder loop, before a reviewer or a CodeScene scan ever fires on them (caution.md C-163: "a gate
10	 * that cannot fire is theatre" - CodeScene refactoring-goal gates were enabled with no goals defined;
11	 * this gate has an explicit, calibrated goal from commit 1).
12	 *
13	 * Five caps, each a hard ceiling, never a target to creep toward:
14	 *   - function body        > 60 lines
15	 *   - nesting depth         > 4   (if/for/while/switch/try nested inside one another)
16	 *   - decision points       > 12  (if / for / while / do-while / switch-case / && / || / ?: )
17	 *   - formal parameters     > 5
18	 *   - file length           > 500 lines
19	 *
20	 * Engine: an AST walk via acorn. acorn is MANDATORY (it always ships as a transitive devDependency of
21	 * eslint). The old brace/indent fallback was removed in PR #3 because it under-reported template ${}
22	 * code, regex-literal braces and braceless nesting - all confident zeros. HEALTH_GATE_ENGINE=heuristic
23	 * now forces tools/health-gate/heuristic.js's EXPLICIT REFUSAL (it throws, check.js exits 2), so the
24	 * fail-closed fallback is exercised in CI (mirrors SWALLOW_GATE_ENGINE=regex, but this fallback refuses
25	 * rather than approximates - under-reporting is an unearned zero, Constitution Rule 4).
26	 *
27	 * Tests: node --test tools/health-gate/check.test.js
28	 *
29	 * Modes:
30	 *   node tools/health-gate/check.js                  scan the repo source tree, exit 1 on any violation
31	 *   node tools/health-gate/check.js --json <path>    also write findings JSON for the sweep normaliser
32	 *   node tools/health-gate/check.js --calibrate      scan eval/calibration-known-bad/fixtures/ and REQUIRE
33	 *                                                    that the seeded violations are found. Zero found = exit 1.
34	 */
35	const fs = require('fs');
36	const path = require('path');
37	
38	const { runGateCli, ROOT } = require('../lib/gate-cli');
39	const { listJsFiles } = require('../lib/fswalk');
40	const { refuseHeuristicScan } = require('./heuristic');
41	
42	// facts, catalogue (minus packs/dist), tools, eval, payload, evidence, breach, llm, mint - the
43	// repo's source dirs. catalogue/packs is data (compiled law rows, not builder-authored logic) and is
44	// owned by a parallel workflow; excluding it here is a scan-scope decision, not an editing boundary.
45	const SCAN_DIRS = ['facts', 'catalogue', 'tools', 'eval', 'payload', 'evidence', 'breach', 'llm', 'mint'];
46	const SKIP_DIRS = /^(node_modules|\.git|out|packs|dist|fixtures)$/;
47	
48	const MAX_FUNCTION_LINES = 60;
49	const MAX_NESTING_DEPTH = 4;
50	const MAX_DECISION_POINTS = 12;
51	const MAX_PARAMS = 5;
52	const MAX_FILE_LINES = 500;
53	
54	const FUNCTION_TYPES = new Set(['FunctionDeclaration', 'FunctionExpression', 'ArrowFunctionExpression']);
55	
56	let acorn = null;
57	try { acorn = require('acorn'); }
58	catch (e) { acorn = null; /* FAIL-OPEN: require() may throw if acorn is genuinely absent; we swallow that to null HERE (acorn=null is the typed failure state) rather than crash on load, but scanContent() then REFUSES (exit 2) when acorn is null, so the SYSTEM fails closed. acorn ships as a transitive devDependency of eslint, so this branch does not fire in a normal install. */ }
59	// HEALTH_GATE_ENGINE=heuristic forces the refusal path so the fail-closed fallback is exercised in CI.
60	const FORCE_HEURISTIC = process.env.HEALTH_GATE_ENGINE === 'heuristic';
61	const useAcorn = Boolean(acorn) && !FORCE_HEURISTIC;
62	
63	// ── naming: best-effort label for a function node, for readable violation messages only (never gates on it) ──
64	
65	function keyName(k) {
66	  if (!k) return '(computed)';
67	  if (k.type === 'Identifier') return k.name;
68	  if (k.type === 'Literal') return String(k.value);
69	  return '(computed)';
70	}
71	
72	function exprName(n) {
73	  if (!n) return '(anonymous)';
74	  if (n.type === 'Identifier') return n.name;
75	  if (n.type === 'MemberExpression') return exprName(n.object) + '.' + keyName(n.property);
76	  return '(anonymous)';
77	}
78	
79	function functionDisplayName(node, hint) {
80	  return (node.id && node.id.name) ? node.id.name : (hint || '(anonymous)');
81	}
82	
83	function isMetaKey(key) {
84	  return key === 'loc' || key === 'start' || key === 'end' || key === 'range';
85	}
86	
87	// Each hint source is a guard-claused predicate returning the name or null, so computeChildHint stays a
88	// flat nullish-coalescing chain with no multi-operator conditional in any test position.
89	function variableDeclaratorHint(node, key) {
90	  if (node.type !== 'VariableDeclarator' || key !== 'init') return null;
91	  if (!node.id || node.id.type !== 'Identifier') return null;
92	  return node.id.name;
93	}
94	
95	function propertyOrMethodHint(node, key) {
96	  if (node.type !== 'Property' && node.type !== 'MethodDefinition') return null;
97	  if (key !== 'value' || !node.key) return null;
98	  return keyName(node.key);
99	}
100	
101	function assignmentHint(node, key) {
102	  if (node.type !== 'AssignmentExpression' || key !== 'right') return null;
103	  return exprName(node.left);
104	}
105	
106	// A function-like node's immediate syntactic context tells us its best-effort display name: the
107	// variable it was assigned to, the object/class key it lives under, or the identifier it was
108	// reassigned onto. Anything else is anonymous (fine: naming is cosmetic here, never load-bearing).
109	function computeChildHint(node, key) {
110	  return variableDeclaratorHint(node, key)
111	    ?? propertyOrMethodHint(node, key)
112	    ?? assignmentHint(node, key);
113	}
114	
115	// ── acorn engine: collect every function-like node, tagged with a best-effort name ────────────────────────
116	
117	// Nested functions are collected too (each is its own unit for metrics purposes; walkMetrics stops at
118	// a nested function's boundary so inner units are never double-charged against the outer one). The walk
119	// is split into three small units (node / array / children) so no single one exceeds the caps.
120	function walkCollectChildren(node, out) {
121	  for (const key of Object.keys(node)) {
122	    if (isMetaKey(key)) continue;
123	    const value = node[key];
124	    if (!value || typeof value !== 'object') continue;
125	    walkCollect(value, computeChildHint(node, key), out);
126	  }
127	}
128	
129	function walkCollect(node, hint, out) {
130	  if (!node || typeof node !== 'object') return;
131	  if (Array.isArray(node)) { for (const n of node) walkCollect(n, hint, out); return; }
132	  if (typeof node.type !== 'string') return;
133	  if (FUNCTION_TYPES.has(node.type)) out.push({ node, name: functionDisplayName(node, hint) });
134	  walkCollectChildren(node, out);
135	}
136	
137	function collectFunctions(root) {
138	  const out = [];
139	  walkCollect(root, null, out);
140	  return out;
141	}
142	
143	// ── acorn engine: bounded per-function walk computing decision points and max nesting depth ────────────────
144	// Each handler owns exactly one nesting-inducing construct; walkMetrics itself is a lookup, not a
145	// switch, which keeps its own decision count low (a dispatch table branches without a branch).
146	
147	function walkIf(node, depth, state) {
148	  state.decisions++;
149	  walkMetrics(node.test, depth, state);
150	  walkMetrics(node.consequent, depth + 1, state);
151	  state.maxDepth = Math.max(state.maxDepth, depth + 1);
152	  if (!node.alternate) return;
153	  // "else if" chains stay at the SAME depth (sibling branches, not nested ones); a genuine
154	  // "else { ... }" block is a further nesting level.
155	  if (node.alternate.type === 'IfStatement') { walkMetrics(node.alternate, depth, state); return; }
156	  walkMetrics(node.alternate, depth + 1, state);
157	  state.maxDepth = Math.max(state.maxDepth, depth + 1);
158	}
159	
160	function walkLoop(node, depth, state) {
161	  state.decisions++;
162	  for (const k of ['init', 'test', 'update', 'left', 'right']) if (node[k]) walkMetrics(node[k], depth, state);
163	  walkMetrics(node.body, depth + 1, state);
164	  state.maxDepth = Math.max(state.maxDepth, depth + 1);
165	}
166	
167	function walkSwitch(node, depth, state) {
168	  walkMetrics(node.discriminant, depth, state);
169	  for (const c of node.cases) {
170	    if (c.test) { state.decisions++; walkMetrics(c.test, depth, state); }
171	    walkMetrics(c.consequent, depth + 1, state);
172	  }
173	  state.maxDepth = Math.max(state.maxDepth, depth + 1);
174	}
175	
176	function walkTry(node, depth, state) {
177	  walkMetrics(node.block, depth + 1, state);
178	  state.maxDepth = Math.max(state.maxDepth, depth + 1);
179	  if (node.handler) { walkMetrics(node.handler.body, depth + 1, state); state.maxDepth = Math.max(state.maxDepth, depth + 1); }
180	  if (node.finalizer) { walkMetrics(node.finalizer, depth + 1, state); state.maxDepth = Math.max(state.maxDepth, depth + 1); }
181	}
182	
183	function walkLogical(node, depth, state) {
184	  if (node.operator === '&&' || node.operator === '||') state.decisions++;
185	  walkMetrics(node.left, depth, state);
186	  walkMetrics(node.right, depth, state);
187	}
188	
189	function walkConditional(node, depth, state) {
190	  state.decisions++;
191	  walkMetrics(node.test, depth, state);
192	  walkMetrics(node.consequent, depth, state);
193	  walkMetrics(node.alternate, depth, state);
194	}
195	
196	function walkGenericChildren(node, depth, state) {
197	  for (const key of Object.keys(node)) {
198	    if (isMetaKey(key)) continue;
199	    const v = node[key];
200	    if (v && typeof v === 'object') walkMetrics(v, depth, state);
201	  }
202	}
203	
204	const NESTING_HANDLERS = {
205	  IfStatement: walkIf,
206	  ForStatement: walkLoop,
207	  ForInStatement: walkLoop,
208	  ForOfStatement: walkLoop,
209	  WhileStatement: walkLoop,
210	  DoWhileStatement: walkLoop,
211	  SwitchStatement: walkSwitch,
212	  TryStatement: walkTry,
213	  LogicalExpression: walkLogical,
214	  ConditionalExpression: walkConditional,
215	};
216	
217	function walkMetrics(node, depth, state) {
218	  if (!node || typeof node !== 'object') return;
219	  if (Array.isArray(node)) { for (const n of node) walkMetrics(n, depth, state); return; }
220	  if (typeof node.type !== 'string' || FUNCTION_TYPES.has(node.type)) return;
221	  const handler = NESTING_HANDLERS[node.type];
222	  if (handler) handler(node, depth, state);
223	  else walkGenericChildren(node, depth, state);
224	}
225	
226	function functionMetricsAcorn(fnNode) {
227	  const state = { decisions: 0, maxDepth: 0 };
228	  walkMetrics(fnNode.body, 0, state);
229	  const lines = fnNode.loc.end.line - fnNode.loc.start.line + 1;
230	  return { lines, params: fnNode.params.length, maxDepth: state.maxDepth, decisions: state.decisions, line: fnNode.loc.start.line };
231	}
232	
233	function scanContentAcorn(src) {
234	  const ast = acorn.parse(src, { ecmaVersion: 'latest', allowHashBang: true, allowReturnOutsideFunction: true, allowAwaitOutsideFunction: true, locations: true });
235	  return collectFunctions(ast).map((f) => ({ name: f.name, ...functionMetricsAcorn(f.node) }));
236	}
237	
238	// ── shared judgement: metrics -> violations against the five caps (engine-agnostic) ────────────────────────
239	
240	const CAPS = [
241	  { key: 'lines', kind: 'long-function', cap: MAX_FUNCTION_LINES, label: 'lines', tail: 'Complex Method' },
242	  { key: 'maxDepth', kind: 'deep-nesting', cap: MAX_NESTING_DEPTH, label: 'levels deep', tail: 'Deep Nested Complexity' },
243	  { key: 'decisions', kind: 'high-branching', cap: MAX_DECISION_POINTS, label: 'decision points', tail: 'Bumpy Road' },
244	  { key: 'params', kind: 'too-many-params', cap: MAX_PARAMS, label: 'parameters', tail: null },
245	];
246	
247	function judgeFunction(relPath, fn) {
248	  const out = [];
249	  for (const c of CAPS) {
250	    const value = fn[c.key];
251	    if (value <= c.cap) continue;
252	    const tail = c.tail ? ' - ' + c.tail : '';
253	    out.push({
254	      file: relPath, line: fn.line, name: fn.name, kind: c.kind, metric: value, cap: c.cap,
255	      message: `function "${fn.name}" has ${value} ${c.label} (cap ${c.cap})${tail}`,
256	    });
257	  }
258	  return out;
259	}
260	
261	function scanContent(relPath, src) {
262	  // acorn is mandatory. Without it (or under a forced heuristic), REFUSE rather than approximate:
263	  // refuseHeuristicScan throws, which the CLI turns into exit 2 (a broken tool), never a zero.
264	  if (!useAcorn) refuseHeuristicScan(relPath);
265	  let fns;
266	  try { fns = scanContentAcorn(src); }
267	  catch (e) { throw new Error(relPath + ': acorn cannot parse this file: ' + e.message + ' (a parse failure is NOT zero violations)'); }
268	  const engine = 'acorn';
269	  const violations = fns.flatMap((fn) => judgeFunction(relPath, fn));
270	  // Count LINES, not newline-split segments: a trailing newline (every POSIX text file) otherwise
271	  // inflates the count by one, so a legal 500-line file misreports as 501 and fails the cap.
272	  const totalLines = src.length === 0 ? 0 : src.replace(/\n$/, '').split('\n').length;
273	  if (totalLines > MAX_FILE_LINES) {
274	    violations.push({ file: relPath, line: 1, name: '(file)', kind: 'large-file', metric: totalLines, cap: MAX_FILE_LINES,
275	      message: `file is ${totalLines} lines (cap ${MAX_FILE_LINES})` });
276	  }
277	  return { violations, functions: fns.length, engine };
278	}
279	
280	function scanTree(dirs) {
281	  const violations = [];
282	  let scanned = 0;
283	  let functions = 0;
284	  for (const dir of dirs) {
285	    const absDir = path.isAbsolute(dir) ? dir : path.join(ROOT, dir);
286	    for (const abs of listJsFiles(absDir, { skipDirs: SKIP_DIRS, skipTests: true })) {
287	      scanned++;
288	      const rel = path.relative(ROOT, abs).replace(/\\/g, '/');
