47	// ── ctx: READ facts off the bundle for the prompt; never re-derive them (Rule 1, one door). ───────────
48	function readField(bundle, keys) {
49	  for (const k of keys) {
50	    const v = bundle && bundle[k];
51	    if (typeof v === 'string' && v) return v;
52	  }
53	  const facts = bundle && bundle.facts;
54	  for (const k of keys) {
