138	    '  "no_breach"    = it does not (a FALSE POSITIVE: the matched text means something else in context - a legal',
139	    '                   practice area, an HTML tag name, a quotation, a negation, a blog post ABOUT the law - or the',
140	    '                   obligation is plainly satisfied by the text shown).',
141	    '  "insufficient" = the evidence is too thin to rule either way. Not a breach. Not a clearance.',
142	    '',
143	    ...promptRules(),
144	    '',
145	    'CANDIDATES:',
146	    JSON.stringify(briefs),
147	    '',
148	    'Return STRICT JSON only:',
149	    '{"verdicts":[{"id":0,"verdict":"breach|no_breach|insufficient","reason":"<=20 words","disproof":"<verbatim quote from the evidence, or null>"}]}',
