153	// ── the deterministic rubric handed to the injected gate: it scores structural validity, NEVER the
154	//    model's self-reported confidence (C-145). Each sub-check is one small helper (health caps). ────────
155	function scoreCompleteness(verdicts, briefs, defs) {
156	  const ids = new Set(verdicts.map((x) => Number(x && x.id)));
157	  const complete = briefs.every((b) => ids.has(b.id)) && verdicts.length === briefs.length;
158	  if (complete) return 3;
159	  defs.push('return EXACTLY one verdict per candidate id (' + briefs.map((b) => b.id).join(',') + '); you returned ' + verdicts.length);
