165	  defs.push('every verdict must be exactly one of: breach, no_breach, insufficient');
166	  return 0;
167	}
168	function scoreAnchoring(verdicts, batch, defs) {
169	  let anchored = true;
170	  for (const x of verdicts) {
171	    if (String((x && x.verdict) || '').toLowerCase() !== 'no_breach') continue;
172	    const f = batch[Number(x && x.id)];
173	    if (f && disproofMatches(x && x.disproof, evidenceText(f))) continue;
174	    anchored = false;
175	    defs.push('id ' + (x && x.id) + ': a "no_breach" needs a VERBATIM disproof quoted from the evidence shown');
176	  }
177	  return anchored ? 4 : 0;
178	}
179	function rubricFor(briefs, batch) {
180	  return function rubric(parsed) {
181	    if (!parsed || !Array.isArray(parsed.verdicts)) return { score: 0, deficiencies: ['no "verdicts" array in the JSON'], hard_fail: true };
182	    const defs = [];
183	    const v = parsed.verdicts;
184	    const score = scoreCompleteness(v, briefs, defs) + scoreEnum(v, defs) + scoreAnchoring(v, batch, defs);
