189	// ── stampers: write the three-state + adjudication fields onto ONE finding, in place. ─────────────────
190	function baseAdj(f, state, adjudicated, adjudication) {
191	  f.state = state;
192	  f.adjudicated = adjudicated;
193	  f.adjudication = adjudication;
194	}
195	function stampBypass(f, kind) {
196	  baseAdj(f, 'violation', true, 'observed_fact');
197	  f.adjudication_reason = kind + ' fact bypasses text adjudication (C-084)';
198	}
199	function stampReject(f, reason) {
200	  baseAdj(f, 'needs_review', false, 'kind_rejected');
201	  f.adjudication_reason = String(reason || 'evidence-kind rejected').slice(0, 160);
202	}
203	function stampAbstain(f, reason) {
204	  baseAdj(f, 'needs_review', false, 'unadjudicated');
205	  f.adjudication_reason = String(reason || 'not adjudicated -> abstain (Rule 12 gate 4)').slice(0, 160);
206	}
207	function stampFromVerdict(f, parsed) {
208	  baseAdj(f, parsed.state, true, parsed.verdict || 'unparseable');
209	  f.adjudication_reason = parsed.reason;
210	  if (parsed.disproof) f.adjudication_disproof = parsed.disproof;
211	}
212	// stampNliDemote(f, e): Rule 12 gate 3. A text candidate the model ruled `breach` whose verified quote
213	// (Gate 2's output) does NOT ENTAIL the claim is demoted to needs_review - it was adjudicated, but the
214	// NLI gate withheld the violation (neutral/contradiction/gate-reject/timeout/no-premise/no result).
215	function stampNliDemote(f, e) {
216	  baseAdj(f, 'needs_review', true, 'nli_demoted');
217	  f.adjudication_reason = 'nli:' + ((e && e.verdict) || 'no_result');
218	}
