220	// verdictsFrom(out) -> the verdicts array from the injected caller's return, accepting both the gate.js
221	// shape ({ ok, out:{ verdicts } }) and a bare { verdicts }. `ok:false` or no array -> null (abstain).
222	function verdictsFrom(out) {
223	  if (!out || out.ok === false) return null;
224	  const v = (out.out && out.out.verdicts) || out.verdicts;
225	  return Array.isArray(v) ? v : null;
226	}
