228	// gateEntailment(f, parsed, opts) - Rule 12 GATE 3 (NLI), the last check before a `breach` verdict
229	// becomes a shipped `violation`. The hypothesis is the claim (the candidate's description); the premise
230	// is the EXACT verbatim quote the quote-match verifier already string-matched to the corpus (Gate 2
231	// feeds Gate 3, so the NLI premise is grounded, not paraphrased). Only a gate-valid `entailment` label
232	// keeps the violation; anything else (neutral, contradiction, gate-reject, timeout, no premise, no
233	// result) demotes to needs_review. The NLI call is bounded by whatever adjudication budget remains
234	// (Rule 8/9: a cap, never a floor); an exhausted budget demotes without calling the model.
235	async function gateEntailment(f, parsed, opts) {
236	  const deadlineAt = Number.isFinite(opts.deadlineAt) ? opts.deadlineAt : (opts.now() + DEFAULT_DEADLINE_MS);
237	  const remaining = deadlineAt - opts.now();
238	  if (remaining <= 0) { stampNliDemote(f, { verdict: 'deadline' }); return; }
239	  // Premise fields: a P3 candidate carries its verbatim quote on the ARTIFACT (artifact.quote/.text,
240	  // Gate 2's string-matched span) and its locator on artifact.page_url/candidate.page_url; the
241	  // port-era flat fields (evidence_quote/evidence_source_id/evidence_url) are read first for
242	  // compatibility. Missing premise still abstain-demotes inside checkEntailment (never a guess).
243	  const art = f.artifact || {};
244	  const claim = {
245	    claim: fieldStr(f, 'description'),
246	    premise_source_id: f.evidence_source_id || f.evidence_url || art.page_url || f.page_url,
247	    premise: fieldStr(f, 'evidence_quote') || (art.quote != null ? String(art.quote) : '') || (art.text != null ? String(art.text) : ''),
248	  };
249	  let e = null;
250	  try {
251	    const results = await checkEntailment([claim], { llmCall: opts.llmCall, deadlineMs: remaining, log: opts.log });
252	    e = results && results[0];
253	  } catch (_err) {
254	    // FAIL-OPEN: an NLI shell that throws demotes the finding to needs_review (Rule 4), never throws
255	    // into the mint. checkEntailment already captures caller throws internally; this is belt-and-braces.
256	    e = null;
257	  }
258	  if (!e || !e.ok) { stampNliDemote(f, e); return; }
259	  stampFromVerdict(f, parsed);
260	}
261	
262	// applyVerdicts(batch, verdicts, opts) - THE FILTER-ONLY CORE. Iterate the INPUT candidates and look up
263	// each one's verdict by the id THIS module assigned it. Nothing is ever created from `verdicts`; a
264	// verdict for an unknown id is simply never looked up. This is why an invented finding cannot be
265	// injected. A `breach` verdict is NOT stamped `violation` directly: it must first survive Rule 12 gate
266	// 3 (gateEntailment); every other verdict is stamped as-is.
267	async function applyVerdicts(batch, verdicts, opts) {
268	  const byId = new Map();
269	  for (const v of verdicts) {
270	    const id = Number(v && v.id);
271	    if (Number.isInteger(id) && !byId.has(id)) byId.set(id, v);
272	  }
273	  for (let i = 0; i < batch.length; i++) {
274	    const raw = byId.get(i);
275	    if (raw === undefined) { stampAbstain(batch[i], 'no verdict returned for this candidate -> abstain'); continue; }
276	    const parsed = parseVerdict(raw, evidenceText(batch[i]));
277	    if (parsed.state === 'violation') { await gateEntailment(batch[i], parsed, opts); continue; }
