282	// applyAbstain(batch, reason) - the abstain floor: every candidate in a batch the model could not
283	// adjudicate defaults to needs_review. Never violation, never pass (Rule 12 gate 4).
284	function applyAbstain(batch, reason) {
285	  for (const f of batch) stampAbstain(f, reason);
286	}
287	
288	function safeLog(log, event) {
289	  if (!log) return;
290	  try { log(event); }
291	  catch (e) { /* FAIL-OPEN: observability logging must never break adjudication; a broken logger is not a legal-claim failure. Dropped on purpose. */ }
292	}
