294	// callGate(batch, ctx, opts) -> the injected caller's raw return, under a HARD deadline (Rule 9).
295	// Resolves to the return value, or null when it timed out / threw (the caller then abstains the batch).
296	async function callGate(batch, ctx, opts) {
297	  const briefs = batch.map((f, i) => briefOf(f, i));
298	  const request = {
299	    role: 'extract',
300	    system: systemPrompt(),
301	    prompt: buildPrompt(ctx, briefs),
302	    rubric: rubricFor(briefs, batch),
303	    threshold: 7, max_attempts: 3, max_tokens: 900, temperature: 0,
304	    scan_id: String(ctx.domain || '') + ':adjudicate',
305	    deadline_ms: opts.batchDeadlineMs,
