307	  const work = Promise.resolve().then(() => opts.llmCall(request));
308	  const raced = await raceWithDeadline(work, opts.batchDeadlineMs, opts.now).catch((e) => ({ _threw: e }));
309	  if (raced && raced._threw) {
310	    // FAIL-OPEN (Rule 4 / Rule 9): a caller that throws must abstain the batch, never throw into the
311	    // mint. The cause is returned to the batch loop and recorded on the report (report.batches).
312	    return { error: String((raced._threw && raced._threw.message) || raced._threw).slice(0, 120) };
313	  }
