316	}
317	
318	// adjudicateBatch(batch, ctx, opts) -> a report row for one batch, having stamped every candidate in it.
319	async function adjudicateBatch(batch, ctx, opts) {
320	  const res = await callGate(batch, ctx, opts);
321	  if (res.timedOut) { applyAbstain(batch, 'llm deadline exceeded -> abstain'); return { ranOk: false, reason: 'timeout' }; }
322	  if (res.error) { applyAbstain(batch, 'llm error -> abstain'); return { ranOk: false, reason: 'error:' + res.error }; }
