329	// adjudicateText(text, ctx, opts, report) - batch the text-derived candidates to the injected caller
330	// under the shared deadline. No caller -> abstain them all (zero regression: nothing was removed).
331	async function adjudicateText(text, ctx, opts, report) {
332	  if (!opts.llmCall) {
333	    applyAbstain(text, 'no LLM caller injected -> abstain (Rule 12 gate 4)');
334	    report.llm_available = false;
335	    return;
336	  }
337	  report.llm_available = true;
338	  const deadline = opts.now() + opts.deadlineMs;
339	  for (let start = 0; start < text.length; start += BATCH) {
340	    const batch = text.slice(start, start + BATCH);
341	    const remaining = deadline - opts.now();
342	    if (remaining <= 0) { applyAbstain(batch, 'adjudication deadline exhausted -> abstain'); report.timed_out = true; report.batches.push({ start, ranOk: false, reason: 'deadline' }); continue; }
343	    const batchOpts = Object.assign({}, opts, { batchDeadlineMs: remaining, deadlineAt: deadline });
344	    const row = await adjudicateBatch(batch, ctx, batchOpts);
345	    report.ran = report.ran || row.ranOk;
346	    report.batches.push(Object.assign({ start }, row));
347	    safeLog(opts.log, { event: 'adjudicate_batch', start, ranOk: row.ranOk, reason: row.reason || null });
