351	// classifyAll(candidates) -> partition into bypass (observation/register), text (absence to adjudicate)
352	// and rejected (masqueraded kind or no artifact). Attaches a transient _ek deleted before return.
353	function classifyAll(candidates) {
354	  const bypass = [];
355	  const text = [];
356	  const rejected = [];
357	  for (const f of candidates) {
358	    const ek = classifyEvidenceKind(f);
359	    f._ek = ek;
360	    if (!ek.valid) rejected.push(f);
361	    else if (ek.bypass) bypass.push(f);
362	    else text.push(f);
363	  }
364	  return { bypass, text, rejected };
365	}
366	
367	function emptyReport(total) {
368	  return {
369	    ran: false, llm_available: false, timed_out: false, total,
370	    observed_fact: 0, register_fact: 0, rejected: 0, text_derived: 0,
371	    violation: 0, needs_review: 0, pass: 0, batches: [],
372	  };
373	}
374	function tallyState(report, state) {
375	  if (state === 'violation') report.violation++;
376	  else if (state === 'pass') report.pass++;
377	  else report.needs_review++;
378	}
379	
380	/**
381	 * adjudicate(verifiedCandidates, bundle, { llmCall, deadlineMs, log }) -> { findings, report }
382	 *
383	 * findings  a NEW array, ONE finding per input candidate (never mutates the input), each stamped with
384	 *           the three-state `state` (violation|needs_review|pass) and the adjudication fields
385	 *           { adjudicated, adjudication, adjudication_reason, adjudication_disproof? }. |findings| always
386	 *           equals |verifiedCandidates|: the adjudicator is filter-only and cannot invent a finding.
387	 * report    observability + stage-manifest input: counts per bucket/state, per-batch outcomes, whether
388	 *           the LLM was available and whether the deadline was hit.
389	 *
390	 * opts.llmCall   async (request) => { ok, out:{ verdicts:[{id,verdict,reason,disproof}] } } (gate.js
391	 *                shape) OR { verdicts:[...] }. INJECTED; this module never calls a network. Absent, or a
392	 *                caller that throws/times out/returns no verdicts -> every text candidate abstains.
393	 * opts.deadlineMs  the total adjudication ceiling (default 60000); a CAP, never a floor (Rule 8/9).
394	 * opts.now / opts.log  injected clock + optional observability sink (both optional).
395	 */
396	async function adjudicate(verifiedCandidates, bundle, options) {
397	  const opts = normaliseOptions(options);
398	  const candidates = (verifiedCandidates || []).map((c) => Object.assign({}, c));
399	  const report = emptyReport(candidates.length);
400	  if (candidates.length === 0) return { findings: candidates, report };
401	
402	  const { bypass, text, rejected } = classifyAll(candidates);
403	  for (const f of bypass) {
404	    stampBypass(f, f._ek.kind);
405	    if (f._ek.kind === 'register') report.register_fact++; else report.observed_fact++;
406	  }
407	  for (const f of rejected) { stampReject(f, f._ek.reason); report.rejected++; }
408	
409	  report.text_derived = text.length;
410	  if (text.length > 0) await adjudicateText(text, ctxFromBundle(bundle), opts, report);
411	
412	  for (const f of candidates) { delete f._ek; tallyState(report, f.state); }
413	  return { findings: candidates, report };
414	}
415	
416	module.exports = {
417	  adjudicate,
418	  // exported for the node:test suite + the calibration fixtures (helpers, never fact producers):
419	  classifyAll,
420	  ctxFromBundle,
421	  evidenceText,
422	  briefOf,
423	  systemPrompt,
424	  buildPrompt,
425	  rubricFor,
426	  verdictsFrom,
427	  applyVerdicts,
428	  BATCH,
429	  DEFAULT_DEADLINE_MS,
430	};
