79	// Generic obligation/boilerplate words dropped before deriving a token-set: patterning on these would
80	// match any page (the C-049/C-059 over-broad-trigger class). This is a STOPWORD list, not a legal
81	// vocabulary - it names no law, regulator or fact (Rule 2).
82	const STOPWORDS = new Set([
83	  'the', 'and', 'for', 'that', 'this', 'with', 'from', 'your', 'their', 'have', 'has', 'are', 'was',
84	  'page', 'pages', 'website', 'websites', 'site', 'sites', 'online', 'web', 'published', 'publish',
85	  'display', 'displayed', 'show', 'shown', 'state', 'stated', 'provide', 'provided', 'include',
86	  'included', 'including', 'required', 'require', 'must', 'may', 'not', 'clear', 'clearly',
87	  'statement', 'reference', 'where', 'near', 'listed', 'every', 'should', 'obligation', 'obligations',
88	  'available', 'relevant', 'visible', 'prominent', 'prominently', 'each', 'any', 'all', 'its', 'his',
89	  'her', 'they', 'them', 'a', 'an', 'of', 'to', 'in', 'on', 'or', 'is', 'be', 'as', 'at', 'by',
90	  'findable', 'named', 'wording', 'present', 'content', 'copy', 'text', 'section', 'link', 'links',
91	]);
92	
93	// Element wording that means "a page/section of this class exists" rather than "this phrase appears":
94	// such an element is satisfiable by a crawled page of the right class, so it also gets a url-path pattern.
95	const FINDABILITY_RX = /\b(findable|available on the website|on the website|link(?:s|ed|ing)?|page|section|procedure)\b/i;
96	// Required-mechanism wording that legitimately lives in JavaScript (route to raw_html; propose abstains
97	// rather than fabricate a missing-mechanism breach, C-036/C-032). Deliberately NARROW: bare "widget",
98	// "tool" and "banner" are ordinary disclosure words and would over-abstain, so only unambiguously
99	// JS-embedded controls qualify (an SRA-style clickable embedded badge, a script/plugin, a consent tool).
100	const MECHANISM_RX = /\b(badge|embedded|embed|script|plugin|clickable|consent[- ]?(?:tool|manager|management)|(?:cookie|consent)[- ]?banner)\b/i;
101	// Footer-surface duties: a company/registration number or registered office (C-034/C-072).
102	const FOOTER_RX = /\b(company number|registration number|registered office|firm(?:'s)? (?:sra|number)|number shown|registered number)\b/i;
103	
104	// ── anchoring + matching primitives ── moved to pattern-match.js (linear-time, Rob P0), imported and
105	//    re-exported above. detection-spec.js keeps only the DERIVATION + VALIDATION of patterns. ─────────
106	
107	// ── negation guard (ported from corpus-index.js NEGATION_RX; PR #340 blanket-negation fix kept) ───
108	// A prohibition ('absence') fires when the firm MAKES the forbidden claim. A sentence that NEGATES the
109	// claim ("we do not offer ... to under-18s", "must be 18 or over") is a compliance statement, not the
110	// prohibited claim; propose.js skips it. Blanket "prohibited/illegal/we comply" negations are NOT here:
111	// a negation must negate THE CLAIM, not merely mention that the law exists.
112	const NEGATION_RX = /\b(?:do not|don't|does not|doesn't|did not|never|cannot|can't|will not|won't|no longer|not (?:offer|available|suitable|permitted|provide)|must be (?:over|aged|18)|18\s*(?:years\s*)?(?:and|or)\s*(?:over|older|above)|over[- ]?18s?\s*only|strictly\s*18)\b/i;
113	function isNegated(sentence) {
114	  return NEGATION_RX.test(String(sentence || ''));
115	}
116	
117	// A customer-review sentence must never be read as the FIRM'S own prohibited claim (C-090). The pure
118	// EvidenceBundle is stripped visible text with no DOM containers, so this is a lightweight review-framing
119	// heuristic (star runs, first-person praise), not full segmentation; the honest limit is flagged to the
120	// caller. propose.js drops a prohibited-claim hit whose carrier sentence looks like a review.
121	const REVIEW_RX = /(★|\bfive[- ]stars?\b|\b\d(?:\.\d)?\s*(?:\/\s*5|stars?)\b|\bwould (?:highly )?recommend\b|\bhighly recommend(?:ed)?\b|\bbest (?:clinic|firm|service|experience)\b)/i;
122	function looksLikeReview(sentence) {
123	  return REVIEW_RX.test(String(sentence || ''));
124	}
125	
126	// splitSentences(text) -> sentence-ish segments bounded by . ! ? bullet or newline. Pure; used to bound
127	// a quote to one sentence (C-089) and to run the negation/review guards per carrier sentence.
128	function splitSentences(text) {
129	  return String(text || '')
130	    .split(/(?<=[.!?•\n])\s+|\n+/)
131	    .map((s) => s.trim())
132	    .filter(Boolean);
133	}
134	
135	// isProse(sentence) -> true when a sentence is genuine client copy, not a nav/footer Title-Case link run
136	// (C-089: never quote boilerplate). Deterministic and conservative.
137	function isProse(sentence) {
138	  const s = String(sentence || '').trim();
139	  if (s.length < 25) return false;                 // C-089 minimum evidence length
140	  const words = s.split(/\s+/);
141	  if (words.length < 4) return false;
142	  const titleish = words.filter((w) => /^[A-Z][a-zA-Z'']+$/.test(w)).length;
143	  if (titleish / words.length > 0.7) return false; // mostly Title-Case tokens => a menu/link run
144	  return /[a-z]/.test(s);
145	}
146	
147	// ── surface + page-class routing ─────────────────────────────────────────────────────────────────
148	function obligationText(obligation) {
149	  const elems = Array.isArray(obligation.elements) ? obligation.elements.join(' ') : '';
150	  return ((obligation.duty || '') + ' ' + elems);
151	}
152	
153	// pageClassFor(obligation) -> the crawl page-class an on-page presence/absence duty needs ('any' for a
154	// general on-page duty; null for register/behavioural non-crawl lanes). This IS coverage-contract's
155	// pageClassForObligation (one door, one meaning): binding the name to the imported function guarantees
156	// the spec's page_class and the coverage verdict can never disagree, and deletes the copy that drifted.
157	const pageClassFor = coverageContract.pageClassForObligation;
158	
159	// surfaceFor(obligation) -> the declared detection/evidence surface (C-035/C-036/C-034).
160	function surfaceFor(obligation) {
161	  const et = obligation && obligation.evidence_type;
162	  if (et === 'register') return 'register_row';
163	  if (et === 'behavioural') return 'browser_lane';
164	  const text = obligationText(obligation);
165	  if (et === 'presence' && FOOTER_RX.test(text)) return 'footer';
166	  if (et === 'presence' && MECHANISM_RX.test(text)) return 'raw_html'; // JS-embeddable mechanism (C-036)
167	  return 'visible_text'; // prohibitions and prose disclosures both detect on visible prose (C-036)
168	}
169	
170	// ── pattern derivation (prose element -> anchored patterns) ──────────────────────────────────────
171	function quotedSpans(text) {
172	  const out = [];
173	  const rx = /['"‘’“”]([^'"‘’“”]{3,})['"‘’“”]/g;
174	  let m;
175	  while ((m = rx.exec(String(text || ''))) !== null) {
176	    const phrase = m[1].trim();
177	    if (phrase.split(/\s+/).length >= MIN_PHRASE_WORDS) out.push(phrase);
178	  }
179	  return out;
180	}
181	
182	// salientTokens(text) -> up to MAX_TOKENS distinctive content tokens (>= MIN_TOKEN_LEN, minus STOPWORDS),
183	// in first-seen order (deterministic). Digits-with-a-word like "18" are kept only when >= MIN_TOKEN_LEN
184	// so a bare short number never becomes a pattern.
185	function salientTokens(text) {
186	  const raw = String(text || '').toLowerCase().match(/[a-z0-9][a-z0-9'-]*[a-z0-9]|[a-z0-9]/g) || [];
187	  const out = [];
188	  const seen = new Set();
189	  for (const w of raw) {
190	    if (w.length < MIN_TOKEN_LEN || STOPWORDS.has(w) || seen.has(w)) continue;
191	    seen.add(w);
192	    out.push(w);
193	    if (out.length >= MAX_TOKENS) break;
194	  }
195	  return out;
196	}
197	
198	// topDistinctive(tokens, n) -> up to n most distinctive tokens (>= 4 chars) by length descending, a
199	// stable sort keeping first-seen order on ties (deterministic). The distinctiveness floor drops the
200	// short common words a legal claim must never hinge on (C-059).
201	function topDistinctive(tokens, n) {
202	  return tokens
203	    .filter((t) => t.length >= 4)
204	    .map((t, i) => ({ t, i }))
205	    .sort((a, b) => (b.t.length - a.t.length) || (a.i - b.i))
206	    .slice(0, n)
207	    .map((x) => x.t);
208	}
209	
210	// patternsFromElement(elementText, evidenceType, pageClass) -> { patterns, unpatternable }.
211	//
212	// THE POLARITY OF STRICTNESS (the C-024-vs-C-078 balance, the single most important choice here).
213	// The two evidence types fail in OPPOSITE directions, so their derived matchers must be strict in
214	// opposite directions:
215	//   - 'absence' (a PROHIBITION; propose fires when the pattern IS FOUND): a loose matcher over-accuses
216	//     (C-078, the defamation-adjacent false hack accusation). So a prohibited element is matched
217	//     STRICTLY - the exact quoted phrase, or the FULL token-set co-occurring (mode 'all'). A near miss
218	//     abstains. Precision beats recall: a missed prohibited claim is recoverable, a false accusation is
219	//     not (C-082).
220	//   - 'presence' (a REQUIREMENT; propose fires when the pattern is ABSENT): a strict matcher over-
221	//     accuses in reverse - it reads a compliant-but-differently-worded page as "missing" (C-024, the
222	//     russell-cooke SRA-string-past-the-cut class; C-093 presence-but-thin). So the "present" signal is
223	//     made EASY to satisfy - the exact quoted phrase, OR a DISTINCTIVE token pair co-occurring, OR a
224	//     findability page of the right class exists - and propose fires the absence-breach only when NONE
225	//     of these hold across the covered surface (total silence). A partially-present disclosure abstains.
226	//   - 'behavioural' / 'register': the tokens do not scan the site; they route the obligation to the
227	//     right observation/register in propose.js, so a lenient 'any' set is correct.
228	// An element that reduces to nothing distinctive is returned as unpatternable: propose.js abstains
229	// rather than fire a low-precision pattern (the C-049 "mute or over-broad" trap - refuse to guess).
230	function patternsFromElement(elementText, evidenceType, pageClass) {
231	  const phrases = quotedSpans(elementText);
232	  const tokens = salientTokens(elementText);
233	  const patterns = phrases
234	    .map((p) => buildAnchoredRegex(p))
235	    .filter(Boolean)
236	    .map((src) => ({ kind: 'anchored-regex', value: src, negation_guarded: evidenceType === 'absence' }));
237	  addDerivedTokenPattern(patterns, phrases, tokens, evidenceType);
238	  if (evidenceType === 'presence' && pageClass && pageClass !== 'any' && FINDABILITY_RX.test(elementText)) {
239	    patterns.push({ kind: 'url-path', value: '/' + pageClass, negation_guarded: false });
240	  }
241	  return { patterns, unpatternable: patterns.length === 0 };
242	}
243	
244	// addDerivedTokenPattern(patterns, phrases, tokens, evidenceType) -> pushes the one token-set this
245	// element contributes, polarity-aware per the doctrine above. Kept separate so patternsFromElement
246	// stays within the health-gate function-length cap.
247	function addDerivedTokenPattern(patterns, phrases, tokens, evidenceType) {
248	  if (evidenceType === 'absence') {
249	    // A quoted prohibited phrase is the precise matcher; do not dilute it with a token-set. Without a
250	    // quote, only a DISTINCTIVE multi-token set (matched later within ONE sentence) is safe enough to
251	    // pattern a prohibition on; a single or generic token is refused (C-059/C-078). Recall is
252	    // deliberately traded for precision here - a missed prohibition is recoverable, a false accusation
253	    // is not.
254	    if (phrases.length) return;
255	    const distinctive = topDistinctive(tokens, 3);
256	    if (distinctive.length >= 2) patterns.push({ kind: 'token-set', value: { tokens: distinctive, mode: 'all' }, negation_guarded: true });
257	    return;
258	  }
259	  if (evidenceType === 'presence') {
260	    const distinctive = topDistinctive(tokens, 2);
261	    if (distinctive.length >= 2) patterns.push({ kind: 'token-set', value: { tokens: distinctive, mode: 'all' }, negation_guarded: false });
262	    return;
263	  }
264	  // behavioural | register: lane-routing tokens, matched leniently in propose.js against the observation
265	  // kind / register, never against site prose.
266	  if (tokens.length) patterns.push({ kind: 'token-set', value: { tokens, mode: 'any' }, negation_guarded: false });
267	}
268	
269	// dedupePatterns(patterns) -> patterns unique by (kind + normalised value), preserving order.
270	function dedupePatterns(patterns) {
271	  const seen = new Set();
272	  const out = [];
273	  for (const p of patterns) {
274	    const key = p.kind + '|' + (p.kind === 'token-set' ? (p.value.mode + ':' + p.value.tokens.join(',')) : p.value);
275	    if (seen.has(key)) continue;
276	    seen.add(key);
277	    out.push(p);
278	  }
279	  return out;
280	}
281	
282	// specForObligation(record, obligation, dutyIdx) -> one DetectionSpec, or null when the obligation has
283	// no id/record to bind to. Patterns are derived from the duty + every element; an obligation that yields
284	// no anchored pattern still produces a spec (with empty patterns) so it is VISIBLE as an honest
285	// coverage gap, never silently dropped - propose.js treats an empty-pattern spec as inert (abstains).
286	function specForObligation(record, obligation, dutyIdx) {
287	  if (!record || typeof record.id !== 'string' || !obligation) return null;
288	  const evidenceType = obligation.evidence_type;
289	  const pageClass = pageClassFor(obligation);
290	  const surface = surfaceFor(obligation);
291	  const sources = [obligation.duty, ...(Array.isArray(obligation.elements) ? obligation.elements : [])];
292	  let patterns = [];
293	  const unpatternable = [];
294	  for (const src of sources) {
295	    if (!src) continue;
296	    const r = patternsFromElement(src, evidenceType, pageClass);
297	    if (r.unpatternable) unpatternable.push(String(src));
298	    patterns = patterns.concat(r.patterns);
299	  }
300	  return {
301	    record_id: record.id,
302	    duty_idx: dutyIdx,
303	    evidence_type: evidenceType,
304	    surface,
305	    patterns: dedupePatterns(patterns),
306	    page_class: pageClass,
307	    unpatternable_elements: unpatternable,
308	  };
309	}
310	
311	// compileRecordSpecs(record) -> the DetectionSpec[] for one record's website_obligations[].
312	function compileRecordSpecs(record) {
313	  const obligations = (record && Array.isArray(record.website_obligations)) ? record.website_obligations : [];
314	  const specs = [];
315	  for (let i = 0; i < obligations.length; i++) {
316	    const spec = specForObligation(record, obligations[i], i);
317	    if (spec) specs.push(spec);
318	  }
319	  return specs;
320	}
321	
322	// recordsOf(catalogue) -> the records array from a compiled catalogue artifact ({records:[...]}) or a
323	// bare array; anything else is []. Tolerant so a caller may pass either shape.
324	function recordsOf(catalogue) {
325	  if (Array.isArray(catalogue)) return catalogue;
326	  if (catalogue && Array.isArray(catalogue.records)) return catalogue.records;
327	  return [];
328	}
329	
330	// compileCatalogue(catalogue) -> { specs, rejected }. Every obligation of every record becomes a spec;
331	// each spec is validated at the source (C-009/C-019), and any spec carrying an unanchored/bare pattern
332	// is REJECTED here with its reasons rather than shipped - an unanchored pattern is unrepresentable in
333	// what propose.js consumes.
334	function compileCatalogue(catalogue) {
335	  const specs = [];
336	  const rejected = [];
337	  for (const record of recordsOf(catalogue)) {
338	    for (const spec of compileRecordSpecs(record)) {
339	      const v = validateSpec(spec);
340	      if (v.valid) specs.push(spec);
341	      else rejected.push({ record_id: spec.record_id, duty_idx: spec.duty_idx, errors: v.errors });
342	    }
343	  }
344	  return { specs, rejected };
345	}
346	
347	// ── validation (the C-009/C-019 anchoring gate; the p3-proposer-unanchored-pattern fixture drives it) ──
348	// isAnchoredPatternValue(pattern) -> { ok, reason }. A pattern is REJECTED when it is bare/unanchored:
349	//   - anchored-regex: source must contain a \b word boundary or a ^/$ anchor AND must compile; a bare
350	//     alternation like "EU" or a bare substring like "cost" (no \b, no ^/$) is rejected (C-019/C-044/C-059).
351	//   - token-set: non-empty; every token >= MIN_TOKEN_LEN and a clean word (a 1-2 char or punctuation
352	//     token would substring-match, the "post"->postcode class C-059).
353	//   - url-path: a rooted single path segment ('/xxx'), never a bare word (the /cost-of-living class C-044).
354	function isAnchoredPatternValue(pattern) {
355	  if (!pattern || typeof pattern !== 'object') return { ok: false, reason: 'pattern is not an object' };
356	  if (!PATTERN_KINDS.includes(pattern.kind)) return { ok: false, reason: 'unknown pattern kind ' + JSON.stringify(pattern.kind) };
357	  if (pattern.kind === 'anchored-regex') return anchoredRegexOk(pattern.value);
358	  if (pattern.kind === 'token-set') return tokenSetOk(pattern.value);
359	  return urlPathOk(pattern.value);
360	}
361	
362	// REDOS_RX: catastrophic-backtracking constructs unrepresentable in a DERIVED anchored-regex (Rob P0:
363	// derived token-set lookaheads with [\s\S]* hung on real corpora). A derived phrase pattern is a
364	// `\b`-bounded word run joined by `\W+` and legitimately never needs any of these, so this rule fires
365	// only on a regression that reintroduces a ReDoS vector:
366	//   \(\?[=!<]        any lookaround (the old 'all' co-occurrence used (?=[\s\S]*...))
367	//   \[\\s\\S\]\*     an unbounded [\s\S]* (or [\S\s]*) wildcard star
368	//   (?:^|[^\\])\.\*  an unescaped .* dot-star ([^\\] so an escaped \.  literal dot is not flagged)
369	const REDOS_RX = /\(\?[=!<]|\[\\s\\S\]\*|\[\\S\\s\]\*|(?:^|[^\\])\.\*/;
370	// NESTED_QUANT_RX: a quantified group immediately re-quantified ((a+)+, (\w*)* ...), the classic
371	// exponential ReDoS. `\W+`/`\W*` are unparenthesised single quantifiers and never match this.
372	const NESTED_QUANT_RX = /\([^)]*[+*][^)]*\)\s*[+*]/;
373	
374	function anchoredRegexOk(value) {
375	  if (typeof value !== 'string' || !value.length) return { ok: false, reason: 'anchored-regex value must be a non-empty string' };
376	  if (!/\\b|\^|\$/.test(value)) return { ok: false, reason: 'anchored-regex is not anchored (no \\b, ^ or $): a bare pattern substring-matches (C-019/C-059)' };
377	  if (REDOS_RX.test(value) || NESTED_QUANT_RX.test(value)) {
378	    return { ok: false, reason: 'anchored-regex contains a catastrophic-backtracking construct (a lookaround, an unbounded .* / [\\s\\S]*, or a nested quantifier); derived patterns must be linear-time (Rob P0: real-corpus hang)' };
379	  }
380	  try {
381	    new RegExp(value, 'i');
382	  } catch (err) {
383	    // FAIL-OPEN: the error is RECORDED verbatim in the returned reason; validateSpec surfaces it (C-050).
384	    return { ok: false, reason: 'anchored-regex does not compile (C-050): ' + err.message };
385	  }
386	  return { ok: true, reason: null };
387	}
388	
389	function tokenSetOk(value) {
390	  const tokens = value && Array.isArray(value.tokens) ? value.tokens : null;
391	  if (!tokens || !tokens.length) return { ok: false, reason: 'token-set has no tokens' };
392	  if (value.mode !== 'all' && value.mode !== 'any') return { ok: false, reason: 'token-set mode must be "all" or "any"' };
393	  for (const t of tokens) {
394	    if (typeof t !== 'string' || t.length < MIN_TOKEN_LEN) return { ok: false, reason: 'token ' + JSON.stringify(t) + ' is shorter than the ' + MIN_TOKEN_LEN + '-char floor (a bare short token substring-matches, C-059)' };
395	    if (!/[a-z0-9]/i.test(t)) return { ok: false, reason: 'token ' + JSON.stringify(t) + ' has no word character' };
396	  }
397	  return { ok: true, reason: null };
398	}
399	
400	function urlPathOk(value) {
401	  if (typeof value !== 'string' || value[0] !== '/') return { ok: false, reason: 'url-path must be a rooted path segment ("/xxx"), never a bare word (C-044)' };
402	  if (!/^\/[a-z0-9][a-z0-9/-]*$/i.test(value)) return { ok: false, reason: 'url-path ' + JSON.stringify(value) + ' is not a clean path segment' };
403	  return { ok: true, reason: null };
404	}
405	
406	// validateSpec(spec) -> { valid, errors }. Shape gate + the anchoring gate on every pattern. A
407	// register/behavioural spec must carry page_class null (the crawl never gates a non-crawl lane); a
408	// presence/absence spec must carry a page_class string. Any bad pattern makes the whole spec invalid.
409	function validateSpec(spec) {
410	  const errors = [];
411	  if (!spec || typeof spec !== 'object') return { valid: false, errors: ['spec is not an object'] };
412	  if (typeof spec.record_id !== 'string' || !spec.record_id) errors.push('record_id must be a non-empty string');
413	  if (!Number.isInteger(spec.duty_idx) || spec.duty_idx < 0) errors.push('duty_idx must be a non-negative integer');
414	  if (!EVIDENCE_TYPES.includes(spec.evidence_type)) errors.push('evidence_type ' + JSON.stringify(spec.evidence_type) + ' is not one of ' + EVIDENCE_TYPES.join('/'));
415	  if (!SURFACES.includes(spec.surface)) errors.push('surface ' + JSON.stringify(spec.surface) + ' is not one of ' + SURFACES.join('/'));
416	  validatePageClass(spec, errors);
417	  validatePatterns(spec, errors);
418	  return { valid: errors.length === 0, errors };
419	}
420	
421	function validatePageClass(spec, errors) {
422	  const laneOnly = spec.evidence_type === 'register' || spec.evidence_type === 'behavioural';
423	  if (laneOnly && spec.page_class !== null) errors.push('a ' + spec.evidence_type + ' spec must have page_class null (its evidence is a non-crawl lane)');
424	  if (!laneOnly && typeof spec.page_class !== 'string') errors.push('a ' + spec.evidence_type + ' spec must declare a page_class string');
425	}
426	
427	function validatePatterns(spec, errors) {
428	  if (!Array.isArray(spec.patterns)) { errors.push('patterns must be an array'); return; }
429	  for (let i = 0; i < spec.patterns.length; i++) {
430	    const p = spec.patterns[i];
431	    if (typeof p.negation_guarded !== 'boolean') errors.push('patterns[' + i + '].negation_guarded must be a boolean');
432	    const v = isAnchoredPatternValue(p);
433	    if (!v.ok) errors.push('patterns[' + i + '] rejected: ' + v.reason);
434	  }
435	}
436	
437	module.exports = {
438	  EVIDENCE_TYPES,
439	  SURFACES,
440	  PATTERN_KINDS,
441	  MIN_TOKEN_LEN,
442	  // compilation
443	  compileCatalogue,
444	  compileRecordSpecs,
445	  specForObligation,
446	  patternsFromElement,
447	  pageClassFor,
448	  surfaceFor,
449	  salientTokens,
450	  quotedSpans,
451	  // anchoring primitives + matcher helpers (one door, shared with propose.js so no second matcher drifts)
452	  anchorToken,
453	  buildAnchoredRegex,
454	  compileRegex,
455	  matchesText,
456	  tokenContains,
457	  NEGATION_RX,
458	  isNegated,
459	  looksLikeReview,
460	  splitSentences,
461	  isProse,
462	  // validation
463	  validateSpec,
464	  isAnchoredPatternValue,
465	};
466

