function salientTokens(text) {
  const raw = String(text || '').toLowerCase().match(/[a-z0-9][a-z0-9'-]*[a-z0-9]|[a-z0-9]/g) || [];
  const out = [];
  const seen = new Set();
  for (const w of raw) {
    if (w.length < MIN_TOKEN_LEN || STOPWORDS.has(w) || seen.has(w)) continue;
    seen.add(w);
    out.push(w);
    if (out.length >= MAX_TOKENS) break;
  }
  return out;
}

