229	// absenceInterlock(detectionSpec, bundle, coverageState) -> a suppression reason, or null when the
230	// coverage interlock is fully satisfied (C-024/C-025/C-026/C-036). Fail-closed: any doubt suppresses.
231	function absenceInterlock(detectionSpec, bundle, coverageState) {
232	  if (coverageState !== 'covered') return 'coverage ' + coverageState + ' for this rule; an absence claim needs a proven page-class (C-029)';
233	  if (detectionSpec.surface === 'raw_html') return 'required mechanism lives in raw HTML, unreadable in the stripped corpus; abstained rather than fabricate a missing-mechanism breach (C-036/C-032)';
234	  if (detectionSpec.surface === 'footer' && !footerOf(bundle)) return 'no footer surface was captured; a registration-disclosure absence cannot be asserted (C-034)';
235	  if (pagesOf(bundle).length < MIN_PAGES_FOR_ABSENCE) return 'corpus below the ' + MIN_PAGES_FOR_ABSENCE + '-page floor for an absence claim (C-025)';
236	  if (isTruncated(bundle)) return 'corpus was truncated; the required content may sit past the cut, so the absence claim is demoted (C-024)';
237	  return null;
238	}
239	
240	// evalAbsenceBreach: a 'presence' obligation (REQUIRED content). If the content is present -> clean pass.
241	// If absent, the interlock decides: satisfied -> an absence-breach with a coverage_proof artifact
242	// (confidence moderate); unsatisfied -> a recorded suppression.
243	function evalAbsenceBreach(detectionSpec, bundle, coverageState) {
244	  if (!detectionSpec.patterns.length) return null;
245	  const pages = pagesOf(bundle);
246	  const surface = surfaceTextForPresence(detectionSpec, pages, footerOf(bundle));
247	  if (requiredContentPresent(detectionSpec, surface.text, pages)) return null; // present -> no breach
248	  const block = absenceInterlock(detectionSpec, bundle, coverageState);
249	  if (block) return suppressed(detectionSpec, KIND.ABSENCE_BREACH, block);
250	  // tier1_fetched + truncated ride the artifact at emit (D2, ledger decision 2): the coverage_proof
251	  // verifier re-checks them independently (defence in depth, Rule 3/4). tier1_fetched is TRUE here
252	  // because absenceInterlock only reaches this point when coverageState==='covered' - the crawler's
253	  // proof the needed page-class was fetched before any cap (C-026); truncated is read straight off the
254	  // bundle and is FALSE here because the interlock demotes a truncated corpus above (C-024).
255	  const artifact = {
256	    type: ARTIFACT_TYPES.COVERAGE_PROOF,
257	    page_class: detectionSpec.page_class,
258	    surface: detectionSpec.surface,
259	    pages_checked: surface.coveredPages,
260	    searched_patterns: detectionSpec.patterns.map(patternSummary),
261	    tier1_fetched: true,
262	    truncated: isTruncated(bundle),
263	  };
264	  return candidate(detectionSpec, KIND.ABSENCE_BREACH, artifact, null, 'moderate');
265	}
266	function patternSummary(pattern) {
267	  if (pattern.kind === 'token-set') return { kind: pattern.kind, tokens: pattern.value.tokens, mode: pattern.value.mode };
268	  return { kind: pattern.kind, value: pattern.value };
269	}
270	
271	// specTokens(detectionSpec) -> the flat set of lane-routing tokens a behavioural/register spec carries.
272	function specTokens(detectionSpec) {
273	  const out = new Set();
274	  for (const p of detectionSpec.patterns) {
275	    if (p.kind === 'token-set') for (const t of p.value.tokens) out.add(String(t).toLowerCase());
276	  }
277	  return out;
278	}
279	// obligationConcerns(detectionSpec, obsKind) -> does this behavioural obligation concern an observation
280	// of this kind (token intersection with the generic concept set); gates C-039/C-042 to consent duties.
281	function obligationConcerns(detectionSpec, obsKind) {
282	  const concepts = OBSERVATION_CONCEPTS[obsKind] || [];
283	  const tokens = specTokens(detectionSpec);
284	  return concepts.some((c) => tokens.has(c) || [...tokens].some((t) => t.includes(c)));
285	}
286	
287	// laneRan(browser) -> true only when the browser lane definitively ran; laneReason gives the recorded
288	// non-run reason (C-041: an evidence lane's absence is visible, never silent).
289	function laneRan(browser) {
290	  return Boolean(browser && browser.lane && browser.lane.ran === true);
291	}
292	function laneReason(browser) {
293	  return (browser && browser.lane && browser.lane.reason) || 'browser lane did not run';
294	}
295	// observedCandidates(detectionSpec, observed) -> a behavioural candidate per observation this obligation
296	// concerns (C-039: a pre-consent cookie set is a completed observed breach with the event as artifact).
297	// This is the SINGLE door for every browser observation, INCLUDING a broken consent control (C-042):
298	// evidence/browser/observe.js pushes a `consent_control_broken` entry into bundle.browser.observed[]
299	// with its host derived through the tools/lib/safe-fetch.js parsed-host door (never substring-matched),
300	// so wrapping that entry here as a network_event REUSES the observed-entry shape verbatim and verifies
301	// unchanged against breach/verifiers/network-event.js (D4, ledger decision 4). There is deliberately no
302	// second broken-control path off bundle.browser.consentControl: a divergent path would double-count the
303	// same breach (the summary and observed[] both carry it) and its bespoke shape lacked the host/name
304	// verifyNetworkEvent matches on, so it could never verify.
305	function observedCandidates(detectionSpec, observed) {
306	  const out = [];
307	  for (const ev of (Array.isArray(observed) ? observed : [])) {
308	    if (!ev || !ev.kind || !obligationConcerns(detectionSpec, ev.kind)) continue;
309	    out.push(candidate(detectionSpec, KIND.BEHAVIOURAL, { type: ARTIFACT_TYPES.NETWORK_EVENT, ...ev }, ev.host || ev.url || null, 'strong'));
310	  }
311	  return out;
312	}
313	// evalBehavioural: consume bundle.browser. The lane not running is a recorded suppression (C-041).
314	function evalBehavioural(detectionSpec, bundle) {
315	  const browser = bundle && bundle.browser;
316	  if (!laneRan(browser)) return [suppressed(detectionSpec, KIND.BEHAVIOURAL, 'browser lane unavailable: ' + laneReason(browser) + ' (C-041)')];
317	  return observedCandidates(detectionSpec, browser.observed);
318	}
319	
320	// registerTargetFor(detectionSpec, record, keys) -> the bundle register key this record's register duty
321	// checks, derived from the record's OWN id/citation/register_url tokens against the bundle's OWN register
322	// keys (data-driven; no regulator name is authored here - Rule 2), or null when unresolved.
323	function registerTargetFor(record, keys) {
324	  const blob = [record && record.id, record && record.regulator && record.regulator.register_url,
325	    record && record.citation && record.citation.url].filter(Boolean).join(' ').toLowerCase();
326	  return keys.find((k) => blob.includes(String(k).toLowerCase())) || null;
327	}
328	// evalRegister: consume bundle.registers. A present matched row is compliant (no candidate). A DEFINITIVE
329	// no_match note (C-004) is a weak candidate carrying a `register_absence` artifact (its own artifact
330	// class, distinct from a register_row which cites a row that is PRESENT - ledger decision 3): the
331	// register lane RAN and returned no name-match. Any other state (no target resolvable, a degraded/skipped
332	// lane, no note at all) is a recorded suppression. The candidate is WEAK: a no-match is not proof of
333	// non-registration (a slightly different registered name can miss the match), so the adjudicator
334	// quarantines it to needs_review rather than shipping a hard violation (Rule 6).
335	function evalRegister(detectionSpec, bundle, record) {
336	  const registers = (bundle && bundle.registers) || {};
337	  const keys = Object.keys(registers).filter((k) => k !== 'notes');
338	  const notes = Array.isArray(registers.notes) ? registers.notes : [];
339	  const noteKeys = notes.map((n) => n && n.register).filter(Boolean);
340	  const target = registerTargetFor(record, [...new Set([...keys, ...noteKeys])]);
341	  if (!target) return suppressed(detectionSpec, KIND.REGISTER, 'no register lane resolvable for this record (unregistered lane / no lookup)');
342	  if (registers[target]) return null; // a matched row is present -> compliant on this duty
343	  const note = notes.find((n) => n && n.register === target);
344	  if (note && note.kind === 'no_match') {
345	    const artifact = { type: ARTIFACT_TYPES.REGISTER_ABSENCE, register: target, query: (note.query || note.detail) || null, lane: 'no_match', note };
346	    return candidate(detectionSpec, KIND.REGISTER, artifact, null, 'weak');
347	  }
348	  return suppressed(detectionSpec, KIND.REGISTER, 'register "' + target + '" not definitively checked (' + ((note && note.kind) || 'no note') + '); a no-match is required before a non-appearance claim (C-004)');
349	}
350	
351	// ── the router ──────────────────────────────────────────────────────────────────────────────────────
352	function recordsForIndex(catalogue) {
353	  if (Array.isArray(catalogue)) return catalogue;
354	  if (catalogue && Array.isArray(catalogue.records)) return catalogue.records;
355	  return [];
356	}
357	function recordIndex(catalogue) {
358	  const map = new Map();
359	  for (const r of recordsForIndex(catalogue)) if (r && r.id) map.set(r.id, r);
360	  return map;
361	}
362	
363	// evaluateSpec(detectionSpec, bundle, coverage, record) -> candidate[] for one spec (0..n). Exported for
364	// unit tests. A page-class-bearing spec whose coverage is 'screened' NEVER proposes (C-029), the hard
365	// block applied before any evidence is read.
366	function evaluateSpec(detectionSpec, bundle, coverage, record) {
367	  const coverageState = coverageStateFor(coverage, detectionSpec.record_id);
368	  if (detectionSpec.page_class !== null && coverageState === 'screened') {
369	    return [suppressed(detectionSpec, kindForType(detectionSpec.evidence_type), 'page-class coverage screened; a screened rule never proposes (C-029)')];
370	  }
371	  if (detectionSpec.evidence_type === 'absence') return listOf(evalPresenceBreach(detectionSpec, pagesOf(bundle)));
372	  if (detectionSpec.evidence_type === 'presence') return listOf(evalAbsenceBreach(detectionSpec, bundle, coverageState));
373	  if (detectionSpec.evidence_type === 'behavioural') return evalBehavioural(detectionSpec, bundle);
374	  if (detectionSpec.evidence_type === 'register') return listOf(evalRegister(detectionSpec, bundle, record));
375	  return [];
376	}
377	function kindForType(evidenceType) {
378	  if (evidenceType === 'absence') return KIND.PRESENCE_BREACH;
379	  if (evidenceType === 'presence') return KIND.ABSENCE_BREACH;
380	  if (evidenceType === 'behavioural') return KIND.BEHAVIOURAL;
381	  return KIND.REGISTER;
382	}
383	function listOf(x) { return x ? [x] : []; }
384	
385	// propose(bundle, catalogue, coverage) -> candidates[]. The public entry. Compiles the catalogue to
386	// DetectionSpecs in memory, then evaluates each. An unreadable (C-038) or non-English-gated (C-022)
387	// bundle asserts nothing at all.
388	function propose(bundle, catalogue, coverage) {
389	  if (isUnreadable(bundle) || isNonEnglishGated(bundle)) return [];
390	  const { specs } = spec.compileCatalogue(catalogue);
391	  const records = recordIndex(catalogue);
392	  const out = [];
393	  for (const detectionSpec of specs) {
394	    const record = records.get(detectionSpec.record_id) || null;
395	    for (const c of evaluateSpec(detectionSpec, bundle, coverage, record)) out.push(c);
396	  }
397	  return out;
398	}
399	
400	module.exports = {
401	  propose,
402	  evaluateSpec,
403	  KIND,
404	  MIN_PAGES_FOR_ABSENCE,
405	  // exported for tests + reuse (one door for the matchers)
406	  requiredContentPresent,
407	  findProhibitedQuote,
408	  registerTargetFor,
409	  coverageStateFor,
410	  absenceInterlock,
411	};
