41	 * ── the ONE documented quote normalisation (Gate 2) ─────────────────────────────────────────────────
42	 *
43	 * Every run of whitespace characters (space, tab, newline, CR, form feed, vertical tab, and any
44	 * mixture of them) collapses to a single ASCII space. Nothing else: no case folding, no punctuation
45	 * stripping, no unicode normalisation, no trimming beyond what a whitespace-run collapse already does
46	 * at a string's edge. This is deliberately the SAME normalisation on both sides (the candidate's
47	 * quote and the bundle page's declared-surface text) and nothing more, because a second silent
48	 * transformation is exactly how Gate 2 could be weakened without anyone noticing: the whole point of
49	 * an "exact" re-match is that there is only one documented rule standing between "verified" and
50	 * "fabricated". Whitespace-only collapsing is necessary because the crawler's stripHtml()
51	 * (evidence/crawler/extract.js) turns block-level HTML boundaries into newlines while a proposer's
52	 * candidate quote is typically authored as a single line; without this one normalisation, a
53	 * genuinely-quoted sentence spanning a paragraph break would be rejected as a false mismatch. No
54	 * other drift (a changed word, a changed character, a re-cased letter) is tolerated: that is
55	 * precisely the class Gate 2 exists to catch (caution.md C-032 - models paraphrase inside quotation
56	 * marks).
57	 *
58	 * ── the detection-surface doctrine (caution.md C-035) ───────────────────────────────────────────────
59	 *
60	 * "Detection surface = evidence surface": a candidate declares which surface it detected the quote on
61	 * (`visible_text`, the stripped text every EvidenceBundle page carries per facts/README.md, or
62	 * `raw_html`, an optional richer surface some rules legitimately need per caution.md C-036's
63	 * trigger/mechanism asymmetry - e.g. proving a consent-manager script TAG is present, which stripHtml
64	 * deliberately removes from visible_text). This module matches the quote against EXACTLY the
65	 * declared surface and no other: a raw_html-only string can never satisfy a visible_text candidate,
66	 * and vice versa. The canonical EvidenceBundle.corpus.pages shape (facts/README.md) does not
67	 * currently carry a raw_html field - only evidence/crawler/'s own future work can add it - so a
68	 * raw_html candidate against a bundle page with no such field is honestly UNVERIFIABLE (rejected,
69	 * never assumed true).
70	 */
71	const { CODES, accepted, rejected } = require('./result');
72	const { ARTIFACT_TYPES } = require('../artifact-types');
73	const { verifyNetworkEvent } = require('./network-event');
74	const { verifyRegisterRow } = require('./register-row');
75	const { verifyRegisterAbsence } = require('./register-absence');
76	const { verifyCoverageProof } = require('./coverage-proof');
77	
78	const VALID_SURFACES = new Set(['visible_text', 'raw_html']);
79	
80	// normaliseWhitespace(s) -> s with every run of whitespace collapsed to a single space. THE one
81	// documented normalisation Gate 2 permits (see header). Applied identically to the candidate's quote
82	// and to the bundle page's declared-surface text before the exact-substring check.
83	function normaliseWhitespace(s) {
84	  return String(s == null ? '' : s).replace(/\s+/g, ' ');
85	}
86	
87	// surfaceText(page, surface) -> the declared surface's text on this bundle page, or null when that
88	// surface is not present (an honest "cannot verify", never a silent fallback to the other surface).
89	function surfaceText(page, surface) {
90	  if (surface === 'visible_text') return typeof page.text === 'string' ? page.text : null;
91	  if (surface === 'raw_html') return typeof page.rawHtml === 'string' ? page.rawHtml : null;
92	  return null;
93	}
94	
95	function findPage(bundle, pageUrl) {
96	  const pages = bundle && bundle.corpus && Array.isArray(bundle.corpus.pages) ? bundle.corpus.pages : [];
97	  return pages.find((p) => p && p.url === pageUrl) || null;
98	}
99	
100	// verifyQuote(artifact, bundle) -> {verified, code, reason}. Gate 2 itself: fails closed on missing
101	// fields, an unrecognised surface, a page absent from the bundle, a declared surface absent from
102	// that page, or (after the one whitespace normalisation) a quote that is not an exact substring of
103	// the declared surface's text.
104	function verifyQuote(artifact, bundle) {
105	  if (typeof artifact.page_url !== 'string' || !artifact.page_url) {
106	    return rejected(CODES.QUOTE_MISSING_FIELDS, 'artifact.page_url is required');
107	  }
108	  if (typeof artifact.quote !== 'string' || !artifact.quote || !artifact.quote.trim()) {
109	    return rejected(CODES.QUOTE_MISSING_FIELDS, 'artifact.quote is required and must not be empty or whitespace-only');
110	  }
111	  if (!VALID_SURFACES.has(artifact.surface)) {
112	    return rejected(
113	      CODES.QUOTE_INVALID_SURFACE,
114	      'artifact.surface must be "visible_text" or "raw_html", got ' + JSON.stringify(artifact.surface)
115	    );
116	  }
117	  const page = findPage(bundle, artifact.page_url);
118	  if (!page) {
119	    return rejected(CODES.QUOTE_PAGE_NOT_FOUND, 'no bundle page at ' + JSON.stringify(artifact.page_url));
120	  }
121	  const rawSurfaceText = surfaceText(page, artifact.surface);
122	  if (rawSurfaceText === null) {
123	    return rejected(
124	      CODES.QUOTE_SURFACE_UNAVAILABLE,
125	      'the "' + artifact.surface + '" surface is not present on this bundle page '
126	        + '(C-035: detection surface and evidence surface must be the same corpus)'
127	    );
128	  }
129	  const quoteNormalised = normaliseWhitespace(artifact.quote);
130	  const surfaceNormalised = normaliseWhitespace(rawSurfaceText);
131	  if (!surfaceNormalised.includes(quoteNormalised)) {
132	    return rejected(
133	      CODES.QUOTE_MISMATCH,
134	      'quote does not exact-match (after whitespace-run normalisation) the "' + artifact.surface
135	        + '" surface of ' + JSON.stringify(artifact.page_url)
136	    );
137	  }
138	  return accepted(
139	    CODES.QUOTE_VERIFIED,
140	    'quote exact-matched the declared "' + artifact.surface + '" surface of ' + JSON.stringify(artifact.page_url)
141	  );
142	}
143	
144	const VERIFIERS_BY_TYPE = {
145	  [ARTIFACT_TYPES.QUOTE]: verifyQuote,
146	  [ARTIFACT_TYPES.NETWORK_EVENT]: verifyNetworkEvent,
147	  [ARTIFACT_TYPES.REGISTER_ROW]: verifyRegisterRow,
148	  [ARTIFACT_TYPES.REGISTER_ABSENCE]: verifyRegisterAbsence,
149	  [ARTIFACT_TYPES.COVERAGE_PROOF]: verifyCoverageProof,
150	};
151	
152	// resolveQuoteArtifact(candidate, artifact) -> an effective quote artifact with real-proposer shape
153	// variance absorbed. Confirmed by direct integration probing against the landed breach/proposers/
154	// propose.js (evalPresenceBreach): it emits `artifact.text` rather than `artifact.quote`, and puts
155	// `page_url` on the CANDIDATE rather than on the artifact (`candidate(detectionSpec,
156	// KIND.PRESENCE_BREACH, {type:'quote', text, surface}, found.page_url, ...)` in propose.js). Both this
157	// module's originally-specified field names (artifact.page_url, artifact.quote) and propose.js's
158	// actual field names are accepted; an artifact-level field always wins when present, so nothing that
159	// already worked stops working - this only widens what verifyQuote can read. Only 'quote' artifacts
160	// are touched; every other type passes through unchanged. This is a narrow, additive compatibility
161	// seam, not a redesign of the artifact contract: it does not relax WHAT is verified (the exact-match
162	// check in verifyQuote is unchanged), only WHERE the same two facts (which page, what quote) may be
163	// read from on the way in.
164	function resolveQuoteArtifact(candidate, artifact) {
165	  if (!artifact || artifact.type !== ARTIFACT_TYPES.QUOTE) return artifact;
166	  const pageUrl = artifact.page_url == null ? (candidate && candidate.page_url) : artifact.page_url;
167	  const quote = artifact.quote == null ? artifact.text : artifact.quote;
168	  if (pageUrl === artifact.page_url && quote === artifact.quote) return artifact;
169	  return Object.assign({}, artifact, { page_url: pageUrl, quote });
170	}
171	
172	// verifyCandidate(candidate, bundle) -> {verified, code, reason}. The fail-closed dispatcher: an
173	// unknown artifact.type is REJECTED, never passed through untested (Rule 4). Never mutates
174	// `candidate`.
175	function verifyCandidate(candidate, bundle) {
176	  if (!candidate || typeof candidate !== 'object') {
177	    return rejected(CODES.INVALID_CANDIDATE, 'candidate must be a non-null object');
178	  }
179	  const artifact = candidate.artifact;
180	  if (!artifact || typeof artifact !== 'object' || typeof artifact.type !== 'string' || !artifact.type) {
181	    return rejected(CODES.MISSING_ARTIFACT, 'candidate.artifact.type is required (Rule 3: no artifact, no breach)');
182	  }
183	  const verify = VERIFIERS_BY_TYPE[artifact.type];
184	  if (!verify) {
185	    return rejected(
186	      CODES.UNKNOWN_ARTIFACT_TYPE,
187	      'unrecognised artifact.type ' + JSON.stringify(artifact.type) + '; unknown artifact types fail closed, never pass through'
188	    );
189	  }
190	  return verify(resolveQuoteArtifact(candidate, artifact), bundle);
191	}
192	
193	// verifyAll(candidates, bundle) -> {verified:[{candidate,verified,code,reason}], rejected:[...]}.
194	// Pure filter: every candidate is judged independently against the SAME bundle, the original
195	// candidate reference is carried unmodified in the result envelope, and nothing is ever dropped
196	// silently - a rejected entry always carries its code and reason.
197	function verifyAll(candidates, bundle) {
198	  const list = Array.isArray(candidates) ? candidates : [];
199	  const verified = [];
200	  const rejectedList = [];
201	  for (const candidate of list) {
202	    const result = verifyCandidate(candidate, bundle);
203	    const entry = { candidate, verified: result.verified, code: result.code, reason: result.reason };
204	    (result.verified ? verified : rejectedList).push(entry);
205	  }
206	  return { verified, rejected: rejectedList };
207	}
208	
209	// ---------------------------------------------------------------------------------
210	// Calibration CLI (the earn-your-zero contract, eval/calibration-known-bad/run.js dialect; mirrors
211	// facts/identity.js and evidence/registers/registers.js's --calibrate convention exactly so a future
212	// CALIBRATIONS entry in eval/calibration-known-bad/run.js needs no adaptation).
213	// `node breach/verifiers/quote-match.js --calibrate [--json <path>]` runs every p3-verifier-*.json
214	// fixture under eval/calibration-known-bad/fixtures/ through verifyCandidate. Each fixture plants a
215	// candidate that must be REJECTED; a finding is emitted only when the rejection actually happens (and
216	// matches the fixture's expected_code, when given). Zero findings means this gate is broken.
217	// ---------------------------------------------------------------------------------
218	function runOneFixture(file, fixture) {
219	  const result = verifyCandidate(fixture.candidate, fixture.bundle);
220	  const poison = fixture.poison || {};
221	  const expectedCode = poison.expected_code;
222	  const caught = result.verified === false && (!expectedCode || result.code === expectedCode);
223	  if (!caught) return [];
224	  return [{
225	    file,
226	    line: 1,
227	    rule: 'p3-verifier-artifact-rejected',
228	    message: 'refused the poisoned candidate (' + result.code + '): ' + result.reason,
229	  }];
230	}
231	
232	function runCalibration(fixturesDir) {
233	  const fs = require('fs');
234	  const path = require('path');
235	  const dir = fixturesDir || path.join(__dirname, '..', '..', 'eval', 'calibration-known-bad', 'fixtures');
236	  const findings = [];
237	  const files = fs.readdirSync(dir).filter((f) => /^p3-verifier-.*\.json$/.test(f)).sort();
238	  for (const f of files) {
239	    if (!/^[a-z0-9][a-z0-9.-]{0,251}$/i.test(f)) {
240	      throw new Error('unsafe path component: ' + JSON.stringify(f));
241	    }
242	    const abs = path.join(dir, f);
243	    const fixture = JSON.parse(fs.readFileSync(abs, 'utf8'));
244	    findings.push(...runOneFixture(abs, fixture));
245	  }
246	  return findings;
247	}
248	
249	function calibrateMain(argv) {
250	  const fs = require('fs');
251	  const args = argv.slice(2);
252	  const jsonIdx = args.indexOf('--json');
253	  const jsonPath = jsonIdx !== -1 ? args[jsonIdx + 1] : null;
254	  const findings = runCalibration();
255	  if (jsonPath) fs.writeFileSync(jsonPath, JSON.stringify(findings, null, 2));
256	  process.stdout.write(JSON.stringify({ checker: 'breach-verifiers', findings }) + '\n');
257	  return 0;
258	}
259	
260	if (require.main === module) {
261	  if (process.argv.includes('--calibrate')) {
262	    process.exit(calibrateMain(process.argv));
263	  } else {
264	    console.error('breach/verifiers/quote-match.js is a library. Only --calibrate is runnable from the CLI.');
265	    process.exit(2);
266	  }
267	}
268	
269	module.exports = {
270	  verifyCandidate,
271	  verifyAll,
272	  verifyQuote,
273	  normaliseWhitespace,
274	  resolveQuoteArtifact,
275	  CODES,
276	  runCalibration,
277	  calibrateMain,
278	};
279

