96	// withDeadline(promise, ms, onTimeout): resolve { timedOut:false, value } when `promise` settles
97	// first, or { timedOut:true } when the cap fires first. The abandoned promise gets a no-op catch so
98	// a late rejection cannot surface as an unhandled rejection. No floor, no minimum wait (Rule 8).
99	function withDeadline(promise, ms, onTimeout) {
100	  let timer = null;
101	  const settled = promise.then(
102	    (value) => ({ timedOut: false, value }),
103	    (error) => ({ timedOut: false, value: null, error })
104	  );
105	  const timeout = new Promise((resolve) => {
106	    timer = setTimeout(() => { if (onTimeout) onTimeout(); resolve({ timedOut: true }); }, ms);
107	    if (timer && typeof timer.unref === 'function') timer.unref();
108	  });
109	  return Promise.race([settled, timeout]).finally(() => { if (timer) clearTimeout(timer); });
110	}
111	
112	// interpretResponse(response): reduce an injected caller's return to { ok, text, error } at the
113	// transport level. { ok:false } or empty text is a provider-level failure the chain falls over.
114	function interpretResponse(response) {
115	  if (response == null) return { ok: false, text: '', error: 'null_response' };
116	  if (typeof response === 'string') {
117	    return response.trim() ? { ok: true, text: response } : { ok: false, text: '', error: 'empty_text' };
118	  }
119	  if (response.ok === false) return { ok: false, text: '', error: String(response.error || 'provider_error') };
120	  const text = typeof response.text === 'string' ? response.text : '';
121	  if (!text.trim()) return { ok: false, text: '', error: 'empty_text' };
122	  return { ok: true, text };
123	}
124	
125	// errText(e): a short message for a rejected provider call (the injected caller threw or its promise
126	// rejected). withDeadline already converts a rejection into a resolved { error } result, so no catch
127	// is needed in callProvider - the failure is a first-class value, never an uncaught throw.
128	function errText(e) {
129	  return String((e && e.message) || e).slice(0, 60);
130	}
