132	// callProvider(provider, task, deadlineMs, validate, log): one deadline-bounded attempt at one
133	// provider. Returns { ok, value?, text?, response?, record }. `record` is always populated for the
134	// attempts ledger (Part B Rule 9: log every routing decision). A structural `validate` (llm/gate.js)
135	// turns a transport success into a routing success ONLY when the response also passes the gate - a
136	// fluent-but-hallucinated answer must not win just because the socket returned 200.
137	async function callProvider(provider, task, deadlineMs, validate, log) {
138	  const t0 = Date.now();
139	  const controller = new AbortController();
140	  // withDeadline converts BOTH a fulfilment and a rejection into a resolved result, so a throwing
141	  // injected caller is a first-class value here (raced.error), never an uncaught throw - no catch
142	  // is needed, and a rejection cleanly falls the chain OVER to the next provider (fail-closed system).
143	  const raced = await withDeadline(
144	    Promise.resolve().then(() => provider.call(task, { signal: controller.signal })),
145	    deadlineMs,
146	    () => controller.abort()
147	  );
148	  const ms = Date.now() - t0;
149	  const base = { provider: provider.name, family: provider.family, ms };
150	  if (raced.timedOut) return finalize(base, 'timeout', null, log);
151	  if (raced.error !== undefined) return finalize(base, 'threw:' + errText(raced.error), null, log);
152	  const interp = interpretResponse(raced.value);
153	  if (!interp.ok) return finalize(base, interp.error, null, log);
154	  if (typeof validate === 'function') return validated(base, interp, raced.value, validate, log);
155	  return { ok: true, text: interp.text, response: raced.value, record: logged(base, 'ok', log) };
156	}
