158	// validated(base, interp, raw, validate, log): apply the injected structural gate to a transport
159	// success. A rejection is recorded as 'gate_reject' and treated as a provider failure (fall over).
160	function validated(base, interp, raw, validate, log) {
161	  const verdict = validate(raw != null ? raw : interp.text);
162	  if (verdict && verdict.ok) {
163	    return { ok: true, value: verdict.value, text: interp.text, response: raw, record: logged(base, 'ok', log) };
164	  }
