180	// logged(base, outcome, log): stamp the outcome on the attempt record and emit it to the injected
181	// sink if one was supplied (the router never writes anywhere itself).
182	function logged(base, outcome, log) {
183	  const record = { provider: base.provider, family: base.family, outcome, ms: base.ms };
