212	// defaultVeto(vote): the standing veto polarity for a findings jury (Part A Pattern 5: weak judges
213	// have high true-positive but very low true-negative rates, so a REJECTION is the trustworthy signal
214	// and veto-to-reject is the correct polarity). A juror vetoes when it declares an explicit veto, or
215	// when its validated verdict is anything other than the affirmative 'violation'.
216	function defaultVeto(vote) {
217	  const v = (vote && vote.value) || {};
218	  if (v.veto === true) return { veto: true, reason: String(v.reason || 'explicit_veto').slice(0, 80) };
