225	// firstVeto(valid, vetoRule): the first juror to veto, or null when the jury is unanimous.
226	function firstVeto(valid, vetoRule) {
227	  for (const vote of valid) {
228	    const r = vetoRule(vote);
229	    if (r && r.veto) return { provider: vote.provider, reason: String(r.reason || 'veto') };
230	  }
231	  return null;
232	}
