234	// collectVotes(jurors, task, deadlineMs, validate, log): call each juror, gate.js-validate each
235	// response BEFORE it may vote (Rule 12: gates 1-4 run per response), and return the vote ledger.
236	async function collectVotes(jurors, task, deadlineMs, validate, log) {
237	  const votes = [];
238	  for (const juror of jurors) {
239	    const outcome = await callProvider(juror, task, deadlineMs, validate, log);
240	    if (outcome.ok) votes.push({ provider: juror.name, family: juror.family, value: outcome.value != null ? outcome.value : { text: outcome.text } });
