246	// quorum(task, opts): the diverse-jury, veto-to-reject gate for P0/P1 findings (Rule 12 gate 5).
247	//   - A CURATED fact (task.curated: an in-set catalogue assertion) is IMMUNE: the jury has no
248	//     authority to veto it (caution.md C-131 - the LLM once vetoed the SRA off an SRA-regulated firm).
249	//   - A finding needs n jurors from n DISTINCT families; too few independent families => fail-closed
250	//     reject (an unadjudicated P0/P1 is demoted to needs-review by the consumer, caution.md C-083).
251	//   - Every response is gate.js-validated before voting; too few valid votes => fail-closed reject.
252	//   - Any single veto rejects; only a unanimous, un-vetoed jury accepts.
253	async function quorum(task, opts = {}) {
254	  const { providers = [], n = 2, vetoRule = defaultVeto, validate = null, deadlineMs = DEFAULT_DEADLINE_MS, log = null } = opts;
