267	  const veto = firstVeto(valid, vetoRule);
268	  if (veto) return { ok: false, verdict: 'reject', reason: 'veto[' + veto.provider + ']:' + veto.reason, votes };
269	  return { ok: true, verdict: 'accept', votes };
270	}
