1	'use strict';
2	// llm/gate.js - THE post-hoc structural gate every LLM response passes before any consumer sees it
3	// (Constitution Rule 11 + Rule 12 gates 1-2, GAPS.md llm-unverified). Deterministic, no network,
4	// fail-closed. A rejected response NEVER reaches a consumer: the gate returns ABSTAIN semantics
5	// (ok:false, value:null), never a repaired or partial answer.
6	//
7	//   validateResponse(response, { schema, allowedSourceIds, sources, minQuoteLen }) ->
8	//     { ok:true,  value, violations:[] }                     (accepted)
9	//     { ok:false, value:null, abstain:true, violations[] }   (refused; the failure mode is silence)
10	//
11	// The three deterministic checks (research grounding: docs/discovery/digest-research-llm-agents.md
12	// Part A, patterns 1, 2 and 6/7 - schema guarantees SHAPE, not truth, so a separate semantic gate
13	// must follow):
14	//   0. PARSE          unparseable JSON = reject. A model reply that is not valid JSON is refused, it
15	//                     is never coerced (caution.md C-137: the parse-fragile prompt-only-JSON lane).
16	//   1. SCHEMA         a tiny built-in JSON-Schema subset validates required fields, types, enums and
17	//                     bounds. No new dependency (Constitution: zero runtime deps); mirrors the pure
18	//                     path-list validator style of payload/contract/index.js.
19	//   2. RETRIEVAL-GATE every cited source_id must be a member of allowedSourceIds (Rule 12 gate 1). An
20	//                     out-of-set citation is a HARD reject - the escape probability of a fabricated
21	//                     citation is zero, not small (13-21% of legal citations hallucinate, arXiv 2606.00898).
22	//   3. QUOTE RE-MATCH every quote must survive a normalised exact-substring match against the source
23	//                     text it cites (Rule 12 gate 2). A paraphrased or fabricated quote drifts and is
24	//                     rejected (models paraphrase inside quotation marks, Stanford HAI).
25	//
26	// This gate checks the citations a response ACTUALLY makes. The stronger policy "a violation MUST
27	// cite an artifact / a NO_BREACH MUST carry a disproof quote" (caution.md C-080/C-092) is the
28	// ADJUDICATOR's contract (breach/adjudicator, Wave 2) and composes ON TOP of this structural gate.
29	
30	const DEFAULT_MIN_QUOTE_LEN = 8;   // caution.md C-089: sub-25-char nav fragments are not evidence; 8 is the H.anchored floor ported from the proven gate, callers (the adjudicator) raise it.
31	const MAX_WALK_DEPTH = 12;         // adversarial deeply-nested response guard (caution.md C-165 red-team inputs); beyond this we stop walking rather than blow the stack.
32	const SOURCE_ID_KEY = /^source_ids?$/i;
33	const QUOTE_FIELDS = ['quote', 'verbatim_quote'];
34	
35	// ---------------------------------------------------------------------------------------------------
36	// Small pure helpers
37	// ---------------------------------------------------------------------------------------------------
38	
39	// normalise(s): the canonical form for the verbatim-quote substring match. Lowercase, collapse all
40	// whitespace runs to a single space, fold curly quotes to straight (both sides of the compare get the
41	// same folding, so the comparison stays exact, never fuzzy). caution.md C-035: detection surface and
42	// evidence surface must be the SAME normalised corpus.
43	function normalise(s) {
44	  return String(s == null ? '' : s)
45	    .replace(/[‘’]/g, "'")
46	    .replace(/[“”]/g, '"')
47	    .replace(/\s+/g, ' ')
48	    .trim()
49	    .toLowerCase();
50	}
51	
52	// toSet(arr): a Set of trimmed string ids. A non-array yields the EMPTY set, so a caller that forgot
53	// to supply the retrieval set can cite NOTHING (fail-closed): every id is then out-of-set.
54	function toSet(arr) {
55	  const s = new Set();
56	  for (const x of Array.isArray(arr) ? arr : []) s.add(String(x).trim());
57	  return s;
58	}
59	
60	function typeOf(v) {
61	  if (v === null) return 'null';
62	  if (Array.isArray(v)) return 'array';
63	  return typeof v;
64	}
65	
66	function sv(path, message) {
67	  return { code: 'schema', path, message: 'schema ' + path + ': ' + message };
68	}
69	
70	// safeRegex(pattern): compile a schema `pattern`. An invalid pattern cannot validate anything, so we
71	// return a never-match regex - the field is then flagged as not matching, keeping the gate fail-closed.
72	function safeRegex(pattern) {
73	  try {
74	    return new RegExp(pattern);
75	  } catch (_e) {
76	    // FAIL-OPEN: an invalid schema pattern is a config error; the never-match keeps the field flagged
77	    // and the SYSTEM fail-closed (the value is reported as a schema violation, never silently passed).
78	    return /$.^/;
79	  }
80	}
81	
82	// ---------------------------------------------------------------------------------------------------
83	// Step 0: parse
84	// ---------------------------------------------------------------------------------------------------
85	
86	// pickText(response): the text payload to parse. Accepts a raw string, a router response object with a
87	// string `.text`, or null when neither is present (the caller may then treat an object as pre-parsed).
88	function pickText(response) {
89	  if (typeof response === 'string') return response;
90	  if (response && typeof response.text === 'string') return response.text;
91	  return null;
92	}
93	
94	// extractJson(text): the substring from the first JSON opener to the last closer, or null. A model that
95	// wraps JSON in prose or ```fences still yields its object; genuinely non-JSON text yields null.
96	function extractJson(text) {
97	  const s = String(text);
98	  const starts = [s.indexOf('{'), s.indexOf('[')].filter((i) => i !== -1);
99	  if (!starts.length) return null;
100	  const start = Math.min(...starts);
101	  const end = Math.max(s.lastIndexOf('}'), s.lastIndexOf(']'));
102	  if (end <= start) return null;
103	  return s.slice(start, end + 1);
104	}
105	
106	// parseResponse(response): { ok:true, value } or { ok:false, violation }. A failed router response
107	// (ok:false) and an unparseable body both route to a typed reject, so the gate can abstain cleanly.
108	function parseResponse(response) {
109	  if (response == null) return { ok: false, violation: { code: 'empty_response', message: 'no response supplied' } };
110	  if (typeof response === 'object' && response.ok === false) {
111	    return { ok: false, violation: { code: 'provider_unavailable', message: 'router returned ok:false (' + String(response.reason || response.error || 'unknown') + ')' } };
112	  }
113	  const text = pickText(response);
114	  if (text === null) {
115	    if (typeof response === 'object') return { ok: true, value: response };
116	    return { ok: false, violation: { code: 'empty_response', message: 'response carried no text' } };
117	  }
118	  const slice = extractJson(text);
119	  if (slice === null) return { ok: false, violation: { code: 'unparseable_json', message: 'no JSON object or array found in the response text' } };
120	  try {
121	    return { ok: true, value: JSON.parse(slice) };
122	  } catch (_e) {
123	    // FAIL-OPEN: a JSON.parse throw is caught HERE and converted to a typed reject; validateResponse
124	    // then returns abstain (ok:false), so the SYSTEM fails closed - a malformed reply never ships.
125	    return { ok: false, violation: { code: 'unparseable_json', message: 'the response text is not valid JSON' } };
126	  }
127	}
128	
129	// ---------------------------------------------------------------------------------------------------
130	// Step 1: schema (a tiny JSON-Schema subset, zero dependencies)
131	// ---------------------------------------------------------------------------------------------------
132	
133	function oneTypeMatches(value, t) {
134	  if (t === 'integer') return typeof value === 'number' && Number.isInteger(value);
135	  if (t === 'number') return typeof value === 'number' && Number.isFinite(value);
136	  if (t === 'object') return typeOf(value) === 'object';
137	  if (t === 'array') return Array.isArray(value);
138	  if (t === 'null') return value === null;
139	  return typeof value === t;
140	}
141	
142	function typeMatches(value, t) {
143	  const types = Array.isArray(t) ? t : [t];
144	  return types.some((one) => oneTypeMatches(value, one));
145	}
146	
147	function checkStringConstraints(value, schema, path) {
148	  const out = [];
149	  if (Number.isFinite(schema.minLength) && value.length < schema.minLength) out.push(sv(path, 'string shorter than minLength ' + schema.minLength));
150	  if (Number.isFinite(schema.maxLength) && value.length > schema.maxLength) out.push(sv(path, 'string longer than maxLength ' + schema.maxLength));
151	  if (schema.pattern && !safeRegex(schema.pattern).test(value)) out.push(sv(path, 'string does not match pattern ' + JSON.stringify(schema.pattern)));
152	  return out;
153	}
154	
155	function checkNumberConstraints(value, schema, path) {
156	  const out = [];
157	  if (Number.isFinite(schema.minimum) && value < schema.minimum) out.push(sv(path, 'number below minimum ' + schema.minimum));
158	  if (Number.isFinite(schema.maximum) && value > schema.maximum) out.push(sv(path, 'number above maximum ' + schema.maximum));
159	  return out;
160	}
161	
162	function checkScalarConstraints(value, schema, path) {
163	  const out = [];
164	  if (schema.enum && !schema.enum.some((e) => e === value)) out.push(sv(path, 'value ' + JSON.stringify(value) + ' not in enum ' + JSON.stringify(schema.enum)));
165	  if ('const' in schema && schema.const !== value) out.push(sv(path, 'value must equal ' + JSON.stringify(schema.const)));
166	  if (typeof value === 'string') out.push(...checkStringConstraints(value, schema, path));
167	  if (typeof value === 'number') out.push(...checkNumberConstraints(value, schema, path));
168	  return out;
169	}
170	
171	function checkObject(value, schema, path) {
172	  const out = [];
173	  for (const key of schema.required || []) {
174	    if (!(key in value) || value[key] === undefined) out.push(sv(path + '.' + key, 'required property missing'));
175	  }
176	  const props = schema.properties || {};
177	  for (const [key, sub] of Object.entries(props)) {
178	    if (key in value) out.push(...validateSchema(value[key], sub, path + '.' + key));
179	  }
180	  if (schema.additionalProperties === false) {
181	    for (const key of Object.keys(value)) {
182	      if (!(key in props)) out.push(sv(path + '.' + key, 'additional property not permitted'));
183	    }
184	  }
185	  return out;
186	}
187	
188	function checkArray(value, schema, path) {
189	  const out = [];
190	  if (Number.isFinite(schema.minItems) && value.length < schema.minItems) out.push(sv(path, 'array shorter than minItems ' + schema.minItems));
191	  if (Number.isFinite(schema.maxItems) && value.length > schema.maxItems) out.push(sv(path, 'array longer than maxItems ' + schema.maxItems));
192	  if (schema.items) value.forEach((el, i) => out.push(...validateSchema(el, schema.items, path + '[' + i + ']')));
193	  return out;
194	}
195	
196	// validateSchema(value, schema, path): the recursive shape check. A type mismatch short-circuits (deeper
197	// checks on the wrong shape are noise); otherwise scalar bounds, object and array rules all apply.
198	function validateSchema(value, schema, path) {
199	  if (!schema || typeof schema !== 'object') return [];
200	  if (schema.nullable && value === null) return [];
201	  if (schema.type && !typeMatches(value, schema.type)) {
202	    return [sv(path, 'expected ' + JSON.stringify(schema.type) + ', got ' + typeOf(value))];
203	  }
204	  const out = checkScalarConstraints(value, schema, path);
205	  if (typeOf(value) === 'object') out.push(...checkObject(value, schema, path));
206	  else if (Array.isArray(value)) out.push(...checkArray(value, schema, path));
207	  return out;
208	}
209	
210	// ---------------------------------------------------------------------------------------------------
211	// Step 2/3: collect citations, then retrieval-gate and quote-match them
212	// ---------------------------------------------------------------------------------------------------
213	
214	function pushSourceIds(v, path, acc) {
215	  if (typeof v === 'string') { acc.sourceIds.push({ id: v, path }); return; }
216	  if (Array.isArray(v)) {
217	    v.forEach((el, i) => { if (typeof el === 'string') acc.sourceIds.push({ id: el, path: path + '[' + i + ']' }); });
218	  }
219	}
220	
221	function firstQuoteField(node) {
222	  for (const key of QUOTE_FIELDS) {
223	    if (typeof node[key] === 'string') return node[key];
224	  }
225	  return null;
226	}
227	
228	// gatherNodeCitations(node, path, acc): pull the source_id citations and any quote+source_id pair out
229	// of ONE object node. A quote is bound to the source_id declared on the SAME object (Rule 12 gate 2:
230	// a quote must cite the document it came from).
231	function gatherNodeCitations(node, path, acc) {
232	  for (const [k, v] of Object.entries(node)) {
233	    if (SOURCE_ID_KEY.test(k)) pushSourceIds(v, path ? path + '.' + k : k, acc);
234	  }
235	  const quote = firstQuoteField(node);
236	  const sid = typeof node.source_id === 'string' ? node.source_id : null;
237	  if (quote != null && sid != null) acc.quotes.push({ quote, sourceId: sid, path });
238	}
239	
240	// walkCitations(node, path, depth, acc): a single depth-bounded walk of the parsed value, gathering
241	// every cited source_id and every quote/source_id pair for the flat checks that follow. A response
242	// nested deeper than MAX_WALK_DEPTH is NOT silently trusted: the unwalked subtree could hide an
243	// out-of-set citation, so the walk records depthExceeded and validateResponse turns that into a hard
244	// max_depth_exceeded violation (Rule 4: an incomplete inspection must fail closed, never pass as clean;
245	// caution.md C-165 adversarial deep-nesting input).
246	function walkCitations(node, path, depth, acc) {
247	  if (depth > MAX_WALK_DEPTH) { acc.depthExceeded = true; return; }
248	  if (node == null || typeof node !== 'object') return;
249	  if (Array.isArray(node)) {
250	    node.forEach((el, i) => walkCitations(el, path + '[' + i + ']', depth + 1, acc));
251	    return;
252	  }
253	  gatherNodeCitations(node, path, acc);
254	  for (const [k, v] of Object.entries(node)) walkCitations(v, path ? path + '.' + k : k, depth + 1, acc);
255	}
256	
257	function collectCitations(value) {
258	  const acc = { sourceIds: [], quotes: [], depthExceeded: false };
259	  walkCitations(value, '$', 0, acc);
260	  return acc;
261	}
262	
263	// checkSourceIds(sourceIds, allowedSet): Rule 12 gate 1. Every cited id must be in the retrieval set.
264	function checkSourceIds(sourceIds, allowedSet) {
265	  const out = [];
266	  for (const { id, path } of sourceIds) {
267	    const norm = String(id).trim();
268	    if (!allowedSet.has(norm)) {
269	      out.push({ code: 'out_of_set_source_id', path, id: norm, message: 'cited source_id "' + norm + '" is not in the retrieval set (Rule 12 gate 1)' });
270	    }
271	  }
272	  return out;
273	}
274	
275	// checkOneQuote(q, sources, minQuoteLen, allowedSet): Rule 12 gate 2 for one quote/source_id pair. The
276	// order of checks is deliberate: too-short, then in-set, then source-present, then verbatim substring.
277	function checkOneQuote(q, sources, minQuoteLen, allowedSet) {
278	  const sid = String(q.sourceId).trim();
279	  const text = String(q.quote || '');
280	  if (text.trim().length < minQuoteLen) return [{ code: 'quote_too_short', path: q.path, sourceId: sid, message: 'quote is shorter than the ' + minQuoteLen + '-char floor (caution.md C-089)' }];
281	  if (!allowedSet.has(sid)) return [{ code: 'out_of_set_source_id', path: q.path, id: sid, message: 'quote cites source_id "' + sid + '" not in the retrieval set (Rule 12 gate 1)' }];
282	  const src = sources ? sources[sid] : null;
283	  if (src == null) return [{ code: 'quote_source_missing', path: q.path, sourceId: sid, message: 'no source text supplied for "' + sid + '"; the quote cannot be verified, so the claim is refused' }];
284	  if (!normalise(src).includes(normalise(text))) return [{ code: 'quote_drift', path: q.path, sourceId: sid, message: 'quote is not a verbatim substring of source "' + sid + '" (Rule 12 gate 2)' }];
285	  return [];
286	}
287	
288	function checkQuotes(quotes, sources, minQuoteLen, allowedSet) {
289	  const out = [];
290	  for (const q of quotes) out.push(...checkOneQuote(q, sources, minQuoteLen, allowedSet));
291	  return out;
292	}
293	
294	// ---------------------------------------------------------------------------------------------------
295	// The gate
296	// ---------------------------------------------------------------------------------------------------
297	
298	function abstain(violations) {
299	  return { ok: false, value: null, abstain: true, violations: violations.filter(Boolean) };
300	}
301	
302	// validateResponse(response, opts): the one door every LLM response passes through. Runs parse ->
303	// schema -> retrieval-gate -> quote-match and AND-composes them. Any violation abstains.
304	function validateResponse(response, opts = {}) {
305	  const schema = opts.schema || null;
306	  const allowedSet = toSet(opts.allowedSourceIds);
307	  const sources = opts.sources || {};
308	  const minQuoteLen = Number.isFinite(opts.minQuoteLen) ? opts.minQuoteLen : DEFAULT_MIN_QUOTE_LEN;
309	  const parsed = parseResponse(response);
310	  if (!parsed.ok) return abstain([parsed.violation]);
311	  const value = parsed.value;
312	  const violations = [];
313	  if (schema) violations.push(...validateSchema(value, schema, '$'));
314	  const cites = collectCitations(value);
315	  if (cites.depthExceeded) {
316	    violations.push({ code: 'max_depth_exceeded', path: '$', message: 'response nests deeper than the ' + MAX_WALK_DEPTH + '-level citation-walk cap; the unwalked subtree cannot be retrieval-gated, so the response is refused (Rule 4/12 gate 1)' });
317	  }
318	  violations.push(...checkSourceIds(cites.sourceIds, allowedSet));
319	  violations.push(...checkQuotes(cites.quotes, sources, minQuoteLen, allowedSet));
320	  if (violations.length) return abstain(violations);
321	  return { ok: true, value, violations: [] };
322	}
323	
324	// ---------------------------------------------------------------------------------------------------
325	// Calibration CLI (the earn-your-zero contract in eval/calibration-known-bad/run.js).
326	// `node llm/gate.js --calibrate [--json <path>]` replays every p3-llm-*.json fixture. A FINDING is
327	// emitted ONLY when the gate correctly REFUSES the poisoned response (and, if the fixture pins an
328	// expected code, that code is present). Zero findings on a fixture means the gate FAILED to catch its
329	// planted disease, and the calibration runner fails CI (Constitution Rule 4: a zero you did not earn).
330	// ---------------------------------------------------------------------------------------------------
331	
332	function judgeFixture(abs, fx) {
333	  const result = validateResponse(fx.response, {
334	    schema: fx.schema, allowedSourceIds: fx.allowedSourceIds, sources: fx.sources, minQuoteLen: fx.minQuoteLen,
335	  });
336	  const wantCode = (fx.poison && fx.poison.expect_violation) || null;
337	  const codeHit = !wantCode || (result.violations || []).some((v) => v.code === wantCode);
338	  if (result.ok === false && codeHit) {
339	    return { file: abs, line: 1, rule: 'llm-gate-reject', message: 'correctly refused poisoned response: ' + ((result.violations || []).map((v) => v.code).join(',') || 'reject') };
340	  }
341	  // The gate WRONGLY ACCEPTED (or refused for the wrong reason): emit NO finding for this fixture, so
342	  // eval/calibration-known-bad/run.js sees the fixture uncaught and FAILS (earn-your-zero).
343	  return null;
344	}
345	
346	function runCalibration(fixturesDir) {
347	  const fs = require('fs');
348	  const path = require('path');
349	  const dir = fixturesDir || path.join(__dirname, '..', 'eval', 'calibration-known-bad', 'fixtures');
350	  const findings = [];
351	  const files = fs.readdirSync(dir).filter((f) => /^p3-llm-.*\.json$/.test(f)).sort();
352	  for (const f of files) {
353	    if (!/^[a-z0-9][a-z0-9.-]{0,251}$/i.test(f)) throw new Error('unsafe path component: ' + JSON.stringify(f));
354	    const abs = path.join(dir, f);
355	    const finding = judgeFixture(abs, JSON.parse(fs.readFileSync(abs, 'utf8')));
356	    if (finding) findings.push(finding);
357	  }
358	  return findings;
359	}
360	
361	function calibrateMain(argv) {
362	  const fs = require('fs');
363	  const args = argv.slice(2);
364	  const jsonIdx = args.indexOf('--json');
365	  const jsonPath = jsonIdx !== -1 ? args[jsonIdx + 1] : null;
366	  const findings = runCalibration();
367	  if (jsonPath) fs.writeFileSync(jsonPath, JSON.stringify(findings, null, 2));
368	  process.stdout.write(JSON.stringify({ checker: 'llm-gate', findings }) + '\n');
369	  return 0;
370	}
371	
372	if (require.main === module) {
373	  if (process.argv.includes('--calibrate')) {
374	    process.exit(calibrateMain(process.argv));
375	  } else {
376	    process.stderr.write('llm/gate.js is a library (validateResponse). Only --calibrate is runnable from the CLI.\n');
377	    process.exit(2);
378	  }
379	}
380	
381	module.exports = {
382	  validateResponse,
383	  validateSchema,
384	  collectCitations,
385	  checkSourceIds,
386	  checkQuotes,
387	  normalise,
388	  runCalibration,
389	  DEFAULT_MIN_QUOTE_LEN,
390	};
391

