44	// '://', '/', '.', 'http', a path or a scheme - those are not hosts, so those calls are not the class.
45	const HOSTNAME_LITERAL_RX = /^[a-z0-9]([a-z0-9-]*\.)+[a-z]{2,}$/i;
46	
