1	#!/usr/bin/env node
2	'use strict';
3	/**
4	 * DEADLINE-AUDIT gate: every external step has a hard deadline (Constitution Rule 9, GAPS.md
5	 * `deadline-hang`, caution.md C-040/C-138).
6	 *
7	 * The old estate let a stuck Chromium hold a mint hostage for 752 seconds because the browser's own
8	 * goto timeout did not bound launch + networkidle, and exhausted free LLM tiers burned 30s x 3 retries
9	 * waiting for answers that were never coming. The lesson: a slow external dependency must DEGRADE the
10	 * mint, never HANG it - so every external call site is wrapped in a hard Promise.race deadline
11	 * (raceWithDeadline / withDeadline / runWithDeadline) or carries its own reachable deadline argument.
12	 *
13	 * This gate FAILS CI (AST scan, evidence/ llm/ breach/) on:
14	 *   1. undeadlined-await: an `await` on a KNOWN injected external caller (fetchFn / launchBrowser /
15	 *      llmCall / a `.call(...)` provider invocation) that is NOT lexically inside a deadline-wrapper's
16	 *      arguments and carries no deadline/timeout/signal argument of its own.
17	 *   2. undeadlined-spawn: a child-process spawn (spawnSync / execSync / execFileSync / spawn) shelling
18	 *      out to an http(s) URL or a curl/wget command, outside any deadline wrapper.
19	 *
20	 * FALSE POSITIVES NEAR ZERO by construction: only the small closed set of KNOWN external-call
21	 * identifiers is ever flagged. A `page.goto(...)`, a `browser.newPage()`, a regex `.exec(...)`, a
22	 * plain local await - none are external-call identifiers, so none are touched. A call inside a
23	 * withDeadline(() => fetchFn(url), ms) wrapper is exempt; so is fetchFn(url, { deadlineMs }).
24	 *
25	 * Engine: acorn is MANDATORY. Without it (or under DEADLINE_AUDIT_ENGINE=refuse) the gate REFUSES
26	 * (exit 2) rather than approximate - an under-report is an unearned zero (Constitution Rule 4). A parse
27	 * failure on any scanned file is likewise fail-closed (exit 2), never silently counted as zero.
28	 *
29	 * Modes (tools/lib/gate-cli.js dialect):
30	 *   node tools/domain-gates/deadline-audit.js               scan evidence/ llm/ breach/, exit 1 on any hit
31	 *   node tools/domain-gates/deadline-audit.js --json <path> also write findings JSON for the sweep normaliser
32	 *   node tools/domain-gates/deadline-audit.js --calibrate   scan eval/calibration-known-bad/fixtures/ and
33	 *                                                           REQUIRE the seeded undeadlined await is caught
34	 */
35	const { runGateCli } = require('../lib/gate-cli');
36	const { scanTreeWith, isMetaKey, lineOf, memberPropName: propName } = require('./acorn-scan');
37	
38	const SCAN_DIRS = ['evidence', 'llm', 'breach'];
39	const SKIP_DIRS = /^(node_modules|\.git|out|packs|dist|fixtures)$/;
40	
41	// The closed set of KNOWN injected external-call identifiers. This is the whole FP surface: nothing
42	// outside it is ever flagged (a page/browser method, a regex .exec, a plain local await are all spared).
43	const KNOWN_IDENTS = new Set(['fetchFn', 'launchBrowser', 'llmCall']);
44	const KNOWN_MEMBER_PROPS = new Set(['fetchFn', 'launchBrowser', 'llmCall', 'call']);
45	const WRAPPERS = new Set(['withDeadline', 'raceWithDeadline', 'runWithDeadline']);
46	const SPAWN_NAMES = new Set(['spawnSync', 'execSync', 'execFileSync', 'spawn']);
47	const DEADLINE_RX = /(deadline|timeout|signal|abort)/i;
48	const HTTP_RX = /^https?:\/\//i;
49	const SHELL_HTTP_RX = /\b(curl|wget)\b/i;
50	
51	let acorn = null;
52	try { acorn = require('acorn'); }
53	catch (e) { acorn = null; /* FAIL-OPEN: acorn=null is the typed failure captured HERE; scanContent() REFUSES (exit 2), so the SYSTEM fails closed. acorn ships transitively via eslint. */ }
54	const FORCE_REFUSE = process.env.DEADLINE_AUDIT_ENGINE === 'refuse';
55	const useAcorn = Boolean(acorn) && !FORCE_REFUSE;
56	
57	// ── small AST predicates (isMetaKey / lineOf / propName come from the shared acorn-scan lib) ──────────
58	function isKnownExternalCallee(callee) {
59	  if (!callee) return false;
60	  if (callee.type === 'Identifier') return KNOWN_IDENTS.has(callee.name);
61	  if (callee.type === 'MemberExpression') return KNOWN_MEMBER_PROPS.has(propName(callee));
62	  return false;
63	}
64	
65	// isWrapperCallee(callee) -> the call is a hard-deadline wrapper (withDeadline family or Promise.race);
66	// anything lexically inside its arguments is deadline-bounded and therefore exempt.
67	function isWrapperCallee(callee) {
68	  if (!callee) return false;
69	  if (callee.type === 'Identifier') return WRAPPERS.has(callee.name);
70	  if (callee.type !== 'MemberExpression') return false;
71	  if (WRAPPERS.has(propName(callee))) return true;
72	  return callee.object && callee.object.type === 'Identifier' && callee.object.name === 'Promise' && propName(callee) === 'race';
73	}
74	
75	function spawnName(callee) {
76	  if (!callee) return '';
77	  if (callee.type === 'Identifier') return callee.name;
78	  if (callee.type === 'MemberExpression') return propName(callee);
79	  return '';
80	}
81	
82	// subtreeSome(node, pred) -> true when any typed AST node in this subtree (arrays included) satisfies
83	// pred. The ONE recursive subtree scan both detectors below share (no per-detector clone).
84	function subtreeSome(node, pred) {
85	  if (Array.isArray(node)) return node.some((x) => subtreeSome(x, pred));
86	  if (!node || typeof node !== 'object') return false;
87	  if (typeof node.type === 'string' && pred(node)) return true;
88	  for (const key of Object.keys(node)) {
89	    if (!isMetaKey(key) && subtreeSome(node[key], pred)) return true;
90	  }
91	  return false;
92	}
93	
94	function keyName(key) {
95	  if (!key) return '';
96	  if (key.type === 'Identifier') return key.name;
97	  if (key.type === 'Literal') return String(key.value);
98	  return '';
99	}
100	
101	// isDeadlineNode(node) -> a budget/deadline/timeout/signal identifier or property key (so
102	// fetchFn(url, { deadlineMs }) and llmCall(req, signal) read as self-bounded, exempt from the gate).
103	function isDeadlineNode(node) {
104	  if (node.type === 'Identifier') return DEADLINE_RX.test(node.name);
105	  if (node.type === 'Property') { const k = keyName(node.key); return Boolean(k) && DEADLINE_RX.test(k); }
106	  return false;
107	}
108	
109	// isHttpNode(node) -> a string literal that is an http(s) URL or a curl/wget command (a spawn shelling
110	// out to the network).
111	function isHttpNode(node) {
112	  return node.type === 'Literal' && typeof node.value === 'string' && (HTTP_RX.test(node.value) || SHELL_HTTP_RX.test(node.value));
113	}
114	
115	function hasOwnDeadlineArg(call) { return subtreeSome(call.arguments, isDeadlineNode); }
116	
117	function isSpawnHttp(call) {
118	  return SPAWN_NAMES.has(spawnName(call.callee)) && subtreeSome(call.arguments, isHttpNode);
119	}
120	
121	// rootAwaitedCall(argNode) -> the base CallExpression an `await` ultimately awaits, unwrapping trailing
122	// promise-combinator chains (X.then()/.catch()/.finally()), or null when the awaited value is not a call.
123	function rootAwaitedCall(node) {
124	  let cur = node;
125	  while (cur && cur.type === 'CallExpression' && cur.callee && cur.callee.type === 'MemberExpression'
126	      && (propName(cur.callee) === 'then' || propName(cur.callee) === 'catch' || propName(cur.callee) === 'finally')) {
127	    cur = cur.callee.object;
128	  }
129	  return cur && cur.type === 'CallExpression' ? cur : null;
130	}
131	
132	// ── flaggers ────────────────────────────────────────────────────────────────────────────────────────
133	function flagAwait(node, wrapped, relPath, violations) {
134	  if (wrapped) return; // the await is lexically inside a deadline wrapper's arguments -> exempt
135	  const call = rootAwaitedCall(node.argument);
136	  if (!call || !isKnownExternalCallee(call.callee)) return;
137	  if (hasOwnDeadlineArg(call)) return; // self-bounded: carries its own deadline/timeout/signal arg
138	  violations.push({ file: relPath, line: lineOf(node), kind: 'undeadlined-await',
139	    message: 'awaited external call is not inside a raceWithDeadline/withDeadline wrapper and carries no deadline argument (Rule 9); a slow dependency would HANG the mint' });
140	}
141	
142	function flagSpawn(node, wrapped, relPath, violations) {
143	  if (wrapped || !isSpawnHttp(node)) return;
144	  violations.push({ file: relPath, line: lineOf(node), kind: 'undeadlined-spawn',
145	    message: 'child-process spawn shells out to http/curl outside any deadline wrapper (Rule 9); an unbounded external step can hang the mint' });
146	}
147	
148	// ── walk: carry a `wrapped` flag that is set true only inside a deadline wrapper's argument subtree ────
149	function childWrapped(node, key, wrapped) {
150	  if (wrapped) return true;
151	  return node.type === 'CallExpression' && key === 'arguments' && isWrapperCallee(node.callee);
152	}
153	
154	function walk(node, wrapped, relPath, violations) {
155	  if (!node || typeof node !== 'object') return;
156	  if (Array.isArray(node)) { for (const n of node) walk(n, wrapped, relPath, violations); return; }
157	  if (typeof node.type !== 'string') return;
158	  if (node.type === 'AwaitExpression') flagAwait(node, wrapped, relPath, violations);
159	  else if (node.type === 'CallExpression') flagSpawn(node, wrapped, relPath, violations);
160	  for (const key of Object.keys(node)) {
161	    if (isMetaKey(key)) continue;
162	    walk(node[key], childWrapped(node, key, wrapped), relPath, violations);
163	  }
164	}
165	
166	function scanContent(relPath, src) {
167	  if (!useAcorn) throw new Error(relPath + ': acorn unavailable and DEADLINE_AUDIT refuses to approximate deadline detection (an under-report is an unearned zero, Constitution Rule 4)');
168	  let ast;
169	  try { ast = acorn.parse(src, { ecmaVersion: 'latest', allowHashBang: true, allowReturnOutsideFunction: true, allowAwaitOutsideFunction: true, locations: true }); }
170	  catch (e) { throw new Error(relPath + ': acorn cannot parse this file: ' + e.message + ' (a parse failure is NOT zero violations)'); }
171	  const violations = [];
172	  walk(ast, false, relPath, violations);
173	  return { violations };
174	}
175	
176	function scanTree(dirs) {
177	  return scanTreeWith(dirs, SKIP_DIRS, scanContent);
178	}
179	
180	function selfTest() {
181	  if (!useAcorn) {
182	    let refused = false;
183	    try { scanContent('selftest.js', 'async function f(x){ return await x.llmCall(1); }'); }
184	    catch (e) { refused = true; /* FAIL-OPEN: the throw is the measured refusal signal (acorn mandatory), captured on purpose. */ }
185	    return { pass: refused, detail: refused ? 'no-acorn engine correctly REFUSES (exit 2), never a zero' : 'no-acorn engine did not refuse - it must never approximate' };
186	  }
187	  const bad = [
188	    'async function f(fetchFn, u){ return await fetchFn(u); }',                      // undeadlined awaited fetch
189	    'async function g(o, r){ return await o.llmCall(r); }',                          // undeadlined awaited injected llm call
190	    'async function h(fetchFn, u){ return await fetchFn(u).catch(() => null); }',    // .catch chain still undeadlined
191	    'const cp = require("child_process"); cp.spawnSync("curl", ["https://x.example"]);', // spawn shelling to http
192	  ];
193	  const good = [
194	    'async function a(fetchFn, u){ return await withDeadline(() => fetchFn(u), 5000); }',  // wrapped
195	    'async function b(fetchFn, u){ return await fetchFn(u, { deadlineMs: 9000 }); }',       // self-bounded arg
196	    'async function c(page, u){ await page.goto(u); }',                                     // page.goto is not a known external ident
197	    'const m = /x/.exec(String(s));',                                                       // regex .exec is not a spawn
198	    'async function d(raceWithDeadline, work){ return await raceWithDeadline(work, 9000); }', // awaited wrapper itself
199	  ];
200	  const badOk = bad.every((s) => scanContent('t.js', s).violations.length === 1);
201	  const goodOk = good.every((s) => scanContent('t.js', s).violations.length === 0);
202	  return {
203	    pass: badOk && goodOk,
204	    detail: (badOk && goodOk)
205	      ? 'catches undeadlined awaits of fetchFn/llmCall (incl .catch chains) and spawn-to-http; clears wrapped calls, self-bounded args, page.goto, regex .exec and awaited wrappers (engine: acorn)'
206	      : 'FAILED: badOk=' + badOk + ' goodOk=' + goodOk,
207	  };
208	}
209	
210	function toFindings(violations) {
211	  return violations.map((v) => ({
212	    tool: 'deadline-audit', ruleId: 'deadline-audit/' + v.kind, file: v.file,
213	    startLine: v.line, endLine: v.line, level: 'error', message: v.message, snippet: v.kind,
214	  }));
215	}
216	
217	function main() {
218	  try {
219	    runGateCli({
220	      name: 'deadline-audit',
221	      selfTest,
222	      scan: scanTree,
223	      toFindings,
224	      scanDirs: SCAN_DIRS,
225	      summary: (r) => r.scanned + ' files, ' + r.violations.length + ' undeadlined external-call site(s) (engine: ' + (useAcorn ? 'acorn' : 'refuse') + ')',
