1	'use strict';
2	/**
3	 * crawl.js - the P3 evidence crawler entry. Produces the EvidenceBundle.corpus the pure facts layer
4	 * consumes ({pages:[{url,title,text,jsonLd,ogSiteName?}], footerText?}) plus a coverage report.
5	 *
6	 * ALL network + clock effects are INJECTED so node:test runs offline and deterministically:
7	 *   crawl(domain, { fetchFn, deadlineMs, maxPages, width, now, timers, fetchXml, log, sector, rules,
8	 *                   followDocuments }) -> { domain, corpus, unreachable, reason, documents, coverage,
9	 *                   telemetry, notes }
10	 *   fetchFn(url) -> Promise<{ ok, status, body, finalUrl?, contentType? }>   (the ONLY way bytes arrive)
11	 *
12	 * Doctrine preserved:
13	 *   - E-236 parallelism: parallel page fetches (width from opts, NO floor), parallel sitemap discovery,
14	 *     TIER-1-first ordering applied BEFORE the page cap (discover.js).
15	 *   - Rule 9: every fetch is wrapped in a hard Promise.race deadline (pool.withDeadline); the pool's
16	 *     wall-clock deadline is a CAP, never a floor (Rule 8).
17	 *   - C-024/C-025: the corpus char cap is generous and env-guarded - a sub-floor env value THROWS.
18	 *   - C-031/C-032/C-038: a login/challenge/error/SPA-shell response never enters the corpus or flips
19	 *     reachability; an unreadable site yields an unreachable bundle (nothing asserted).
20	 *   - C-033/C-034: the homepage footer is a mandatory surface, and footer-linked documents are followed
21	 *     (evidence/documents), with unparsed PDFs demoting dependent obligations in the coverage report.
22	 */
23	
24	const crypto = require('crypto');
25	const safeFetch = require('../../tools/lib/safe-fetch.js');
26	const { withDeadline, runPool } = require('./pool.js');
27	const extract = require('./extract.js');
28	const discover = require('./discover.js');
29	const coverage = require('./coverage-contract.js');
30	const { collectDocuments, isPdfLike } = require('../documents/documents.js');
31	
32	const CORPUS_CAP_FLOOR = 50000;      // below this, footer disclosures fall past the cut (russell-cooke, C-024)
33	const CORPUS_CAP_DEFAULT = 500000;
34	const PAGES_FLOOR = 5;
35	const PAGES_DEFAULT = 120;
36	const WIDTH_DEFAULT = 8;
37	const DEADLINE_DEFAULT = 45000;
38	
39	// resolveCap(envName, def, floor) -> the effective cap. An env value below the safety floor THROWS
40	// (caution.md C-025: a budget must never be silently zeroed to nothing via env).
41	function resolveCap(envName, def, floor) {
42	  const raw = process.env[envName];
43	  if (raw === undefined || raw === '') return def;
44	  const n = Number(raw);
45	  if (!Number.isFinite(n) || n < floor) {
46	    throw new Error(envName + '=' + JSON.stringify(raw) + ' is below the safety floor of ' + floor + '; a corpus budget is a cap, never a silent zeroing (caution.md C-025)');
47	  }
48	  return n;
49	}
50	
51	// normaliseDomain(domain) -> the canonical host for a raw operator-supplied domain, produced through the
52	// ONE host door (safe-fetch.inputHost): scheme/path/port/www are parsed off via `new URL`, never string-
53	// stripped here (the second-door class, Rule 1). Returns '' when no host can be parsed.
54	function normaliseDomain(domain) {
55	  return safeFetch.inputHost(domain);
56	}
57	
58	// fetchPage(fetchFn, url, perPageMs, timers) -> the fetch result, or null on failure/timeout (Rule 9:
59	// a slow page degrades to null and the crawl continues; it never hangs).
60	async function fetchPage(fetchFn, url, perPageMs, timers) {
61	  try { return await withDeadline(() => fetchFn(url), perPageMs, timers); }
62	  catch (e) { return null; /* FAIL-OPEN: a per-page deadline/exception yields a null slot handled by the caller's telemetry, never a hang or a swallowed hard error. */ }
63	}
64	
65	// makeFetchXml(fetchFn, perPageMs, timers) -> the injected XML/robots fetcher discover.js needs: returns
66	// the body text on a 200, '' otherwise (never throws), each read behind the same hard deadline.
67	function makeFetchXml(fetchFn, perPageMs, timers) {
68	  return (url) => fetchPage(fetchFn, url, perPageMs, timers).then((r) => (r && r.ok && r.body) ? String(r.body) : '');
69	}
70	
71	// contentPageFrom(url, res, cap) -> a corpus page ({url,title,text,jsonLd,ogSiteName?}) when res is real,
72	// readable CONTENT (not a login/challenge/error/shell, C-031/C-038); else null with the reason class. A
73	// document asset (PDF/doc, by extension or content-type) is NOT an HTML corpus page: its binary bytes
74	// would strip into pseudo-"content" and falsely cover a page-class, defeating the C-033 no-parser
75	// interlock. It is deferred to the documents lane and marked 'document' here (never asserted from).
76	function contentPageFrom(url, res, cap) {
77	  if (!res || !res.body) return { page: null, klass: res && res.status ? 'error' : 'unreachable' };
78	  if (isPdfLike(url, res.contentType)) return { page: null, klass: 'document' };
79	  const klass = extract.pageContentClass(res.status, res.body);
80	  if (klass !== 'content') return { page: null, klass };
81	  const page = extract.buildPage(res.finalUrl || url, res.body);
82	  let truncated = false;
83	  if (page.text.length > cap) { truncated = true; page.text = page.text.slice(0, cap); }
84	  return { page, klass: 'content', truncated, bodyHash: crypto.createHash('sha1').update(String(res.body)).digest('hex') };
85	}
86	
87	// accumulateCorpus(fetchList, results, home, homeUrl, cap) -> { pages, truncated, telemetry }. Content
88	// pages are deduped by body hash (soft-404s collapse); every non-content class is counted, never asserted.
89	function accumulateCorpus(fetchList, results, cap) {
90	  const pages = [];
91	  const seenBody = new Set();
92	  const telemetry = { pages_tried: fetchList.length, content: 0, login: 0, challenge: 0, error: 0, empty: 0, unreachable: 0 };
93	  let truncated = false;
94	  for (let i = 0; i < fetchList.length; i++) {
95	    const { page, klass, truncated: t, bodyHash } = contentPageFrom(fetchList[i], results[i], cap);
96	    telemetry[klass] = (telemetry[klass] || 0) + 1;
97	    if (!page) continue;
98	    if (seenBody.has(bodyHash)) continue;
99	    seenBody.add(bodyHash);
100	    truncated = truncated || Boolean(t);
101	    pages.push(page);
102	  }
103	  return { pages, truncated, telemetry };
104	}
105	
106	// footerLinks(homeHtml, base, accepted) -> same-site hrefs found inside the homepage <footer> (where the
107	// policy/PDF links live, C-034); empty when there is no footer region.
108	function footerLinks(homeHtml, base, accepted) {
109	  const m = /<footer\b[^>]*>([\s\S]*?)<\/footer\s*>/i.exec(String(homeHtml || ''));
110	  if (!m) return [];
111	  return discover.discoverLinks(m[1], base, accepted);
112	}
113	
114	// blockReason(homeRes, homeKlass, pageCount) -> an honest reason string when the crawl read no content.
115	function blockReason(homeRes, homeKlass, pageCount) {
116	  if (pageCount > 0) return null;
117	  if (homeKlass === 'challenge') return 'anti_bot_challenge';
118	  if (homeKlass === 'login') return 'login_wall';
119	  if (homeRes && homeRes.status >= 400) return 'http_' + homeRes.status;
120	  if (homeKlass === 'empty') return 'js_rendered_empty_shell';
121	  return 'no_readable_pages';
122	}
123	
124	// buildCoverage(pages, opts, truncated, unparsedClasses) -> the coverage report: the site-level render
125	// class always, plus the per-rule covered|screened contract when catalogue rules were supplied.
126	function buildCoverage(pages, opts, truncated, unparsedClasses) {
127	  const site = coverage.computeCoverage(pages, opts.sector);
128	  const out = { site };
129	  if (Array.isArray(opts.rules)) out.perRule = coverage.coverageFor(opts.rules, pages, { truncated, unparsedClasses });
130	  return out;
131	}
132	
133	// makeRecorder(opts) -> { notes, record }. record(kind,msg) appends a typed note AND forwards to the
134	// injected log, so a degraded lane is always recorded and never silent (Rule 4).
135	function makeRecorder(opts) {
136	  const notes = [];
137	  const log = typeof opts.log === 'function' ? opts.log : () => {};
138	  const record = (kind, msg) => { notes.push({ kind, msg }); log(kind, msg); };
139	  return { notes, record };
140	}
141	
142	// resolveBudgets(opts) -> the effective crawl budgets, each an upper bound (Rule 8): the corpus char cap,
143	// the page cap, the pool width, the wall-clock deadline and the per-page deadline. Env caps below their
144	// safety floor THROW via resolveCap (C-025); nothing here floors a budget.
145	function resolveBudgets(opts) {
146	  const cap = typeof opts.corpusMaxChars === 'number' ? opts.corpusMaxChars : resolveCap('CORPUS_MAX_CHARS', CORPUS_CAP_DEFAULT, CORPUS_CAP_FLOOR);
147	  const maxPages = typeof opts.maxPages === 'number' ? opts.maxPages : resolveCap('MAX_CRAWL_PAGES', PAGES_DEFAULT, PAGES_FLOOR);
148	  const width = typeof opts.width === 'number' && opts.width > 0 ? opts.width : WIDTH_DEFAULT;
149	  const deadlineMs = typeof opts.deadlineMs === 'number' ? opts.deadlineMs : DEADLINE_DEFAULT;
150	  const perPageMs = Math.min(deadlineMs, opts.perPageMs || 20000);
151	  return { cap, maxPages, width, deadlineMs, perPageMs };
152	}
153	
154	// fetchHomepage(ctx) -> { home, homeHtml, homeKlass }. The homepage is the one mandatory surface (footer
155	// disclosures live here, C-034); a non-content homepage (login/challenge/error/SPA shell) is recorded and
156	// never asserted from (C-031/C-038). ctx carries the shared crawl context (opts, base, perPageMs, record).
157	async function fetchHomepage(ctx) {
158	  const { opts, base, perPageMs, record } = ctx;
159	  const home = await fetchPage(opts.fetchFn, base + '/', perPageMs, opts.timers);
160	  const homeHtml = home && home.body ? String(home.body) : '';
161	  const homeKlass = extract.pageContentClass(home ? home.status : 0, homeHtml);
162	  if (homeKlass !== 'content') record('homepage-not-content', base + '/ classified as "' + homeKlass + '"; no content asserted from it (C-031/C-038)');
163	  return { home, homeHtml, homeKlass };
164	}
165	
166	// discoverFetchList(ctx, homeHtml, fetchXml, maxPages) -> the deduped, same-site, Tier-1-FIRST-then-capped
167	// fetch list (C-026). Links (homepage) and sitemap are discovered in PARALLEL (E-236); orderCandidates
168	// ranks by tier BEFORE the cap slice, so a Tier-1 legal page survives a cap smaller than the candidate
169	// count even when it was discovered last.
170	async function discoverFetchList(ctx, homeHtml, fetchXml, maxPages) {
171	  const { dom, base, accepted } = ctx;
172	  const [links, sitemap] = await Promise.all([
173	    Promise.resolve(homeHtml ? discover.discoverLinks(homeHtml, base, accepted) : []),
174	    discover.discoverSitemap(dom, accepted, fetchXml).catch(() => []),
175	  ]);
176	  return discover.orderCandidates(base + '/', [...links, ...sitemap], accepted, maxPages);
177	}
178	
179	// followFooterDocuments(ctx, homeHtml, pages) -> the documents-lane result. Skipped (empty) when
180	// document-following is disabled or nothing readable was crawled; otherwise footer-linked policy documents
181	// are followed and read honestly (C-033, evidence/documents).
182	async function followFooterDocuments(ctx, homeHtml, pages) {
183	  const { opts, base, accepted, perPageMs, record } = ctx;
184	  const empty = { documents: [], unparsed: [], unparsedClasses: new Set(), notes: [] };
185	  if (opts.followDocuments === false || !pages.length) return empty;
186	  return collectDocuments(footerLinks(homeHtml, base, accepted),
187	    { fetchFn: opts.fetchFn, deadlineMs: perPageMs, timers: opts.timers, log: record });
188	}
189	
190	// crawl(domain, opts) -> the evidence bundle. Thin orchestrator: resolve budgets, fetch the homepage,
191	// discover links + sitemap in parallel, order Tier-1-first then cap, fetch the corpus in parallel, follow
192	// footer documents, and assemble the corpus + coverage report.
193	async function crawl(domain, opts = {}) {
194	  const dom = normaliseDomain(domain);
195	  if (!dom || !dom.includes('.')) throw new Error('crawl: a fetchable domain (with a public suffix) is required, got ' + JSON.stringify(domain));
196	  if (typeof opts.fetchFn !== 'function') throw new Error('crawl: opts.fetchFn is required (all network is dependency-injected)');
197	  const { notes, record } = makeRecorder(opts);
198	  const { cap, maxPages, width, deadlineMs, perPageMs } = resolveBudgets(opts);
199	  const base = 'https://' + dom;
200	  const homeUrl = base + '/';
201	  const accepted = safeFetch.acceptedSiteSet(dom);
202	  const fetchXml = typeof opts.fetchXml === 'function' ? opts.fetchXml : makeFetchXml(opts.fetchFn, perPageMs, opts.timers);
203	  const ctx = { opts, dom, base, accepted, perPageMs, record };
204	
205	  const { home, homeHtml, homeKlass } = await fetchHomepage(ctx);
206	  const fetchList = await discoverFetchList(ctx, homeHtml, fetchXml, maxPages);
207	
208	  const results = await runPool(fetchList, width, deadlineMs,
209	    (u) => (u === homeUrl ? Promise.resolve(home) : fetchPage(opts.fetchFn, u, perPageMs, opts.timers)), opts.now);
210	  const { pages, truncated, telemetry } = accumulateCorpus(fetchList, results, cap);
211	  if (truncated) record('corpus-truncated', 'a page exceeded the ' + cap + '-char corpus cap; absence claims on it demote to needs-review (C-024)');
212	
213	  const footerText = extract.extractFooterText(homeHtml);
214	  const docResult = await followFooterDocuments(ctx, homeHtml, pages);
215	
216	  const unreachable = pages.length === 0;
217	  const corpus = { pages, footerText: footerText || undefined };
218	  return {
219	    domain: dom,
220	    corpus,
221	    unreachable,
222	    reason: blockReason(home, homeKlass, pages.length),
223	    documents: { records: docResult.documents, unparsed: docResult.unparsed },
224	    coverage: buildCoverage(pages, opts, truncated, docResult.unparsedClasses),
225	    telemetry: { ...telemetry, pages_captured: pages.length, truncated, via: unreachable ? 'none' : 'direct' },
226	    notes,
227	  };
228	}
229	
230	module.exports = {
231	  crawl, resolveCap, normaliseDomain, accumulateCorpus, contentPageFrom, footerLinks, blockReason,
232	  resolveBudgets, makeRecorder, fetchHomepage, discoverFetchList, followFooterDocuments,
233	};
