1	'use strict';
2	/**
3	 * extract.js - the crawler's HTML -> evidence extractor. THE ONE producer of stripped visible text for
4	 * the corpus (caution.md C-012: sector/rule matching never runs on <script>/<style>/markup noise; the
5	 * evidence quote is cut from exactly this text, C-035). Pure and synchronous over an HTML string; no
6	 * network, no clock, no env. Every corpus page and the footer surface (C-034) come out of here.
7	 *
8	 * pageContentClass() is the C-031/C-032/C-038 guard: a login/challenge/error/SPA-shell response is
9	 * classified by its CONTENT, not its byte count, so a login or bot-wall page can never flip a site to
10	 * "reachable" or become an absence-finding surface.
11	 */
12	
13	const NAMED_ENTITIES = {
14	  amp: '&', lt: '<', gt: '>', quot: '"', apos: "'", nbsp: ' ', '#39': "'",
15	  ndash: '-', mdash: '-', hellip: '...', copy: '(c)', reg: '(R)', trade: '(TM)',
16	  pound: '£', euro: '€', middot: '·', bull: '•',
17	};
18	
19	function decodeEntities(s) {
20	  return String(s).replace(/&(#x?[0-9a-fA-F]+|[a-zA-Z]+);/g, (m, g) => {
21	    const key = g.toLowerCase();
22	    if (Object.prototype.hasOwnProperty.call(NAMED_ENTITIES, key)) return NAMED_ENTITIES[key];
23	    if (g[0] === '#') {
24	      const code = (g[1] === 'x' || g[1] === 'X') ? parseInt(g.slice(2), 16) : parseInt(g.slice(1), 10);
25	      if (Number.isFinite(code) && code >= 9 && code <= 0x10ffff) {
26	        try { return String.fromCodePoint(code); } catch (e) { return ' '; /* FAIL-OPEN: an invalid code point in hostile source HTML degrades to a space, the honest substitute; nothing is hidden. */ }
27	      }
28	    }
29	    return m;
30	  });
31	}
32	
33	// stripHtml(html) -> visible text only. Raw-text and non-content elements are dropped whole (tolerant of
34	// "</script >" whitespace, caution.md html-text D-01), block closers become newlines so footer lines
35	// survive, remaining tags become spaces, entities are decoded, whitespace is collapsed.
36	function stripHtml(html) {
37	  let s = String(html);
38	  s = s.replace(/<!--[\s\S]*?-->/g, ' ');
39	  s = s.replace(/<(script|style|noscript|template|svg|iframe|head)\b[\s\S]*?<\/\1\s*>/gi, ' ');
40	  // An UNCLOSED raw-text element (e.g. `<script>window.x="privacy policy absent"</body>` with NO
41	  // </script>) survives the paired removal above; the bare opening tag is then stripped by the generic
42	  // tag rule, leaving its contents in the visible corpus - invisible script text that can become a
43	  // quoted legal finding (Rule 3: evidence must be an observable artifact, caution.md C-035). Per HTML
44	  // parsing a raw-text element consumes to its close OR end-of-input, so drop from the first still-open
45	  // opener to EOI (fail-closed: unterminated raw text is corrupt input, never evidence).
46	  s = s.replace(/<(?:script|style|noscript|template|svg|iframe|head)\b[^>]*>[\s\S]*$/i, ' ');
47	  s = s.replace(/<\/(p|div|li|ul|ol|h[1-6]|tr|td|th|section|article|footer|header|nav|br)\s*>/gi, '\n');
48	  s = s.replace(/<br\s*\/?>/gi, '\n');
49	  s = s.replace(/<[^>]+>/g, ' ');
50	  s = decodeEntities(s);
51	  s = s.replace(/[ \t\r\f\v]+/g, ' ');
52	  s = s.replace(/ ?\n ?/g, '\n');
53	  s = s.replace(/\n{3,}/g, '\n\n');
54	  return s.trim();
55	}
56	
57	function extractTitle(html) {
58	  const m = /<title[^>]*>([\s\S]*?)<\/title\s*>/i.exec(String(html));
59	  return m ? decodeEntities(m[1]).replace(/\s+/g, ' ').trim() : '';
60	}
61	
62	// extractOgMeta(html) -> a map of Open Graph meta values keyed by the property SUFFIX (og.site_name,
63	// og.title, ...). Generic on purpose: the identity-signal property name is never hardcoded here (the
64	// og: prefix plus a captured suffix), so extract.js surfaces the raw corpus value while identity
65	// RESOLUTION (legal_name/display_name from the site name) stays the one door in facts/identity.js.
66	function extractOgMeta(html) {
67	  const out = {};
68	  const re = /<meta\b[^>]*>/gi;
69	  let m;
70	  while ((m = re.exec(String(html))) !== null) {
71	    const p = /property\s*=\s*["']og:([a-z_]+)["']/i.exec(m[0]);
72	    if (!p) continue;
73	    const c = /content\s*=\s*["']([^"']*)["']/i.exec(m[0]);
74	    if (c) out[p[1].toLowerCase()] = decodeEntities(c[1]).trim();
75	  }
76	  return out;
77	}
78	
79	function extractJsonLd(html) {
80	  const out = [];
81	  const re = /<script\b[^>]*type\s*=\s*["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script\s*>/gi;
82	  let m;
83	  while ((m = re.exec(String(html))) !== null) {
84	    const raw = m[1].trim();
85	    if (!raw) continue;
86	    try { out.push(JSON.parse(raw)); }
87	    catch (e) { /* FAIL-OPEN: invalid JSON-LD on the live site is a fact about the site; record nothing, fabricate nothing (no partial-parse guesses). */ }
88	  }
89	  return out;
90	}
91	
92	// extractFooterText(html) -> the statutory-disclosure surface (C-034): the concatenated visible text of
93	// every <footer> region, else '' (the crawl caller may fall back to the page tail). Company number,
94	// registered office and SRA/authorisation strings live here; it is a MANDATORY detection surface.
95	function extractFooterText(html) {
96	  const out = [];
97	  const re = /<footer\b[^>]*>([\s\S]*?)<\/footer\s*>/gi;
98	  let m;
99	  while ((m = re.exec(String(html))) !== null) { const t = stripHtml(m[1]); if (t) out.push(t); }
100	  return out.join('\n').trim();
101	}
102	
103	// extractHrefs(html) -> every raw href value in the document (query strings kept, C-027). Resolution and
104	// same-site filtering are the crawl layer's job (via the tools/lib/safe-fetch.js parsed-host door).
105	function extractHrefs(html) {
106	  const out = [];
107	  const re = /href\s*=\s*["']([^"']+)["']/gi;
108	  let m;
109	  while ((m = re.exec(String(html))) !== null && out.length < 2000) out.push(decodeEntities(m[1]).trim());
110	  return out;
111	}
112	
113	function buildPage(url, html) {
114	  const page = { url, title: extractTitle(html), text: stripHtml(html), jsonLd: extractJsonLd(html) };
115	  const og = extractOgMeta(html);
116	  if (og.site_name !== undefined) page.ogSiteName = og.site_name;
117	  return page;
118	}
119	
120	// ── content classification (C-031 / C-032 / C-038): never let a wall/login/error/shell flip reachable ──
121	const CHALLENGE_MARKERS = [
122	  'just a moment', 'attention required', 'checking your browser', 'verify you are human',
123	  'access denied', 'ddos protection', 'cf-challenge', 'enable javascript and cookies to continue',
124	  'captcha', 'request unsuccessful', 'incapsula', 'perimeterx', 'are you a robot',
125	];
126	const WALL_STATUSES = new Set([401, 403, 429, 503]);
127	const LOGIN_MARKERS = /(sign in|signin|log in|login|log ?into|please (?:sign|log) in|enter your (?:password|username)|forgot your password)/i;
128	
129	function looksChallenge(status, text, title) {
130	  if (WALL_STATUSES.has(status)) return true;
131	  const hay = ((title || '') + '\n' + String(text || '').slice(0, 2500)).toLowerCase();
132	  if (!hay.trim()) return false;
133	  return CHALLENGE_MARKERS.some((mk) => hay.includes(mk)) && String(text || '').length < 4000;
134	}
135	
136	// looksLogin: the WHOLE page is a sign-in gate, not a content page that merely links to a client login.
137	// Guarded by content dominance (thin visible text OR a password field on a short page), never byte count
138	// alone (caution.md C-031).
139	function looksLogin(html, text) {
140	  const t = String(text || '');
141	  if (!LOGIN_MARKERS.test((t + ' ' + extractTitle(html)))) return false;
142	  const hasPasswordField = /<input\b[^>]*type\s*=\s*["']password["']/i.test(String(html));
143	  if (t.length < 600) return true;
144	  return hasPasswordField && t.length < 1500;
145	}
146	
147	// looksSpaShell: HTTP 200, an HTML document, but near-zero visible text (C-032, royalparkpartners.com).
148	function looksSpaShell(html, text) {
149	  if (String(text || '').length >= 200) return false;
150	  const body = String(html || '');
151	  if (!/<html[\s>]/i.test(body) && !/<div/i.test(body)) return false;
152	  return /<div[^>]*id\s*=\s*["'](root|app|__next|___gatsby)["']/i.test(body) || /<script/i.test(body);
153	}
154	
155	// pageContentClass(status, html) -> 'content' | 'challenge' | 'login' | 'error' | 'empty'. Only 'content'
156	// enters the corpus and counts toward reachability; every other class is honestly withheld.
157	function pageContentClass(status, html) {
158	  const st = Number(status) || 0;
159	  if (st >= 500 || st === 404 || st === 410) return 'error';
160	  const text = stripHtml(html);
161	  if (looksChallenge(st, text, extractTitle(html))) return 'challenge';
162	  if (looksLogin(html, text)) return 'login';
163	  if (looksSpaShell(html, text)) return 'empty';
164	  if (text.length < 20) return 'empty';
165	  return 'content';
166	}
167	
168	module.exports = {
169	  decodeEntities, stripHtml, extractTitle, extractOgMeta, extractJsonLd,
170	  extractFooterText, extractHrefs, buildPage, pageContentClass,
171	};
