1	'use strict';
2	/**
3	 * coverage-contract.js - coverage as BLOCKING DATA, not reporting theatre (caution.md C-029).
4	 *
5	 * The reconciliation gate used to check "was the site reachable", not "did we read the page the rule
6	 * needs", so absence rules fired on pages nobody read. Here every catalogue rule declares the page-class
7	 * its website obligations need, and coverageFor() answers per rule: `covered` (that class was crawled) or
8	 * `screened` (it was not; NEVER a breach input). Wave-2 treats `screened` as a HARD BLOCK: no screened
9	 * rule may become a breach.
10	 *
11	 * classify() (caution.md C-044) matches PATH SEGMENTS with anchored tokens, never loose substrings, so
12	 * /feedback does not credit 'fees', /cost-of-living does not credit 'pricing', /returning-customers does
13	 * not credit 'returns'. Pure and deterministic: no network, no clock, no env.
14	 *
15	 * The absence-demotion interlock (caution.md C-024/C-033): a rule whose evidence would be an ABSENCE claim
16	 * is demoted to `screened` (needs-review) when the corpus was truncated, and any page-class that exists
17	 * only inside an unparsed document (evidence/documents 'no-parser') is treated as NOT covered.
18	 */
19	
20	const BASE_REQUIRED = ['homepage', 'privacy'];
21	const SECTOR_REQUIRED = {
22	  'law-firms': ['complaints', 'pricing'], barristers: ['complaints'], finance: ['terms'],
23	  insurance: ['terms'], ecommerce: ['terms', 'returns'], retail: ['terms'],
24	  healthcare: ['privacy'], 'real-estate': ['fees'],
25	};
26	
27	function requiredClasses(sector) {
28	  const extra = SECTOR_REQUIRED[String(sector || '').toLowerCase()] || [];
29	  return [...new Set([...BASE_REQUIRED, ...extra])];
30	}
31	
32	// pagePath(page) -> the normalised path segment (leading slash, query/fragment stripped, lowercased) of a
33	// page object ({url}|{type}) or bare string. Classification anchors on PATH tokens, never the host.
34	function pagePath(page) {
35	  const raw = String((page && (page.url || page.type || page)) || '').toLowerCase();
36	  const path = raw.replace(/^https?:\/\/[^/]+/, '');
37	  return '/' + path.replace(/[?#].*$/, '').replace(/^\/+/, '');
38	}
39	
40	// classify(page) -> the page-class of a fetched URL by PATH SEGMENT with anchored tokens (C-044). Accepts
41	// a page object ({url}|{type}) or a bare string.
42	function classify(page) {
43	  const seg = pagePath(page);
44	  const has = (re) => re.test(seg);
45	  if (has(/\b(privacy|data[-_ ]?protection|gdpr|cookie)\b/)) return 'privacy';
46	  if (has(/\b(complaints?|ombudsman)\b/)) return 'complaints';
47	  if (has(/\bfees?\b/)) return 'fees';
48	  if (has(/\b(pricing|prices?|tariff|cost[-_ ]?(of[-_ ]?service|guide|schedule)?|charges)\b/) && !/\bcost[-_ ]?of[-_ ]?living\b/.test(seg)) return 'pricing';
49	  if (has(/\b(terms|t-and-c|conditions)\b/)) return 'terms';
50	  if (has(/\b(returns?|refunds?)\b/)) return 'returns';
51	  if (/^\/?$/.test(seg) || has(/\b(home|index)\b/)) return 'homepage';
52	  return 'other';
53	}
54	
55	// fetchedClassSet(crawledPages) -> the Set of page-classes present in the crawl. The homepage counts as
56	// present whenever ANY page was read (you always land somewhere), and 'any' is the general-corpus class.
57	function fetchedClassSet(crawledPages) {
58	  const set = new Set((crawledPages || []).map(classify));
59	  if ((crawledPages || []).length) { set.add('homepage'); set.add('any'); }
60	  return set;
61	}
62	
63	// computeCoverage(crawledPages, sector, opts) -> site-level tri-state: 'assessable' (enough required
64	// classes) or 'screened' (too little coverage -> not-assessed, never a breach on unread content).
65	function computeCoverage(crawledPages, sector, opts = {}) {
66	  const required = requiredClasses(sector);
67	  const fetched = fetchedClassSet(crawledPages);
68	  const missing = required.filter((c) => !fetched.has(c));
69	  const ratio = required.length ? (required.length - missing.length) / required.length : 0;
70	  const threshold = typeof opts.threshold === 'number' ? opts.threshold : 0.5;
71	  const reachable = (crawledPages || []).length > 0;
72	  const render_class = (!reachable || ratio < threshold) ? 'screened' : 'assessable';
73	  return { required, fetched_classes: [...fetched].sort(), missing, ratio: Math.round(ratio * 100) / 100, render_class, reachable };
74	}
75	
76	// pageClassForObligation(obligation) -> the crawl page-class an on-page presence/absence duty needs,
77	// derived from anchored tokens in the duty + element text; 'any' when the duty is a general on-page
78	// requirement (assessable on the homepage/footer). register/behavioural duties return null (their
79	// evidence comes from the registers/browser lanes, not the crawl).
80	function pageClassForObligation(obligation) {
81	  const et = obligation && obligation.evidence_type;
82	  if (et !== 'presence' && et !== 'absence') return null;
83	  const text = ((obligation.duty || '') + ' ' + (obligation.elements || []).join(' ')).toLowerCase();
84	  if (/\b(privacy|data protection|gdpr|cookie|personal data)\b/.test(text)) return 'privacy';
85	  if (/\b(complaints?|ombudsman|redress)\b/.test(text)) return 'complaints';
86	  if (/\bfees?\b/.test(text)) return 'fees';
87	  if (/\b(pricing|price|tariff|charges|cost of service)\b/.test(text)) return 'pricing';
88	  if (/\b(terms|conditions)\b/.test(text)) return 'terms';
89	  if (/\b(returns?|refunds?)\b/.test(text)) return 'returns';
90	  return 'any';
91	}
92	
93	// ruleNeeds(rule) -> { needs: [pageClass...], laneOnly: bool, hasAbsence: bool }. laneOnly means the rule
94	// has NO on-page text obligation (its evidence is register/behavioural), so the crawl does not gate it.
95	function ruleNeeds(rule) {
96	  const obligations = (rule && rule.website_obligations) || [];
97	  const needs = new Set();
98	  let hasAbsence = false;
99	  for (const o of obligations) {
100	    const cls = pageClassForObligation(o);
101	    if (cls) needs.add(cls);
102	    if (o && o.evidence_type === 'absence') hasAbsence = true;
103	  }
104	  return { needs: [...needs], laneOnly: needs.size === 0, hasAbsence };
105	}
106	
107	// judgeRule(rule, fetched, ctx) -> the per-rule coverage verdict. `ctx` carries the interlock inputs:
108	// truncated (C-024) and unparsedClasses (C-033).
109	function judgeRule(rule, fetched, ctx) {
110	  const { needs, laneOnly, hasAbsence } = ruleNeeds(rule);
111	  if (laneOnly) return { id: rule.id, state: 'covered', needs: [], missing: [], reason: 'non-crawl-evidence (register/behavioural lane)' };
112	  const missing = needs.filter((c) => c !== 'any' && !fetched.has(c));
113	  const reasons = missing.map((c) => (ctx.unparsedClasses.has(c)
114	    ? 'page-class "' + c + '" lives only in an unparsed document (C-033)'
115	    : 'missing page-class "' + c + '"'));
116	  if (ctx.truncated && hasAbsence) reasons.push('absence claim on a truncated corpus demoted to needs-review (C-024)');
117	  const covered = reasons.length === 0;
118	  return { id: rule.id, state: covered ? 'covered' : 'screened', needs, missing, reason: covered ? 'all needed page-classes crawled' : reasons.join('; ') };
119	}
120	
121	// coverageFor(rules, crawledPages, opts) -> { rules:[{id,state,needs,missing,reason}], summary } where
122	// state is covered|screened per rule. `opts.truncated` and `opts.unparsedClasses` drive the interlock.
123	function coverageFor(rules, crawledPages, opts = {}) {
124	  const fetched = fetchedClassSet(crawledPages);
125	  const ctx = {
126	    truncated: Boolean(opts.truncated),
127	    unparsedClasses: opts.unparsedClasses instanceof Set ? opts.unparsedClasses : new Set(opts.unparsedClasses || []),
128	  };
129	  const out = (rules || []).map((r) => judgeRule(r, fetched, ctx));
130	  const screened = out.filter((r) => r.state === 'screened').length;
131	  return { rules: out, summary: { total: out.length, covered: out.length - screened, screened } };
132	}
133	
134	// isScreened(coverage, ruleId) -> true when wave-2 must NOT emit a breach for this rule (hard block).
135	function isScreened(coverage, ruleId) {
136	  const r = coverage && coverage.rules && coverage.rules.find((x) => x.id === ruleId);
137	  return Boolean(r) && r.state === 'screened';
138	}
139	
140	// applyCoverage(findings, coverage) -> drop breach ('miss') findings when the SITE coverage is screened.
141	function applyCoverage(findings, coverage) {
142	  if (!coverage || coverage.render_class === 'assessable') return findings || [];
143	  return (findings || []).filter((f) => f && f.status !== 'miss');
144	}
145	
146	module.exports = {
147	  BASE_REQUIRED, SECTOR_REQUIRED, requiredClasses, classify, pagePath, computeCoverage,
148	  coverageFor, isScreened, applyCoverage, pageClassForObligation, ruleNeeds,
149	};
150

