1	'use strict';
2	/**
3	 * pool.js - the E-236 parallel primitive and the Rule 9 hard-deadline wrapper.
4	 *
5	 * E-236 restored a 43s crawl to 6.9s with identical accuracy by removing the IDLING, not the work: I/O-
6	 * bound page fetches run in a bounded-concurrency pool with a wall-clock deadline that is a CAP (it stops
7	 * STARTING new work past the deadline), never a floor (Constitution Rule 8 - no Math.max, no minimum wait).
8	 * The pool width comes from the caller; nothing here widens or floors it.
9	 *
10	 * Rule 9: every external step is wrapped in a hard Promise.race deadline, so a slow dependency degrades
11	 * the crawl (a null slot) and never hangs it (the 752s stuck-Chromium class). Timers are INJECTABLE so
12	 * node:test drives this deterministically with no real wall-clock wait.
13	 */
14	
15	// withDeadline(factory, ms, timers) -> a promise that settles with factory()'s value, or REJECTS once
16	// `ms` elapses, whichever is first. timers defaults to the globals; a test injects a fake pair. The
17	// timer is always cleared so a resolved factory never leaves a dangling handle keeping the process alive.
18	function withDeadline(factory, ms, timers) {
19	  const T = timers || { setTimeout, clearTimeout };
20	  let timer = null;
21	  const deadline = new Promise((_resolve, reject) => {
22	    timer = T.setTimeout(() => reject(new Error('deadline exceeded after ' + ms + 'ms')), ms);
23	    if (timer && typeof timer.unref === 'function') timer.unref();
24	  });
25	  return Promise.race([Promise.resolve().then(factory), deadline])
26	    .finally(() => { if (timer) T.clearTimeout(timer); });
27	}
28	
29	// runPool(items, width, deadlineMs, fn, now) -> results aligned to `items` (null where a fetch failed or
30	// the wall-clock deadline was reached before that item STARTED). `now` is injectable (defaults to
31	// Date.now) so a test can prove the deadline is a cap: advance the clock past deadlineMs and the pool
32	// stops starting work, leaving the un-started tail null - it never blocks and never floors.
33	async function runPool(items, width, deadlineMs, fn, now) {
34	  const clock = typeof now === 'function' ? now : Date.now;
35	  const out = new Array(items.length);
36	  let idx = 0;
37	  const start = clock();
38	  async function worker() {
39	    for (;;) {
40	      const i = idx++;
41	      if (i >= items.length) return;
42	      if (clock() - start >= deadlineMs) { out[i] = null; continue; } // CAP: never START at or past the deadline (>=, Rule 8 - the budget is exhausted the instant elapsed reaches it)
43	      try { out[i] = await fn(items[i], i); }
44	      catch (e) { out[i] = null; /* FAIL-OPEN: one page's failure degrades to a null slot and the crawl continues (E-236 tolerance); the null is visible to the caller's telemetry, not swallowed silently. */ }
45	    }
46	  }
47	  const lanes = items.length === 0 ? 0 : Math.min(width, items.length);
48	  await Promise.all(Array.from({ length: lanes }, worker));
49	  return out;
50	}
51	
52	module.exports = { withDeadline, runPool };
53

1	'use strict';
2	/**
3	 * documents.js - follow footer-linked policy documents and read them, HONESTLY (caution.md C-033).
4	 *
5	 * Footer-linked policy documents and external PDFs (Lomond, Dutch & Dutch privacy/MSA/fees PDFs) were
6	 * never read, so "missing" findings fired on obligations whose evidence was in a linked PDF. This lane
7	 * follows those links and reads what it CAN with a zero-dependency route:
8	 *
9	 *   - HTML policy documents ARE parseable with the crawler's stripper -> {parsed:true, text}.
10	 *   - PDFs are NOT: there is no reliable zero-dependency PDF text extractor, and an honest gap beats a bad
11	 *     parser (a mis-extracted policy is worse than a known-unread one). Every PDF is recorded LOUDLY as
12	 *     {url, fetched:true, parsed:false, reason:'no-parser'} on the bundle, its note pushed to the log, and
13	 *     its page-class returned in `unparsedClasses` so the coverage interlock (C-024/C-033) demotes any
14	 *     obligation that depends on it to needs-review instead of asserting an absence.
15	 *
16	 * No new dependency is introduced (Constitution: zero runtime npm deps). Effects are INJECTED: fetchFn
17	 * (async url -> {ok,status,body,finalUrl,contentType}) and the deadline timers, so node:test runs offline.
18	 */
19	
20	const { withDeadline } = require('../crawler/pool.js');
21	const { stripHtml } = require('../crawler/extract.js');
22	const { classify } = require('../crawler/coverage-contract.js');
