2	// evidence/registers/lib/lookup-runner.js — the ONE execution flow every register module in this
3	// directory shares: guard the query length, check for a required key/config, make the single
4	// deadline-wrapped fetch, and judge the response against the shared name-match gate (C-004). Each
5	// register module supplies only its own request shape, response parsing and row fields; this file
6	// owns the flow they all have in common so a fix or a strengthening (a new guard, a new note kind)
7	// lands once, not six times (the C-188 "stale door" doctrine applied to evidence collection, not just
8	// facts production).
9	const { withDeadline, DEFAULT_DEADLINE_MS } = require('./deadline');
10	const { queryTooShort, bestCandidate } = require('./name-match');
11	const { makeNote } = require('./notes');
12	
13	// noteForFailedFetch(spec, outcome) -> note for a withDeadline() outcome that did not settle ok
14	// (a timeout or a thrown/rejected fetchFn). Split out of judgeOutcome so no single unit there
15	// carries every branch (tools/health-gate/check.js's decision-point cap).
16	function noteForFailedFetch(spec, outcome) {
17	  const reason = outcome.reason === 'timeout' ? 'timeout' : 'fetch_error';
18	  const detail = outcome.reason === 'timeout'
19	    ? 'no response within the call deadline'
20	    : 'fetch failed: ' + (outcome.error && outcome.error.message);
21	  return makeNote(spec.register, 'degraded', reason, detail, spec.log);
22	}
23	
24	// noteForBadResponse(spec, res) -> note when the settled fetchFn result is not a well-formed
25	// {status:200, json} shape (a non-200 status, or a missing/absent JSON body).
26	function noteForBadResponse(spec, res) {
27	  const status = res && res.status;
28	  return makeNote(spec.register, 'degraded', 'unexpected_response', 'register answered with status ' + status, spec.log);
29	}
30	
31	// judgeCandidates(spec, json) -> {row, note}. Runs the shared name-match gate (C-004) over a
32	// well-formed response body: zero candidates and a below-threshold best candidate are both
33	// row-absent, loud notes; a matched candidate is stamped with provenance and returned as a row.
34	function judgeCandidates(spec, json) {
35	  const { register, query, log } = spec;
36	  const candidates = spec.extractCandidates(json) || [];
37	  if (candidates.length === 0) {
38	    return { row: null, note: makeNote(register, 'no_match', 'no_candidates_returned', 'register returned zero candidates for "' + query + '"', log) };
39	  }
40	  const best = bestCandidate(query, candidates, (c) => c.name);
41	  if (!best || !best.matched) {
42	    const nearest = best ? (best.nameMatched + ' (score ' + best.score.toFixed(2) + ')') : '(none)';
43	    const detail = 'nearest candidate for "' + query + '" was ' + nearest
44	      + '; refused (C-004: a non-empty response is not a match without a real name match)';
45	    return { row: null, note: makeNote(register, 'no_match', 'below_threshold', detail, log) };
46	  }
47	  const row = spec.buildRow(best.candidate, best);
48	  row.source = register;
49	  row.fetched_at = new Date().toISOString();
50	  row.query = query;
51	  row.match = { name_queried: best.nameQueried, name_matched: best.nameMatched, score: Number(best.score.toFixed(4)) };
52	  return { row, note: null };
53	}
54	
55	// judgeOutcome(spec, outcome) -> {row, note}. `outcome` is a withDeadline() result: either
56	// {ok:false, reason:'timeout'|'error', ...} or {ok:true, value:{status, json}|null}. Never throws:
57	// every branch here is a typed, recorded degrade (never a fabricated or partial row).
58	function judgeOutcome(spec, outcome) {
59	  if (!outcome.ok) return { row: null, note: noteForFailedFetch(spec, outcome) };
60	  const res = outcome.value;
61	  if (!res || res.status !== 200 || res.json == null) return { row: null, note: noteForBadResponse(spec, res) };
62	  return judgeCandidates(spec, res.json);
63	}
64	
65	// runLookup(spec) -> Promise<{row, note}> for ONE register call. `spec` fields:
66	//   register          register id, e.g. 'companies_house'
67	//   query             the company-name candidate being searched
68	//   fetchFn           injected fetch(url, options) -> Promise<{status, json}|null> (Rule 9: the ONLY
69	//                     way this module ever touches the network; never called directly by a submodule)
70	//   deadlineMs        per-call budget (Rule 9); DEFAULT_DEADLINE_MS if not given
71	//   log               optional structured logger, forwarded to every note
72	//   requiredKeyNote   optional {present:false, reason, detail}; when present.present is false this
73	//                     lookup degrades on missing key/config WITHOUT ever calling fetchFn
74	//   buildRequest()    -> {url, headers, requestKey}
75	//   extractCandidates(json) -> [{name, raw}]
76	//   buildRow(candidate, best) -> the register-specific row object (source/fetched_at/query/match are
77	//                     added by judgeOutcome above, never by the submodule — C-005: only the
78	//                     establishing call stamps provenance, and it is stamped in exactly one place)
79	async function runLookup(spec) {
80	  const { register, query, fetchFn, deadlineMs, log } = spec;
81	  if (queryTooShort(query)) {
82	    const detail = 'normalised query "' + query + '" is too short to search a register safely';
83	    return { row: null, note: makeNote(register, 'no_match', 'query_too_short', detail, log) };
84	  }
85	  if (spec.requiredKeyNote && spec.requiredKeyNote.present === false) {
86	    return { row: null, note: makeNote(register, 'degraded', spec.requiredKeyNote.reason, spec.requiredKeyNote.detail, log) };
87	  }
88	  const { url, headers, requestKey } = spec.buildRequest();
89	  const outcome = await withDeadline(() => fetchFn(url, { headers, requestKey }), deadlineMs || DEFAULT_DEADLINE_MS, register);
90	  return judgeOutcome(spec, outcome);
91	}
