1	'use strict';
2	// evidence/browser/observe.js - the PECR pre-consent OBSERVATION lane (P3 Wave-1c).
3	//
4	// WHAT THIS SEES THAT HTML CANNOT (caution.md C-039): the PECR reg.6 breach is not in the page
5	// source, it is in BEHAVIOUR - non-essential cookies written, and tracker requests fired, on first
6	// load with NOTHING clicked. This lane loads a page in a fresh browser, touches nothing, records the
7	// cookies + tracker network events that appear BEFORE any consent interaction, then accepts consent
8	// and captures again for the pre/post diff. A non-essential cookie/tracker present pre-consent is an
9	// observed breach candidate carrying the captured network event as its deterministic artifact
10	// (Constitution Rule 3). This module only OBSERVES; the breach lane (P3 Wave 2) adjudicates.
11	//
12	// FOUR structural safeguards this file is built around:
13	//   1. DEADLINE (C-040 / Rule 9): ONE outer Promise.race wraps launch -> observe -> close. The 752s
14	//      hostage incident is structurally impossible here: observe() cannot outlast deadlineMs + a
15	//      bounded force-close, whatever the browser does. Proven by observe.test.js's hanging-fake test
16	//      and the p3-browser-deadline calibration fixture.
17	//   2. OPTIONAL DEPENDENCY (C-041): Playwright is NOT a package.json dependency. It is resolved
18	//      lazily via an injected launchBrowser factory (or the lazy adapter). When unavailable, the lane
19	//      records lane:{ran:false, reason:'playwright-unavailable'} LOUDLY - never a silent nothing,
20	//      never a throw that kills a mint.
21	//   3. LINK HEALTH (C-042): a found consent/cookie-policy control is health-checked via an injected
22	//      fetch; a broken control is itself a finding (kind:'consent_control_broken').
23	//   4. LICENCE-CLEAN ORACLE (C-043): classification uses evidence/browser/oracle.js, 100% own-authored
24	//      (no NC/AGPL/ShareAlike data); its licence provenance is recorded on lane.oracle.
25	//
26	// TESTABILITY: observe() never touches a real browser or network directly. It drives an injected
27	// `launchBrowser` factory that returns a browser conforming to the small contract documented in
28	// playwright-adapter.js. node:test drives the ENTIRE logic with a scripted FAKE browser; no real
29	// Chromium runs in tests or CI (the acceptance-spec rule: live-fetch paths are dependency-injected).
30	
31	const { raceWithDeadline } = require('./deadline');
32	const { resolvePlaywrightLauncher } = require('./playwright-adapter');
33	const { isTrackerHost, classifyCookie, oracleMeta } = require('./oracle');
34	// HOST is a one-door fact (Rule 1): a hostname is read through the single parsed-host door in
35	// tools/lib/safe-fetch.js, never re-derived here and never substring-matched (GAPS host-substring).
36	// parseSafeFetchTarget is the SAME door's SSRF gate: the consent-control URL is DOM-controlled (it comes
37	// from page.findConsentControl), so it must clear the door before any link-health fetch touches it.
38	const { hostOf: safeHostOf, parseSafeFetchTarget } = require('../../tools/lib/safe-fetch');
39	
40	// Every budget below is a CAP, never a floor (Rule 8): the outer race takes whichever settles first, and
41	// a caller may only lower a budget, never raise it past these module ceilings (see capOr).
42	const DEFAULT_DEADLINE_MS = 45000; // total launch->close ceiling; well under the 120s mint budget
43	const DEFAULT_SETTLE_MS = 3000;    // wait for on-load tags to fire and drop cookies (cap)
44	const DEFAULT_CLOSE_MS = 5000;     // force-close ceiling
45	const DEFAULT_LINK_MS = 8000;      // consent-control link-health fetch ceiling
46	
47	// ── option normalisation ───────────────────────────────────────────────────────────────────────
48	
49	function numOrNull(v) { const n = Number(v); return Number.isFinite(n) ? n : null; }
50	
51	// capOr(v, cap): a positive finite override CLAMPED to `cap`, else `cap`. A budget is a hard ceiling
52	// (Rule 8): a caller may ask for a SHORTER wall time, never a longer one, so a 3600000ms deadlineMs
53	// cannot defeat the documented 45s ceiling and stall a mint (the 752s-hostage class stays impossible).
54	function capOr(v, cap) {
55	  const n = Number(v);
56	  return Number.isFinite(n) && n > 0 ? Math.min(n, cap) : cap;
57	}
58	
59	function normaliseOpts(opts) {
60	  const o = opts || {};
61	  return {
62	    deadlineMs: capOr(o.deadlineMs, DEFAULT_DEADLINE_MS),
63	    settleMs: capOr(o.settleMs, DEFAULT_SETTLE_MS),
64	    closeMs: capOr(o.closeMs, DEFAULT_CLOSE_MS),
65	    linkMs: capOr(o.linkMs, DEFAULT_LINK_MS),
66	    now: typeof o.now === 'function' ? o.now : Date.now,
67	    launchBrowser: o.launchBrowser,
68	    fetchLink: o.fetchLink,
69	    oracle: o.oracle || { isTrackerHost, classifyCookie, oracleMeta },
70	  };
71	}
72	
73	// ── oracle indirection (an injected oracle overrides the module's own; both are licence-clean) ───
74	
75	function oracleMetaOf(cfg) {
76	  const o = cfg.oracle;
77	  return (o && typeof o.oracleMeta === 'function') ? o.oracleMeta() : oracleMeta();
78	}
79	function classify(cfg, cookie) {
80	  const o = cfg.oracle;
81	  return (o && typeof o.classifyCookie === 'function') ? o.classifyCookie(cookie) : classifyCookie(cookie);
82	}
83	function trackerHost(cfg, host) {
84	  const o = cfg.oracle;
85	  return (o && typeof o.isTrackerHost === 'function') ? o.isTrackerHost(host) : isTrackerHost(host);
86	}
87	
88	// ── lane result builders (every non-ran outcome is RECORDED, never silent - C-041/Rule 4) ────────
89	
90	function unknownControl() { return { found: false, healthy: null, url: null, status: null }; }
91	
92	function lanePlaywrightUnavailable(cfg) {
93	  return { observed: [], consentControl: unknownControl(), lane: { ran: false, reason: 'playwright-unavailable', oracle: oracleMetaOf(cfg) } };
94	}
95	function laneDeadline(elapsed, cfg) {
96	  return { observed: [], consentControl: unknownControl(), lane: { ran: false, reason: 'deadline', elapsedMs: elapsed, oracle: oracleMetaOf(cfg) } };
97	}
98	function laneError(err, elapsed, cfg) {
99	  const message = String((err && err.message) || err).slice(0, 200);
100	  return { observed: [], consentControl: unknownControl(), lane: { ran: false, reason: 'error', message, elapsedMs: elapsed, oracle: oracleMetaOf(cfg) } };
101	}
102	function laneRan(observed, consentControl, diff, cfg) {
103	  return { observed, consentControl, lane: { ran: true, reason: null, diff, oracle: oracleMetaOf(cfg) } };
104	}
105	
106	// ── host + cookie helpers ────────────────────────────────────────────────────────────────────────
107	
108	function expiryDays(expires, nowMs) {
109	  const e = Number(expires);
110	  if (!Number.isFinite(e) || e <= 0) return null;
111	  return Math.round((e * 1000 - nowMs) / 86400000);
112	}
113	
114	function nonEssentialCookies(cookies, cfg) {
115	  const out = [];
116	  for (const cookie of cookies || []) {
117	    const cls = classify(cfg, cookie);
118	    if (cls.verdict === 'non_essential') out.push({ cookie, cls });
119	  }
120	  return out;
121	}
122	
123	function uniqueHosts(trackers) {
124	  const seen = new Set();
125	  const out = [];
126	  for (const ev of trackers || []) {
127	    if (ev && ev.host && !seen.has(ev.host)) { seen.add(ev.host); out.push(ev.host); }
128	  }
129	  return out;
130	}
131	
132	function firstTrackerForHost(trackers, host) {
133	  for (const ev of trackers || []) {
134	    if (ev && ev.host === host) return ev;
135	  }
136	  return null;
137	}
138	
139	function isTrackerEvent(ev, cfg) {
140	  return Boolean(ev && ev.host) && trackerHost(cfg, ev.host);
141	}
142	
143	// ── network capture: register a pre-goto listener so on-load requests are never missed ────────────
144	
145	function attachNetworkCapture(page, cfg) {
146	  const events = [];
147	  if (typeof page.on === 'function') {
148	    page.on('request', (ev) => { if (isTrackerEvent(ev, cfg)) events.push(ev); });
149	  }
150	  return { snapshot() { return events.slice(); } };
151	}
152	
153	async function snapshotState(page, capture, cfg) {
154	  const cookies = typeof page.cookies === 'function' ? await page.cookies() : [];
155	  return { cookies: Array.isArray(cookies) ? cookies : [], trackers: capture.snapshot(), ts: cfg.now() };
156	}
157	
158	// ── observed-breach construction (Rule 3: every entry carries a deterministic artifact) ───────────
159	
160	function cookieArtifact(cookie, cls, nowMs) {
161	  return {
162	    type: 'cookie_jar_entry',
163	    // No cookie VALUE is ever stored (Rule 16: it may carry PII/secrets); name + domain + expiry only.
164	    cookie: { name: cookie.name, domain: cookie.domain, expiresDays: expiryDays(cookie.expires, nowMs) },
165	    category: cls.category || 'tracking',
166	    platform: cls.platform || null,
167	  };
168	}
169	
170	function addCookieBreaches(observed, pre, cfg) {
171	  for (const { cookie, cls } of nonEssentialCookies(pre.cookies, cfg)) {
172	    const host = cls.host || String(cookie.domain || '').replace(/^\./, '');
173	    observed.push({
174	      kind: 'cookie_pre_consent',
175	      name: cookie.name,
176	      host,
177	      essential: false,
178	      networkEvent: firstTrackerForHost(pre.trackers, host),
179	      artifact: cookieArtifact(cookie, cls, pre.ts),
180	      ts: pre.ts,
181	    });
182	  }
183	}
184	
185	function addTrackerBreaches(observed, pre) {
186	  for (const host of uniqueHosts(pre.trackers)) {
187	    const ev = firstTrackerForHost(pre.trackers, host);
188	    observed.push({
189	      kind: 'tracker_request_pre_consent',
190	      name: host,
191	      host,
192	      essential: false,
193	      networkEvent: ev,
194	      artifact: { type: 'network_request', networkEvent: ev },
195	      ts: (ev && ev.ts) || pre.ts,
196	    });
197	  }
198	}
199	
200	function addBrokenControl(observed, consentControl, cfg) {
201	  if (!consentControl.found || consentControl.healthy !== false) return;
202	  observed.push({
203	    kind: 'consent_control_broken',
204	    name: consentControl.url,
205	    host: safeHostOf(consentControl.url),
206	    essential: null,
207	    networkEvent: null,
208	    // The artifact retains the OBSERVED failing status (Rule 3): a broken-control finding exists ONLY on
209	    // a captured HTTP failure. A timeout or a transport error never reaches here - those abstain to
210	    // healthy:null in linkHealth (absence vs observation, Rule 8), so this branch cannot fire on them.
211	    artifact: { type: 'link_health', url: consentControl.url, healthy: false, status: consentControl.status },
212	    ts: cfg.now(),
213	  });
214	}
215	
216	function buildObserved(pre, consentControl, cfg) {
217	  const observed = [];
218	  addCookieBreaches(observed, pre, cfg);
219	  addTrackerBreaches(observed, pre);
220	  addBrokenControl(observed, consentControl, cfg);
221	  return observed;
222	}
223	
224	function diffSummary(pre, post, cfg) {
225	  return {
226	    preNonEssentialCookies: nonEssentialCookies(pre.cookies, cfg).length,
227	    postNonEssentialCookies: nonEssentialCookies(post.cookies, cfg).length,
228	    preTrackerHosts: uniqueHosts(pre.trackers).length,
229	    postTrackerHosts: uniqueHosts(post.trackers).length,
230	  };
231	}
232	
233	// ── consent-control link health (C-042) ──────────────────────────────────────────────────────────
234	
235	function runFetch(fetchLink, url) { return Promise.resolve().then(() => fetchLink(url)); }
236	// A rejected fetch is marked as a TRANSPORT ERROR (no `value`): the server's response was never seen.
237	function fetchToError(e) { return { timedOut: false, error: String((e && e.message) || e).slice(0, 120) }; }
238	function statusBad(status) { const s = Number(status); return Number.isFinite(s) && s >= 400; }
239	
240	// linkHealth(url, cfg) -> { healthy, status }. healthy is TRUE/FALSE only on an OBSERVED HTTP response
241	// (a captured status): a >=400 or ok:false response is an observed broken control (healthy:false, status
242	// retained for the artifact). A TIMEOUT or a TRANSPORT ERROR is an UNOBSERVED failure - the response was
243	// never seen, so it proves nothing about the control and abstains (healthy:null), never emitting a
244	// finding (absence vs observation, Rule 8 + "no artifact, no breach", Rule 3). The earlier build promoted
245	// both timeout and network error to healthy:false and shipped an artifact carrying no status at all.
246	async function linkHealth(url, cfg) {
247	  if (typeof cfg.fetchLink !== 'function') return { healthy: null, status: null };
248	  const raced = await raceWithDeadline(runFetch(cfg.fetchLink, url), cfg.linkMs, cfg.now).catch(fetchToError);
249	  if (raced.timedOut || raced.error !== undefined) return { healthy: null, status: null };
250	  const res = raced.value || {};
251	  const status = numOrNull(res.status);
252	  return { healthy: Boolean(res.ok) && !statusBad(status), status };
253	}
254	
255	async function checkConsentControl(control, cfg) {
256	  if (!control || !control.found) return unknownControl();
257	  const url = control.url || null;
258	  if (!url) return { found: true, healthy: null, url: null, status: null };
259	  // The control URL is DOM-controlled: it must clear the single SSRF-safe door before any fetch touches
260	  // it (Rule 5 - hosts parsed via one door; a page cannot point the runner at a private/metadata host).
261	  // An unsafe target is not fetched at all: health is unassertable, so abstain (no finding, healthy:null).
262	  if (!parseSafeFetchTarget(url)) return { found: true, healthy: null, url, status: null };
263	  const health = await linkHealth(url, cfg);
264	  return { found: true, healthy: health.healthy, url, status: health.status };
265	}
266	
267	// ── the observation pipeline (all under the outer deadline) ───────────────────────────────────────
268	
269	async function navigateUntouched(page, url, cfg) {
270	  await page.goto(url);
271	  if (typeof page.settle === 'function') await page.settle(cfg.settleMs);
272	}
273	
274	async function safeFindControl(page) {
275	  if (typeof page.findConsentControl !== 'function') return null;
276	  return page.findConsentControl();
277	}
278	
279	async function attemptConsent(page, control) {
280	  if (!control || !control.found) return;
281	  if (typeof page.clickConsent !== 'function') return;
282	  await page.clickConsent(control);
283	}
284	
285	async function runObservation(url, cfg, launcher, holder) {
286	  const browser = await launcher();
287	  holder.browser = browser;
288	  const page = await browser.newPage();
289	  const capture = attachNetworkCapture(page, cfg);
290	  await navigateUntouched(page, url, cfg);
291	  const pre = await snapshotState(page, capture, cfg);   // BEFORE any consent interaction
292	  const control = await safeFindControl(page);
293	  const consentControl = await checkConsentControl(control, cfg);
294	  await attemptConsent(page, control);                    // injected clicker (accept)
295	  const post = await snapshotState(page, capture, cfg);   // AFTER consent, for the diff
296	  const observed = buildObserved(pre, consentControl, cfg);
297	  await browser.close();
298	  holder.browser = null;
299	  return laneRan(observed, consentControl, diffSummary(pre, post, cfg), cfg);
300	}
301	
302	// ── force-close: bounded on EVERY exit path, so a stuck browser cannot reintroduce the 752s hang ──
303	
304	async function forceClose(holder, cfg) {
305	  const browser = holder.browser;
306	  holder.browser = null;
307	  if (!browser || typeof browser.close !== 'function') return;
308	  try {
309	    await raceWithDeadline(Promise.resolve().then(() => browser.close()), cfg.closeMs, cfg.now);
310	  } catch (e) {
311	    // FAIL-OPEN JUSTIFICATION (Rule 4): a browser that will not close cannot be allowed to block the
312	    // mint; the CI/mint runner is ephemeral and reaps the process. Recorded to stderr (observable),
313	    // never silently swallowed, and never rethrown into the mint path.
314	    console.error('[evidence/browser] force-close failed (non-fatal, runner is ephemeral): ' + String((e && e.message) || e).slice(0, 160));
315	  }
316	}
317	
318	async function resolveLauncher(cfg) {
319	  if (typeof cfg.launchBrowser === 'function') return cfg.launchBrowser;
320	  return resolvePlaywrightLauncher({ now: cfg.now });
321	}
322	
323	async function observeWithLauncher(url, cfg, launcher) {
324	  const holder = { browser: null };
325	  const started = cfg.now();
326	  try {
327	    const raced = await raceWithDeadline(runObservation(url, cfg, launcher, holder), cfg.deadlineMs, cfg.now);
328	    if (raced.timedOut) return laneDeadline(raced.elapsed, cfg);
329	    return raced.value;
330	  } catch (e) {
331	    // FAIL-OPEN: a launch/observe failure is RECORDED into lane.reason='error' (laneError captures
332	    // e.message) and returned; a broken browser must degrade the mint, never throw into it (Rule 4).
333	    return laneError(e, cfg.now() - started, cfg);
334	  } finally {
335	    await forceClose(holder, cfg);
336	  }
337	}
338	
339	/**
340	 * observe(url, opts) -> Promise<bundle.browser>. Never throws, never hangs a mint.
341	 *
342	 * opts (all optional; live-fetch paths are dependency-injected):
343	 *   launchBrowser  async () => browser        the browser factory (see playwright-adapter.js contract).
344	 *                                             Absent -> the lazy real Playwright adapter is tried; if no
345	 *                                             driver resolves, lane:{ran:false, reason:'playwright-unavailable'}.
346	 *   fetchLink      async (url) => {ok,status} injected consent-control link-health fetch (C-042).
347	 *   deadlineMs     number   total launch->close ceiling (default 45000; a CAP, never a floor).
348	 *   settleMs       number   post-navigation settle (default 3000).
349	 *   closeMs        number   force-close ceiling (default 5000).
350	 *   linkMs         number   link-health fetch ceiling (default 8000).
351	 *   now            () => ms injected clock (default Date.now) for deterministic elapsed/ts in tests.
352	 *   oracle         { isTrackerHost, classifyCookie, oracleMeta }  override (default: the licence-clean module oracle).
353	 *
354	 * Returns { observed, consentControl, lane } where:
355	 *   observed[]      { kind, name, host, essential, networkEvent, artifact, ts }
356	 *                   kind in { cookie_pre_consent, tracker_request_pre_consent, consent_control_broken }.
357	 *   consentControl  { found, healthy, url }.
358	 *   lane            { ran, reason, oracle:{source,licence}, ... } - the lane's outcome, always recorded.
359	 */
360	async function observe(url, opts) {
361	  const cfg = normaliseOpts(opts);
362	  const launcher = await resolveLauncher(cfg);
363	  if (typeof launcher !== 'function') return lanePlaywrightUnavailable(cfg);
364	  return observeWithLauncher(url, cfg, launcher);
365	}
366	
367	module.exports = {
368	  observe,
369	  // exported for unit tests and the calibration fixture (never re-derives a fact; helpers only):
370	  normaliseOpts,
371	  buildObserved,
372	  diffSummary,
373	  checkConsentControl,
374	  laneDeadline,
375	  lanePlaywrightUnavailable,
376	  DEFAULT_DEADLINE_MS,
377	  DEFAULT_SETTLE_MS,
378	  DEFAULT_CLOSE_MS,
379	  DEFAULT_LINK_MS,
380	};
381

