1	'use strict';
2	// evidence/browser/observe.test.js - node:test suite for the PECR pre-consent lane.
3	// Run: node --test evidence/browser/observe.test.js
4	//
5	// FAKE-BROWSER ARCHITECTURE: observe() drives an injected launchBrowser factory, so the ENTIRE
6	// logic is exercised here against a SCRIPTED FAKE browser - no real Chromium, no network, no CI
7	// browser install. makeFake({...}) returns a launch() conforming to observe.js's small contract
8	// (newPage/on('request')/goto/settle/cookies/findConsentControl/clickConsent/close) and can be
9	// scripted to: set cookies pre- and post-consent, fire tracker requests on load and after the
10	// consent click, present (or omit) a consent control, and HANG on launch or goto to prove the
11	// deadline. `rec` records what the fake was asked to do (closed, clicked, ...).
12	
13	const test = require('node:test');
14	const assert = require('node:assert/strict');
15	
16	const { observe, normaliseOpts, DEFAULT_DEADLINE_MS, DEFAULT_CLOSE_MS, DEFAULT_SETTLE_MS, DEFAULT_LINK_MS } = require('./observe.js');
17	
18	function counter() { let t = 0; return () => (t += 1); }
19	function hangForever() { return new Promise(() => {}); }
20	
21	function makeFake(script) {
22	  const s = script || {};
23	  const rec = { closed: false, newPageCalls: 0, gotoCalled: false, clicked: false, consented: false };
24	  const handlers = [];
25	  function emit(reqs) {
26	    for (const r of reqs || []) {
27	      const ev = { host: r.host, url: r.url || ('https://' + r.host + '/tag.js'), resourceType: r.resourceType || 'script', ts: Date.now() };
28	      for (const h of handlers) h(ev);
29	    }
30	  }
31	  const page = {
32	    on(ev, h) { if (ev === 'request') handlers.push(h); },
33	    async goto() { if (s.hang === 'goto') return hangForever(); rec.gotoCalled = true; emit(s.preRequests); },
34	    async settle() {},
35	    async cookies() { return rec.consented ? (s.postCookies || s.preCookies || []) : (s.preCookies || []); },
36	    async findConsentControl() { return s.control || null; },
37	    async clickConsent() { rec.clicked = true; rec.consented = true; emit(s.postRequests); },
38	  };
39	  const browser = {
40	    async newPage() { rec.newPageCalls++; return page; },
41	    async close() { rec.closed = true; },
42	  };
43	  async function launch() { if (s.hang === 'launch') return hangForever(); return browser; }
44	  return { launch, rec, browser, page };
45	}
46	
47	const healthy = async () => ({ ok: true, status: 200 });
48	
49	// ── C-041: optional dependency absent, recorded loudly, never a throw ─────────────────────────────
50	
51	test('observe: no launchBrowser and no real driver -> lane records playwright-unavailable, never throws', async () => {
52	  const r = await observe('https://example.com', {}); // nothing injected; the real resolver finds no driver
