2	/* global document, window */
3	// evidence/browser/playwright-adapter.js - the LAZY, OPTIONAL real-browser adapter.
4	//
5	// Playwright is an OPTIONAL runtime dependency: it is deliberately NOT in this repo's
6	// package.json (zero-runtime-dependency rule) and must never be added by this module. This file is
7	// the ONLY place that names it, and it is required LAZILY inside a function - never at module load -
8	// so importing evidence/browser can never throw for a missing driver. When no driver resolves,
9	// resolvePlaywrightLauncher() logs LOUDLY and returns null; observe.js turns that into a recorded
10	// `lane:{ran:false, reason:'playwright-unavailable'}` (caution.md C-041: the lane's absence is
11	// visible, never silent).
12	//
13	// It maps a real Playwright browser onto observe.js's small injected contract, so observe.js is
14	// driven identically by this adapter in production and by a scripted FAKE browser in tests. The
15	// contract a launchBrowser() result must satisfy:
16	//   browser.newPage()        -> page
17	//     page.on('request', h)     register a listener; h({ host, url, resourceType, ts })
18	//     page.goto(url)            navigate, touch nothing
19	//     page.settle(ms)           wait ms for on-load tags to fire
20	//     page.cookies()            -> [{ name, domain, value, expires }]  (expires: unix seconds or -1)
21	//     page.findConsentControl() -> { found, url?, text?, acceptSelector? } | null
22	//     page.clickConsent(ctrl)   accept consent (no-op when none)
23	//   browser.close()
24	
25	const DRIVERS = ['playwright', 'playwright-core', '@playwright/test'];
26	
27	// resolveChromium() -> { chromium, driver } | null. Tries each optional driver by lazy require.
28	// A require() failure for an absent optional dependency is EXPECTED, not an error: it is captured to
29	// the "try the next driver" control flow (not swallowed in error - the loud null is returned below).
30	function resolveChromium() {
31	  for (const mod of DRIVERS) {
32	    const chromium = tryRequireChromium(mod);
33	    if (chromium) return { chromium, driver: mod };
34	  }
35	  return null;
36	}
37	
38	function tryRequireChromium(mod) {
39	  try {
40	    const m = require(mod);
41	    return m.chromium || (m.default && m.default.chromium) || null;
42	  } catch (e) {
43	    return null; // FAIL-OPEN: an absent OPTIONAL driver is a legitimate state; the caller logs the aggregate miss loudly and returns null (C-041). Not an error to surface per-driver.
44	  }
45	}
46	
47	// The DOM scan that runs inside the page (browser context). Returns the first consent/cookie
48	// policy control found: a recognised accept button and/or a policy link. Kept side-effect free.
49	function scanConsentDom() {
50	  const pick = (sel) => document.querySelector(sel);
51	  const acceptSel = [
52	    '#onetrust-accept-btn-handler', '#CybotCookiebotDialogBodyLevelButtonLevelOptinAllowAll',
53	    '.cky-btn-accept', '#ccc-recommended-settings', 'button[aria-label*="accept" i]',
54	  ].find((s) => pick(s));
55	  const link = pick('a[href*="cookie" i], a[href*="privacy" i]');
56	  const found = Boolean(acceptSel || link);
57	  return {
58	    found,
59	    url: link ? link.href : null,
60	    text: link ? (link.textContent || '').trim().slice(0, 120) : null,
61	    acceptSelector: acceptSel || null,
62	    hasBanner: /cookie|consent|privacy/i.test((document.body && document.body.innerText || '').slice(0, 4000)),
63	  };
64	}
65	
66	function toRequestEvent(request, now) {
67	  try {
68	    return { host: new URL(request.url()).hostname, url: request.url().slice(0, 300), resourceType: request.resourceType(), ts: now() };
69	  } catch (e) {
70	    return null; // FAIL-OPEN: a malformed request URL is not observable evidence; drop it (recorded as null, filtered by the caller). Not an error to surface.
71	  }
72	}
73	
74	function wrapPage(page, ctx, now) {
75	  return {
76	    on(event, handler) {
77	      if (event !== 'request') return;
78	      page.on('request', (r) => { const ev = toRequestEvent(r, now); if (ev) handler(ev); });
79	    },
80	    async goto(url) { await page.goto(url, { waitUntil: 'domcontentloaded', timeout: 15000 }).catch(() => {}); },
81	    async settle(ms) { await page.waitForTimeout(ms); },
82	    async cookies() { return (await ctx.cookies()).map((c) => ({ name: c.name, domain: c.domain, value: c.value, expires: c.expires })); },
83	    async findConsentControl() { return page.evaluate(scanConsentDom).catch(() => null); },
84	    async clickConsent(control) {
85	      if (!control || !control.acceptSelector) return;
86	      await page.click(control.acceptSelector, { timeout: 3000 }).catch(() => {});
87	    },
88	  };
89	}
90	
91	function wrapBrowser(browser, now) {
92	  return {
93	    async newPage() {
94	      const ctx = await browser.newContext({ viewport: { width: 1366, height: 900 } });
95	      const page = await ctx.newPage();
96	      return wrapPage(page, ctx, now);
97	    },
98	    async close() { await browser.close(); },
99	  };
100	}
101	
102	// resolvePlaywrightLauncher(opts) -> a launchBrowser() factory conforming to observe.js's contract,
103	// or null when no driver resolves (logged loudly, C-041). `opts.now` is the injected clock stamped
104	// onto captured request events.
105	function resolvePlaywrightLauncher(opts) {
106	  const resolved = resolveChromium();
107	  if (!resolved) {
108	    console.error('[evidence/browser] no Playwright driver resolvable (tried ' + DRIVERS.join(', ')
109	      + '); the PECR pre-consent lane is UNAVAILABLE and will be recorded as such on the bundle. '
110	      + 'Install playwright in the mint runner, or inject a launchBrowser factory.');
111	    return null;
112	  }
113	  const now = (opts && typeof opts.now === 'function') ? opts.now : Date.now;
114	  return async function launchBrowser() {
115	    const browser = await resolved.chromium.launch({ args: ['--no-sandbox', '--disable-dev-shm-usage'] });
116	    return wrapBrowser(browser, now);
117	  };
118	}
119	
120	module.exports = { resolvePlaywrightLauncher, scanConsentDom, DRIVERS };
