2	/**
3	 * breach/verifiers/register-row.js - verifies a `register_row` artifact (Constitution Rule 3: "a
4	 * register row" is one of the four things a breach finding may carry as its deterministic artifact).
5	 *
6	 * Contract (candidate.artifact when type === 'register_row'):
7	 *   { type: 'register_row', register: 'companiesHouse'|'gleif'|'sra'|'cqc'|'fca'|'ico', row: {...} }
8	 *
9	 * `register` names the key on EvidenceBundle.registers (facts/README.md); `row` is the EXACT row
10	 * object the candidate is citing as its evidence, copied verbatim from what the candidate read off
11	 * the bundle. verifyRegisterRow does not re-run the name-match gate (caution.md C-004: that is
12	 * evidence/registers/'s one door, already applied before the row ever reached the bundle) - it proves
13	 * only that the cited row is not a paraphrase or an invention: it deep-equals the row actually present
14	 * on bundle.registers[register]. This directory never hardcodes the six register keys itself (that
15	 * enumeration belongs to evidence/registers/registers.js, Rule 1's one-door doctrine): an unknown or
16	 * misspelt register key simply has no bundle row to match, so it is rejected by the same absence path
17	 * as a genuinely missing register, with no separate allow-list to keep in sync.
18	 */
19	const { isDeepStrictEqual } = require('util');
20	const { CODES, accepted, rejected } = require('./result');
21	
22	// verifyRegisterRow(artifact, bundle) -> {verified, code, reason}. Fails closed on: a missing
23	// register/row field, a register key absent from bundle.registers, or a cited row whose content
24	// differs from the bundle's row in any field (an altered figure, a fabricated number, a dropped
25	// provenance field - all count as a mismatch; Rule 12 Gate 2's "exact re-match" ethos applied to
26	// structured data, not just prose).
27	function verifyRegisterRow(artifact, bundle) {
28	  if (!artifact || typeof artifact !== 'object') {
29	    // Fail closed on a missing artifact envelope (Rule 3/4): read `artifact.register` off undefined
30	    // would THROW, and a thrown verifier is an unhandled path - a missing envelope is simply "no
31	    // verifiable register row", so it is a clean REJECT, never an exception into the pipeline.
32	    return rejected(CODES.REGISTER_ROW_MISSING_FIELDS, 'artifact envelope is required (no artifact, no breach)');
33	  }
34	  if (typeof artifact.register !== 'string' || !artifact.register) {
35	    return rejected(CODES.REGISTER_ROW_MISSING_FIELDS, 'artifact.register is required');
36	  }
37	  if (!artifact.row || typeof artifact.row !== 'object' || Array.isArray(artifact.row)) {
38	    return rejected(CODES.REGISTER_ROW_MISSING_FIELDS, 'artifact.row is required (the exact row object the candidate cites)');
39	  }
40	  const registers = (bundle && bundle.registers) || {};
41	  const actual = registers[artifact.register];
42	  if (!actual || typeof actual !== 'object') {
43	    return rejected(CODES.REGISTER_ROW_ABSENT, 'bundle.registers has no row for ' + JSON.stringify(artifact.register));
44	  }
45	  if (!isDeepStrictEqual(actual, artifact.row)) {
46	    return rejected(
47	      CODES.REGISTER_ROW_MISMATCH,
48	      'the cited row does not exactly match bundle.registers.' + artifact.register
49	    );
50	  }
51	  return accepted(CODES.REGISTER_ROW_VERIFIED, 'row exact-matched bundle.registers.' + artifact.register);
52	}
53	
54	module.exports = { verifyRegisterRow };
