47	      CODES.NETWORK_EVENT_MISSING_FIELDS,
48	      'artifact.kind, artifact.host and artifact.name are all required to identify a network_event candidate'
49	    );
50	  }
51	  const browser = bundle && bundle.browser;
52	  if (!browser || !browser.lane || browser.lane.ran !== true) {
