6	 * deterministic artifact is proof that the lookup ACTUALLY RAN and returned no match (Constitution
7	 * Rule 3; caution.md C-004: a name-match failure is the only evidence of non-appearance, and a
8	 * lookup that never ran proves nothing).
9	 *
10	 * Contract (candidate.artifact when type === 'register_absence'):
11	 *   {
12	 *     type: 'register_absence',
13	 *     register,   // the key on EvidenceBundle.registers this claim concerns (e.g. 'sra')
14	 *     query,      // informational: what was looked up (may be null; the verifier does not read it)
15	 *     lane: 'no_match',
16	 *     note,       // the registers notes[] entry that recorded the outcome
17	 *   }
18	 *
19	 * verifyRegisterAbsence(artifact, bundle) proves TWO things independently of the artifact's own
20	 * claims (defence in depth, Rule 4; the proposer's assertion is not trusted alone):
21	 *   1. There is NO present row on bundle.registers[register] - you cannot claim a firm is absent from
22	 *      a register that returned a matched row for it.
23	 *   2. bundle.registers.notes[] carries an entry for THIS register whose kind is 'no_match'. This is
24	 *      the crux of C-004: a 'skipped' lookup (judged not applicable) or a 'degraded' lookup (a missing
25	 *      key, a fetch error, a timeout) proves NOTHING about whether the firm is registered; only a
26	 *      lookup that RAN and returned no name-match is evidence of non-appearance. A degraded/skipped/
27	 *      absent note is REJECTED (fail closed), never accepted as an absence proof.
28	 *
29	 * This directory never re-runs the name-match gate itself (that is evidence/registers/'s one door,
30	 * caution.md C-004, applied before the note ever reached the bundle): it proves only that the note
31	 * the candidate leans on genuinely records a ran-and-no-match outcome.
32	 */
33	const { CODES, accepted, rejected } = require('./result');
34	
35	// KIND_PROVES_ABSENCE: the ONLY register-note kind that proves a firm is absent. A skipped or degraded
36	// lane recorded a note too, but neither ran a real name-match, so neither proves non-appearance (C-004).
37	const KIND_PROVES_ABSENCE = 'no_match';
38	
39	// noteForRegister(bundle, register) -> the notes[] entry recording this register's lookup outcome, or
40	// null when no note exists (the lane never recorded running at all).
41	function noteForRegister(bundle, register) {
42	  const registers = (bundle && bundle.registers) || {};
43	  const notes = Array.isArray(registers.notes) ? registers.notes : [];
44	  return notes.find((n) => n && n.register === register) || null;
45	}
46	
47	// verifyRegisterAbsence(artifact, bundle) -> {verified, code, reason}. Fails closed on: a missing
48	// register field, a register that actually returned a present row (so an absence claim is false), or a
49	// lookup that did not definitively run-and-no-match (a skipped/degraded/absent note proves nothing).
50	function verifyRegisterAbsence(artifact, bundle) {
51	  if (typeof artifact.register !== 'string' || !artifact.register) {
52	    return rejected(CODES.REGISTER_ABSENCE_MISSING_FIELDS, 'artifact.register is required');
53	  }
54	  const registers = (bundle && bundle.registers) || {};
55	  const present = registers[artifact.register];
56	  if (present && typeof present === 'object') {
57	    return rejected(
58	      CODES.REGISTER_ABSENCE_ROW_PRESENT,
59	      'bundle.registers.' + artifact.register + ' carries a present row; a non-appearance claim cannot stand against a matched register row'
60	    );
61	  }
62	  const note = noteForRegister(bundle, artifact.register);
63	  if (!note || note.kind !== KIND_PROVES_ABSENCE) {
64	    const seen = note ? note.kind : 'no note';
65	    return rejected(
66	      CODES.REGISTER_ABSENCE_NOT_PROVEN,
67	      'the ' + JSON.stringify(artifact.register) + ' lookup did not definitively run-and-no-match (saw: ' + seen
68	        + '); only a "no_match" note proves non-appearance (C-004: a skipped or degraded lookup proves nothing)'
69	    );
70	  }
71	  return accepted(
72	    CODES.REGISTER_ABSENCE_VERIFIED,
73	    'the ' + artifact.register + ' register lookup ran and returned no name-match (C-004): a definitive non-appearance'
74	  );
75	}
76	
77	module.exports = { verifyRegisterAbsence, noteForRegister };
