1	'use strict';
2	/**
3	 * pattern-match.js - the anchoring + matching primitives for the breach proposer layer.
4	 *
5	 * A DetectionSpec (detection-spec.js) carries patterns as plain data ({kind, value}); this module is
6	 * how those patterns are ANCHORED (compiled to \b-bounded regex sources) and MATCHED against text.
7	 * Extracted from detection-spec.js so the pattern grammar and the matcher are separate, focused units.
8	 *
9	 * LINEAR-TIME by construction (Rob P0: the old 'all' token-set compiled to
10	 * `(?=[\s\S]*t1)(?=[\s\S]*t2)...[\s\S]`, which backtracked catastrophically on real corpora -
11	 * NY_RPC_7_3_7_4 hung, CA_RPC_CH7 / IL_RPC_7 ~6-8s). No matcher here ever builds a co-occurrence
12	 * mega-regex: a token-set is tested token by token (each `\bword\b` is a bounded literal, no
13	 * backtracking blowup), combined by some()/every(); an anchored-regex is a `\b`-bounded word run
14	 * joined by `\W+` (linear). validateSpec's ReDoS guard (detection-spec.js) rejects any stored
15	 * anchored-regex that reintroduces a lookaround or an unbounded .* / [\s\S]* star.
16	 *
17	 * Pure and synchronous (no network/clock/env). Holds NO law/fine/regulator literal (Rule 2).
18	 */
19	
20	// ── anchoring primitives ─────────────────────────────────────────────────────────────────────────
21	function escapeRegex(s) {
22	  return String(s).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
23	}
24	
25	// anchorToken(word) -> a word-boundary-anchored regex SOURCE for one token (C-059). An internal hyphen
26	// is preserved ("under-18" -> \bunder-18\b); a bare token can never leak into a substring match.
27	function anchorToken(word) {
28	  return '\\b' + escapeRegex(String(word)) + '\\b';
29	}
30	
31	// buildAnchoredRegex(phrase) -> a single anchored-regex SOURCE for a multi-word phrase: each word
32	// escaped, joined by \W+ (run of non-word chars), the whole bounded by \b on both ends. Whitespace and
33	// punctuation between the client's words is tolerated; the phrase can never match as a bare substring.
34	function buildAnchoredRegex(phrase) {
35	  const words = String(phrase).trim().split(/\s+/).map(escapeRegex).filter(Boolean);
36	  if (!words.length) return null;
37	  return '\\b' + words.join('\\W+') + '\\b';
38	}
39	
40	// compileRegex(pattern) -> a case-insensitive RegExp for a pattern, or null if it cannot compile. A null
41	// here is surfaced by validateSpec as a rejected spec, never swallowed (the C-050 dead-regex class).
42	function compileRegex(pattern) {
43	  const src = regexSourceOf(pattern);
44	  if (src == null) return null;
45	  try {
46	    return new RegExp(src, 'i');
47	  } catch (_err) {
48	    // FAIL-OPEN: recorded as null and reported by validateSpec's does-not-compile branch (Rule 4).
49	    return null;
50	  }
51	}
52	
53	// regexSourceOf(pattern) -> the single-regex source a pattern compiles to: an anchored-regex is its
54	// value; a token-set 'any' is an anchored alternation; a token-set 'all' has no safe single-regex form
55	// (returns null, matched linearly in matchesText); a url-path is matched by propose.js, not here.
56	function regexSourceOf(pattern) {
57	  if (!pattern || typeof pattern !== 'object') return null;
58	  if (pattern.kind === 'anchored-regex') return typeof pattern.value === 'string' ? pattern.value : null;
59	  if (pattern.kind === 'token-set') return tokenSetSource(pattern.value);
60	  return null;
61	}
62	
63	// tokenSetSource(value) -> a SINGLE-regex source for a token-set, or null when there is no linear-time
64	// single-regex form. 'any' is a plain anchored alternation (linear). 'all' (co-occurrence, any order)
65	// has NO safe single-regex form - the old lookahead-with-[\s\S]* backtracked catastrophically (Rob P0)
66	// and a permutation alternation is exponential - so it returns null and is matched token-by-token in
67	// matchesText(). No derived pattern ever contains an unbounded lookahead-dot-star again.
68	function tokenSetSource(value) {
69	  const tokens = value && Array.isArray(value.tokens) ? value.tokens : null;
70	  if (!tokens || !tokens.length) return null;
71	  if (value.mode === 'any') return '(?:' + tokens.map(anchorToken).join('|') + ')';
72	  return null; // 'all' co-occurrence is matched linearly in matchesText, never as a mega-regex
73	}
74	
75	// tokenContains(text, token) -> is the single anchored token present in text. LINEAR: `\bword\b` is a
76	// literal with boundaries and has no backtracking blowup.
77	function tokenContains(text, token) {
78	  let re;
79	  try { re = new RegExp(anchorToken(token), 'i'); }
80	  catch (_err) {
81	    // FAIL-OPEN: a token that cannot compile to a RegExp is treated as NO-MATCH (the fail-closed
82	    // direction: never a false breach match). Not swallowed silently - validateSpec's does-not-compile
83	    // check rejects the spec that produced such a token (C-050), so the real defect surfaces there.
84	    return false;
85	  }
86	  return re.test(text);
87	}
88	
89	// matchesText(pattern, text) -> does a pattern match `text`, in GUARANTEED LINEAR time. THE one text
90	// matcher propose.js calls (one door): a token-set is tested token by token, combined by some() ('any')
91	// or every() ('all') - NEVER a co-occurrence mega-regex (the ReDoS Rob P0 fixed). An anchored-regex is
92	// a `\b`-bounded word run (linear). A url-path is matched by propose.js against page URLs, not here.
93	function matchesText(pattern, text) {
94	  if (!pattern || typeof pattern !== 'object') return false;
95	  const hay = String(text == null ? '' : text);
96	  if (pattern.kind === 'token-set') {
97	    const tokens = pattern.value && Array.isArray(pattern.value.tokens) ? pattern.value.tokens : [];
98	    if (!tokens.length) return false;
99	    const hit = (t) => tokenContains(hay, t);
100	    return pattern.value.mode === 'any' ? tokens.some(hit) : tokens.every(hit);
101	  }
102	  if (pattern.kind === 'anchored-regex') {
103	    const re = compileRegex(pattern);
104	    return re ? re.test(hay) : false;
105	  }
106	  return false;
107	}
108	
109	module.exports = {
110	  escapeRegex,
111	  anchorToken,
112	  buildAnchoredRegex,
113	  compileRegex,
114	  regexSourceOf,
115	  tokenSetSource,
116	  tokenContains,
117	  matchesText,
118	};
