1	'use strict';
2	// llm/entailment.js - GATE 3: the NLI entailment step (Constitution Rule 12 gate 3, Rule 11;
3	// caution.md C-147; GAPS.md llm-unverified). The deterministic shell that turns each atomic claim
4	// into a hypothesis, its cited span into a premise, and runs an INJECTED model as an NLI verifier.
5	// Anything not labelled `entailment` is refused; the failure mode is abstention, never a guess.
6	//
7	// NO NETWORK. The model caller is INJECTED (`llmCall`), exactly like breach/adjudicator/adjudicate.js;
8	// this module owns only: prompt assembly (llm/prompts/entailment.js), a HARD per-call deadline
9	// (Rule 9, reusing llm/router.js withDeadline), the post-hoc structural gate (llm/gate.js
10	// validateResponse: schema + retrieval-gate + quote-match), and the verdict -> ok reduction.
11	//
12	// checkEntailment(claims, { llmCall, deadlineMs, now, log }) -> Promise<Array<{
13	//   claim, premise_source_id, verdict: 'entailment'|'neutral'|'contradiction', ok:boolean, reason
14	// }>>
15	//   - one result per input claim, IN ORDER (the array is built by mapping the INPUT, never the model
16	//     output: like the adjudicator, this shell is filter-only and can neither add nor drop a claim).
17	//   - ok:true ONLY when the gate-validated verdict is exactly 'entailment'. neutral, contradiction,
18	//     a gate rejection (out-of-set source_id, bad schema, unparseable), a timeout or a throw all
19	//     yield ok:false with verdict defaulted to the conservative 'neutral' (abstain-by-default,
20	//     Rule 12 gate 4). The consumer (the adjudicator, wired by Rob) demotes any ok:false to
21	//     needs_review; it NEVER ships as a violation.
22	//
23	// WIRING NOTE FOR ROB (do not wire here; R3 owns breach/adjudicator/adjudicate.js): after a text
24	// candidate is ruled `breach` and before stampFromVerdict writes `violation`, gate it through
25	//   const [e] = await checkEntailment(
26	//     [{ claim: f.description, premise_source_id: f.evidence_source_id || f.evidence_url,
27	//        premise: f.evidence_quote }],
28	//     { llmCall: opts.llmCall, deadlineMs: remaining });
29	//   if (!e || !e.ok) demote the finding to needs_review (adjudication_reason: 'nli:' + e.verdict).
30	// The premise MUST be the exact verbatim span the quote-match verifier already string-matched to the
31	// corpus (Rule 12 gate 2 feeds gate 3), so the NLI premise is grounded, not paraphrased.
32	
33	const { withDeadline } = require('./router.js');
34	const { validateResponse } = require('./gate.js');
35	const { buildEntailmentPrompt, LABELS } = require('./prompts/entailment.js');
36	
37	const DEFAULT_DEADLINE_MS = 9000; // a CAP, never a floor (Rule 8); one NLI call is bounded to seconds.
38	const ENTAILMENT = 'entailment';
39	const ABSTAIN_LABEL = 'neutral'; // the conservative default label on any refusal (not entailment).
40	
41	// numOr(v, d): a positive finite override CLAMPED to the cap `d`, else the default `d`. `d` is the hard
42	// ceiling (DEFAULT_DEADLINE_MS), never a floor: a caller may only ask for a SHORTER deadline, never a
43	// longer one, so an override of an hour cannot defeat the documented seconds-scale cap (Rule 8/9). A
44	// misconfigured deadline (NaN, <=0) falls back to the cap default.
45	function numOr(v, d) {
46	  const n = Number(v);
47	  return Number.isFinite(n) && n > 0 ? Math.min(n, d) : d;
48	}
49	
50	// normaliseClaim(claim): read the hypothesis, its premise span and that span's source_id off one
51	// input claim, tolerating the field spellings the proposer/verifier flow uses. Never re-derives a
52	// fact; it only reads the fields it was handed (Rule 1).
53	function normaliseClaim(claim) {
54	  const c = claim || {};
55	  const hypothesis = firstString([c.claim, c.hypothesis, c.text, c.description]);
56	  const sourceId = firstString([c.premise_source_id, c.source_id, c.sourceId, c.evidence_source_id, c.evidence_url]);
57	  const premise = firstString([c.premise, c.premise_text, c.span, c.evidence_quote, c.quote]);
58	  return { hypothesis, sourceId, premise };
59	}
60	
61	// firstString(cands): the first non-empty string in a candidate list, else '' (fail-closed: a missing
62	// field becomes an empty string that the abstain guards below reject, never a fabricated default).
63	function firstString(cands) {
64	  for (const v of cands) {
65	    if (typeof v === 'string' && v.trim()) return v;
66	  }
67	  return '';
68	}
69	
70	// resultFor(claim, sourceId, verdict, ok, reason): the one canonical result row shape.
71	function resultFor(hypothesis, sourceId, verdict, ok, reason) {
72	  return { claim: hypothesis, premise_source_id: sourceId, verdict, ok, reason };
73	}
74	
75	// callModel(prompt, opts): one HARD-deadline-bounded attempt at the injected caller. Returns the raw
76	// model return on success, or a typed abstain marker ({ _abstain, reason }) on timeout/throw. A
77	// synchronous throw in llmCall is turned into a rejection by Promise.resolve().then so withDeadline
78	// captures it as a first-class value (never an uncaught throw into the mint).
79	async function callModel(pkg, opts) {
80	  const request = {
81	    role: 'extract', system: pkg.system, prompt: pkg.prompt, schema: pkg.schema,
82	    allowedSourceIds: pkg.allowedSourceIds, sources: pkg.sources,
83	    temperature: 0, max_tokens: 400, deadline_ms: opts.deadlineMs,
84	  };
85	  const work = Promise.resolve().then(() => opts.llmCall(request));
86	  const raced = await withDeadline(work, opts.deadlineMs);
87	  if (raced.timedOut) return { _abstain: true, reason: 'nli call exceeded the ' + opts.deadlineMs + 'ms deadline -> abstain (Rule 9)' };
88	  if (raced.error !== undefined) return { _abstain: true, reason: 'nli call threw: ' + String(raced.error).slice(0, 80) + ' -> abstain (Rule 4)' };
89	  return { value: raced.value };
90	}
91	
92	// verdictFromResponse(raw, pkg): run the injected caller's return through llm/gate.js and reduce it
93	// to { verdict, ok, reason }. A gate rejection (schema, out-of-set source_id, quote drift) or a
94	// missing/unknown label abstains; only a clean, gate-valid 'entailment' is ok:true.
95	function verdictFromResponse(raw, pkg) {
96	  const gated = validateResponse(raw, { schema: pkg.schema, allowedSourceIds: pkg.allowedSourceIds, sources: pkg.sources });
97	  if (!gated.ok) {
98	    const code = (gated.violations && gated.violations[0] && gated.violations[0].code) || 'gate_reject';
99	    return { verdict: ABSTAIN_LABEL, ok: false, reason: 'gate rejected the nli response (' + code + ') -> abstain' };
100	  }
101	  const label = String((gated.value && gated.value.verdict) || '').toLowerCase().trim();
102	  if (!LABELS.includes(label)) return { verdict: ABSTAIN_LABEL, ok: false, reason: 'nli label not in the closed enum -> abstain' };
103	  if (label === ENTAILMENT) return { verdict: ENTAILMENT, ok: true, reason: 'premise entails the hypothesis' };
104	  return { verdict: label, ok: false, reason: 'nli label "' + label + '" is not entailment -> abstain (Rule 12 gate 3)' };
105	}
106	
107	// checkOne(claim, opts): the whole per-claim pipeline. A claim missing its hypothesis, its premise or
108	// its source_id cannot be verified, so it abstains WITHOUT calling the model. An empty hypothesis is
109	// no proposition to entail, so a bare 'entailment' reply would be ok:true for nothing checked - that
110	// escape is closed here (fail-closed, Rule 4).
111	async function checkOne(claim, opts) {
112	  const { hypothesis, sourceId, premise } = normaliseClaim(claim);
113	  if (!hypothesis || !sourceId || !premise) {
114	    return resultFor(hypothesis, sourceId, ABSTAIN_LABEL, false, 'no hypothesis, cited premise span or source_id -> cannot verify, abstain (Rule 3/4)');
115	  }
116	  if (typeof opts.llmCall !== 'function') {
117	    return resultFor(hypothesis, sourceId, ABSTAIN_LABEL, false, 'no llmCall injected -> abstain (Rule 12 gate 4)');
118	  }
119	  const pkg = buildEntailmentPrompt({ hypothesis, premise, sourceId });
120	  const called = await callModel(pkg, opts);
121	  if (called._abstain) return resultFor(hypothesis, sourceId, ABSTAIN_LABEL, false, called.reason);
122	  const v = verdictFromResponse(called.value, pkg);
123	  logSafe(opts.log, { event: 'nli', source_id: sourceId, verdict: v.verdict, ok: v.ok });
124	  return resultFor(hypothesis, sourceId, v.verdict, v.ok, v.reason);
125	}
126	
127	// logSafe(log, event): emit to an optional observability sink; a throwing sink can never break a
128	// verification (FAIL-OPEN: an observability fault is not a legal-claim failure, dropped on purpose).
129	function logSafe(log, event) {
130	  if (typeof log !== 'function') return;
131	  try { log(event); } catch (_e) { /* FAIL-OPEN: log sink faults are non-fatal, deliberately dropped */ }
132	}
133	
134	/**
135	 * checkEntailment(claims, opts) -> Promise<result[]>. Runs each claim through the NLI gate SEQUENTIALLY
136	 * (so per-claim deadlines compose predictably and a shared free-tier is not stormed). The output array
137	 * is a strict 1:1 map of the INPUT (filter-only): |result| === |claims|, always.
138	 *
139	 * opts.llmCall    async (request) => model response (raw string, {text}, or {ok,text}); INJECTED, this
140	 *                 module never opens a socket. Absent/throws/times out/unparseable -> the claim abstains.
141	 * opts.deadlineMs the per-call hard deadline (default 9000); a CAP, never a floor (Rule 8/9).
142	 * opts.now/opts.log  reserved clock + optional observability sink (both optional).
143	 */
144	async function checkEntailment(claims, options = {}) {
145	  const list = Array.isArray(claims) ? claims : [];
146	  const opts = {
147	    llmCall: typeof options.llmCall === 'function' ? options.llmCall : null,
148	    deadlineMs: numOr(options.deadlineMs, DEFAULT_DEADLINE_MS),
149	    log: typeof options.log === 'function' ? options.log : null,
150	  };
