2	'use strict';
3	// llm/evals/run.js - THE blocking precision + abstain-rate harness for the LLM-touched gates
4	// (PRD tool #9; Constitution Rule 11 + Rule 12 gates 3/4/5; caution.md C-146). It replays a fixture
5	// suite of adjudication, entailment, structural-gate and jury-immunity tasks through the DETERMINISTIC
6	// shells (breach/adjudicator, llm/entailment, llm/gate, llm/router) with SCRIPTED providers - NO
7	// network, no model, no keys. Every prompt/model change is gated here on precision and abstain-rate.
8	//
9	// THE CONTRACT (why this is the enforcement point Rule 12 names):
10	//   - known-breach tasks MUST ship a positive (a violation / an entailment). These are the true
11	//     positives.
12	//   - known-clean tasks carry TEMPTING-but-wrong evidence (a practice-area page, a fabricated
13	//     disproof, a fluent-but-neutral premise) and MUST NOT ship a positive. A clean task that ships
14	//     is a FALSE POSITIVE - and a single false positive is a bug (axe-core doctrine, Rule 10).
15	//   - gate tasks (out-of-set citation, quote drift, garbage) MUST be refused by the structural gate.
16	//   - curated-immunity tasks MUST return 'immune': the jury may never veto a catalogue fact (C-131).
17	//
18	// EXIT: 1 when precision < 1.0 on the seeded set, when any immunity veto fires, or when any fixture's
19	// actual outcome does not match its declared expectation (a known-breach that stopped shipping is a
20	// regression too); 0 when every fixture matches and precision is a clean 1.0; 2 on a harness error.
21	//
22	// Usage: node llm/evals/run.js [--json]
23	
24	const fs = require('fs');
25	const path = require('path');
26	
27	const { adjudicate } = require('../../breach/adjudicator/adjudicate.js');
28	const { checkEntailment } = require('../entailment.js');
29	const { validateResponse } = require('../gate.js');
30	const { quorum } = require('../router.js');
31	
32	const FIXTURES_DIR = path.join(__dirname, 'fixtures');
33	const SHELL_DEADLINE_MS = 5000; // a CAP for the scripted shells; they resolve synchronously anyway.
34	
35	function arraysEqual(a, b) {
36	  if (!Array.isArray(a) || !Array.isArray(b) || a.length !== b.length) return false;
37	  return a.every((x, i) => x === b[i]);
38	}
39	
40	// classificationResult(fx, passed, shipped, detail): the common result shape for the three
41	// classification kinds (adjudication/entailment/gate). expectPositive is set from the fixture class:
42	// only a known-breach is expected to ship a positive; everything else must abstain/refuse.
43	function classificationResult(fx, passed, shipped, detail) {
44	  return { name: fx.name, kind: fx.kind, passed, shipped, expectPositive: fx.class === 'known-breach', abstained: !shipped, immunityVeto: false, detail };
45	}
46	
47	async function runAdjudication(fx) {
48	  // The adjudicator now runs Gate 3 (checkEntailment) AFTER a breach verdict: an entailment request
49	  // (recognisable by its closed 3-label verdict enum) must be answered with a gate-valid pass, or a
50	  // scripted breach would demote to needs_review and the known-breach fixtures could never ship.
51	  // Entailment-FAILURE behaviour is exercised by the dedicated entailment fixtures, not here.
52	  const llmCall = fx.scripted_verdicts
53	    ? async (request) => {
54	      const enumSet = request && request.schema && request.schema.properties
55	        && request.schema.properties.verdict && request.schema.properties.verdict.enum;
56	      if (Array.isArray(enumSet) && enumSet.includes('entailment')) {
57	        return { source_id: (request.allowedSourceIds || [])[0] || '', verdict: 'entailment' };
58	      }
59	      return fx.scripted_verdicts;
60	    }
61	    : null;
62	  const { findings } = await adjudicate(fx.candidates, fx.bundle, { llmCall, deadlineMs: SHELL_DEADLINE_MS });
63	  const states = findings.map((f) => f.state);
64	  return classificationResult(fx, arraysEqual(states, fx.expect.states), states.includes('violation'), 'states=[' + states.join(',') + ']');
65	}
66	
67	async function runEntailment(fx) {
68	  const llmCall = async () => fx.scripted_response;
69	  const results = await checkEntailment(fx.claims, { llmCall, deadlineMs: SHELL_DEADLINE_MS });
70	  const oks = results.map((r) => r.ok);
71	  const detail = 'ok=[' + oks.join(',') + '] verdict=[' + results.map((r) => r.verdict).join(',') + ']';
