81	async function runImmunity(fx) {
82	  const providers = (fx.providers || []).map((p) => ({ name: p.name, family: p.family, call: async () => JSON.stringify(p.reply) }));
83	  const r = await quorum(fx.task, { providers, n: 2, deadlineMs: SHELL_DEADLINE_MS });
84	  const want = fx.expect.verdict || 'immune';
85	  const immunityVeto = r.verdict !== 'immune';
86	  return { name: fx.name, kind: fx.kind, passed: r.verdict === want, shipped: null, expectPositive: null, abstained: false, immunityVeto, detail: 'verdict=' + r.verdict + (r.reason ? ' reason=' + r.reason : '') };
87	}
88	
89	const RUNNERS = { adjudication: runAdjudication, entailment: runEntailment, gate: runGate, 'quorum-immunity': runImmunity };
90	
91	// dispatch(fx): route one fixture to its runner. A runner that throws is a FAILED fixture that shipped
92	// nothing (never a silent skip and never a false positive) - the failure is recorded, never swallowed.
93	async function dispatch(fx) {
94	  const runner = RUNNERS[fx.kind];
95	  if (!runner) throw new Error('unknown fixture kind: ' + JSON.stringify(fx.kind) + ' (' + fx.name + ')');
96	  try {
97	    return await runner(fx);
98	  } catch (e) {
99	    // FAIL-OPEN: a runner throw is RECORDED as a FAILED fixture (passed:false, shipped:false, the cause
100	    // in `detail`), so a broken fixture fails the harness LOUDLY and is never swallowed into a pass or a
101	    // false positive (Rule 4: a failure may never report success).
102	    return { name: fx.name, kind: fx.kind, passed: false, shipped: false, expectPositive: fx.class === 'known-breach', abstained: true, immunityVeto: false, detail: 'ERROR: ' + String((e && e.message) || e).slice(0, 160) };
103	  }
104	}
