106	function loadFixtures() {
107	  if (!fs.existsSync(FIXTURES_DIR)) throw new Error('fixtures dir missing: ' + FIXTURES_DIR);
108	  const files = fs.readdirSync(FIXTURES_DIR).filter((f) => f.endsWith('.json')).sort();
109	  return files.map((f) => JSON.parse(fs.readFileSync(path.join(FIXTURES_DIR, f), 'utf8')));
110	}
111	
112	// tallyClassification(results): the precision + abstain-rate numbers over the classification tasks
113	// (adjudication/entailment/gate); immunity tasks are counted separately.
114	function tallyClassification(results) {
115	  const cls = results.filter((r) => r.expectPositive !== null);
116	  let tp = 0; let fp = 0; let fn = 0; let abstained = 0;
117	  for (const r of cls) {
118	    if (r.expectPositive && r.shipped) tp++;
119	    else if (!r.expectPositive && r.shipped) fp++;
120	    else if (r.expectPositive && !r.shipped) fn++;
121	    if (r.abstained) abstained++;
122	  }
123	  const precision = (tp + fp) === 0 ? 1 : tp / (tp + fp);
124	  const abstainRate = cls.length ? abstained / cls.length : 0;
125	  return { total: cls.length, tp, fp, fn, precision, abstainRate };
126	}
127	
128	// evaluate(): run every fixture and reduce to the blocking verdict object. No process side effects, so
129	// the node:test suite can call it directly and assert on precision/abstain-rate.
130	async function evaluate() {
131	  const fixtures = loadFixtures();
132	  if (fixtures.length < 12) throw new Error('the seeded set must hold at least 12 fixtures; found ' + fixtures.length);
133	  const results = [];
134	  for (const fx of fixtures) results.push(await dispatch(fx));
135	  const c = tallyClassification(results);
136	  const immunityVetoes = results.filter((r) => r.immunityVeto).length;
137	  const failedExpect = results.filter((r) => !r.passed);
138	  const ok = c.precision >= 1 && immunityVetoes === 0 && failedExpect.length === 0;
139	  return { ok, results, immunityVetoes, failedExpect: failedExpect.map((r) => r.name), ...c };
140	}
141	
142	function reportHuman(v) {
143	  console.log('llm/evals: precision + abstain-rate harness (' + v.results.length + ' fixtures)');
