145	    const mark = r.passed ? 'PASS' : 'FAIL';
146	    console.log('  ' + mark.padEnd(4) + ' [' + r.kind + '] ' + r.name + ': ' + r.detail);
147	  }
148	  console.log('  precision=' + v.precision.toFixed(3) + ' (TP=' + v.tp + ' FP=' + v.fp + ' FN=' + v.fn + ') abstain_rate=' + v.abstainRate.toFixed(3) + ' immunity_vetoes=' + v.immunityVetoes);
