44	// loadRedTeamFixtures(filePath) -> {present, entries, parseError?}. Never throws.
45	function loadRedTeamFixtures(filePath) {
46	  if (!fs.existsSync(filePath)) return { present: false, entries: [] };
47	  let data;
48	  try {
49	    data = JSON.parse(fs.readFileSync(filePath, 'utf8'));
50	  } catch (e) {
51	    return { present: true, entries: [], parseError: e.message };
52	  }
53	  const entries = normaliseEntries(data);
54	  if (entries === null) {
55	    return { present: true, entries: [], parseError: 'unrecognised top-level shape (expected an array or {entries:[...]}/{fixtures:[...]})' };
56	  }
57	  return { present: true, entries };
58	}
59	
60	const STAGE_NAMES = new Set(['facts', 'coverage', 'propose', 'verify', 'adjudicate']);
61	
62	// pendingGateReason(entry) -> a reason string when the fixture ITSELF declares its target gate is not
63	// on disk yet (current_status:'pending_gate', or target_gate.status:'pending_gate'), else null. This
64	// reads the real file's own authoritative status rather than guessing.
65	function pendingGateReason(entry) {
66	  if (entry.current_status === 'pending_gate') return 'fixture declares current_status: pending_gate';
67	  const tg = entry.target_gate;
68	  if (tg && typeof tg === 'object' && tg.status === 'pending_gate') {
69	    return 'fixture declares target_gate.status: pending_gate (' + (tg.gate || 'unnamed gate') + ')';
70	  }
71	  return null;
72	}
73	
74	// targetGateUnavailable(entry, stageTable) -> the gate NAME when entry.target_gate/gate/target is a
75	// BARE STRING naming one of this harness's own stage names and that stage did not run (the harness's
76	// originally-documented, generic contract - kept as a forward-compatible fallback since the real file
77	// uses a richer object shape handled by pendingGateReason() above instead).
78	function targetGateUnavailable(entry, stageTable) {
79	  const gate = entry.target_gate || entry.gate || entry.target || null;
80	  if (typeof gate !== 'string' || !STAGE_NAMES.has(gate)) return null;
81	  const row = (stageTable || []).find((s) => s.stage === gate);
82	  if (!row || row.status !== 'ran') return gate;
