86	// resolveBundle(entry, fixturesDir) -> an EvidenceBundle, or null when the entry carries none this
87	// harness knows how to resolve. entry.input.bundle (the real landed file's shape) is tried first.
88	function resolveBundle(entry, fixturesDir) {
89	  if (entry.input && entry.input.bundle && typeof entry.input.bundle === 'object') return entry.input.bundle;
90	  if (entry.bundle && typeof entry.bundle === 'object') return entry.bundle;
91	  if (entry.fixture) {
92	    const p = path.isAbsolute(entry.fixture) ? entry.fixture : path.join(fixturesDir, entry.fixture);
93	    if (fs.existsSync(p)) return JSON.parse(fs.readFileSync(p, 'utf8'));
94	  }
95	  if (entry.domain) {
96	    const p = path.join(fixturesDir, entry.domain + '.json');
97	    if (fs.existsSync(p)) return JSON.parse(fs.readFileSync(p, 'utf8'));
98	  }
99	  return null;
100	}
101	
102	// mustNotTerms(entry) -> every forbidden token this generic harness can search for: any STRING value
103	// anywhere in entry.must_not, and every STRING found inside an ARRAY value. Boolean flags (the
104	// majority of this fixture file's must_not clauses) describe a behavioural invariant no generic token
105	// search can check; they contribute nothing, and an entry with only boolean flags falls through to an
106	// honest 'skipped' rather than a false 'caught' on a check that never ran.
107	function mustNotTerms(entry) {
108	  const mn = (entry && entry.must_not) || {};
109	  const terms = [];
110	  for (const value of Object.values(mn)) {
111	    if (typeof value === 'string') terms.push(value);
112	    else if (Array.isArray(value)) { for (const v of value) if (typeof v === 'string') terms.push(v); }
113	  }
114	  return terms;
115	}
116	
117	// findingsText(pipelineResult) -> a lowercased text blob of the pipeline's own findings[].
118	function findingsText(pipelineResult) {
119	  return (pipelineResult.breach.findings || []).map((f) => JSON.stringify(f)).join(' \n ').toLowerCase();
120	}
121	
122	// wholeOutputText(pipelineResult) -> a lowercased text blob of the WHOLE pipeline output (payload +
123	// coverage), so a fabrication escaping through any stage - not only findings[] - is still caught
124	// (defence in depth).
125	function wholeOutputText(pipelineResult) {
126	  try {
127	    return JSON.stringify({ payload: pipelineResult.payload, coverage: pipelineResult.coverage }).toLowerCase();
128	  } catch (e) {
129	    // FAIL-OPEN: a circular or unserialisable pipeline result must not crash the red-team lane; an
130	    // empty corpus here simply means this defence-in-depth check can never hit on its own - the
131	    // entry's own findings-text check (findingsText) still runs independently regardless.
132	    return '';
133	  }
134	}
135	
136	// evaluateMustNot(entry, pipelineResult) -> {status:'caught'|'escaped'|'skipped', reason?}.
137	function evaluateMustNot(entry, pipelineResult) {
138	  const terms = mustNotTerms(entry);
139	  if (terms.length === 0) {
140	    return {
141	      status: 'skipped',
142	      reason: 'entry carries no must_not value this generic harness can search for as a forbidden token (only boolean flags) - it may need bespoke wiring, see its own "wiring" field',
143	    };
144	  }
145	  const corpus = findingsText(pipelineResult) + ' \n ' + wholeOutputText(pipelineResult);
146	  const hit = terms.find((t) => corpus.includes(String(t).toLowerCase()));
147	  return hit ? { status: 'escaped', reason: 'matched forbidden token: ' + JSON.stringify(hit) } : { status: 'caught' };
148	}
149	
150	// runGenericEntry(entry, ctx) -> {status, reason?} via the generic bundle + must_not-token path.
151	async function runGenericEntry(entry, ctx, id) {
152	  const pending = pendingGateReason(entry);
153	  if (pending) return { status: 'skipped', reason: pending };
154	
155	  const gateReason = targetGateUnavailable(entry, ctx.stageTable);
156	  if (gateReason) return { status: 'skipped', reason: 'target gate "' + gateReason + '" is not available in this run' };
157	
158	  const bundle = resolveBundle(entry, ctx.fixturesDir);
159	  if (!bundle) {
