166	  } catch (e) {
167	    // FAIL-OPEN: a red-team fixture that makes the PIPELINE ITSELF throw is a distinct failure mode
168	    // from a fabrication escaping - it is recorded loudly as 'error' (not 'skipped', not 'caught') so
169	    // a crash on adversarial input is never mistaken for the gate having held.
170	    return { status: 'error', reason: 'pipeline threw on this fixture: ' + e.message };
171	  }
172	  return evaluateMustNot(entry, pipelineResult);
173	}
174	
175	/**
176	 * runRedTeamEntry(entry, ctx) -> {id, status:'caught'|'escaped'|'skipped'|'error'|'xfail', reason?}
177	 * ctx = { stageTable, fixturesDir, runPipelineForBundle: async (domain, bundle) => pipelineResult }
178	 */
179	async function runRedTeamEntry(entry, ctx) {
180	  const id = (entry && entry.id) ? entry.id : '(no id)';
181	  const handler = RT_HANDLERS[id];
