187	      // finding about the engine - recorded loudly as 'error', never mistaken for the gate holding.
188	      return { id, status: 'error', reason: 'bespoke handler threw: ' + e.message };
189	    }
190	  }
191	  return { id, ...(await runGenericEntry(entry, ctx, id)) };
192	}
193	
194	// runRedTeamLane(filePath, ctx) -> {present, rows, parseError?}. Iterates every entry sequentially
195	// (adversarial fixtures are expected to be few; sequential keeps error attribution unambiguous).
196	async function runRedTeamLane(filePath, ctx) {
197	  const loaded = loadRedTeamFixtures(filePath);
198	  if (!loaded.present) return { present: false, rows: [] };
199	  if (loaded.parseError) return { present: true, rows: [], parseError: loaded.parseError };
200	  const rows = [];
201	  for (const entry of loaded.entries) rows.push(await runRedTeamEntry(entry, ctx));
202	  return { present: true, rows };
203	}
204	
205	module.exports = {
206	  loadRedTeamFixtures,
207	  targetGateUnavailable,
208	  pendingGateReason,
209	  resolveBundle,
210	  mustNotTerms,
211	  evaluateMustNot,
212	  runRedTeamEntry,
213	  runRedTeamLane,
214	};
